-- Poems batch 56
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a8ffe8bd-a239-4697-b3cc-9b2fde8f19a3','看桑','孫魴','唐','唐诗','tang','','[]','簇簇互相遮，閑看實可嗟。',48,'全唐诗/poet.tang.48000.json','["簇簇互相遮，閑看實可嗟。", "藉多雖是葉，栽盛不如花。", "春綠暗連麥，秋乾暮立鴉。", "舊鄉曾種得，經亂屬誰家。"]'),
('f2e2620a-5678-48a6-a3d6-0a9f434ea948','僊都山留題','劉昭禹','唐','唐诗','tang','','[]','林下事無非，塵中竟不知。',48,'全唐诗/poet.tang.48000.json','["林下事無非，塵中竟不知。", "白雲深擁我，青石合眠誰。", "山靜擣靈藥，夜閑論古詩。", "此來親羽客，何日變枯髭。"]'),
('0815a7af-9951-44db-8b8a-cdb33c8bb82e','晚霽望嶽𪋤','劉昭禹','唐','唐诗','tang','','[]','湘西斜日邊，峭入幾尋天。',48,'全唐诗/poet.tang.48000.json','["湘西斜日邊，峭入幾尋天。", "翠落重城內，屏開萬戶前。", "崖崚危濺瀑，林罅靜通仙。", "誰肯功成後，相攜掃石眠。"]'),
('e9d6cb4f-d686-4d2d-903e-44a3b7ac0464','石筍','劉昭禹','唐','唐诗','tang','','[]','千古海門石，移歸吟叟居。',48,'全唐诗/poet.tang.48000.json','["千古海門石，移歸吟叟居。", "竅腥蛟出後，形瘦浪衝餘。", "工語寧無玉，僧知忽有書。", "好期仙者叱，變化向庭隅。"]'),
('34b5ba00-8cf1-4716-a4cf-930d79e8dd0f','傷雨後牡丹','劉昭禹','唐','唐诗','tang','','[]','廢功看不已，醉起又持杯。',48,'全唐诗/poet.tang.48000.json','["廢功看不已，醉起又持杯。", "數日簾常卷，中宵雨忽來。", "淒涼無戲蝶，零落在蒼苔。", "造化根難問，令人首可迴。"]'),
('99b8ef9b-a83a-474b-8fdb-ae3a4e053f98','送人紅花栽','劉昭禹','唐','唐诗','tang','','[]','世上紅蕉異，因移萬里根。',48,'全唐诗/poet.tang.48000.json','["世上紅蕉異，因移萬里根。", "艱難離瘴土，瀟灑入朱門。", "葉戰青雲韻，花零宿露痕。", "長安多未識，誰想動吟魂。"]'),
('15b82936-4e4d-4f17-b1cf-2ea9674b4b14','曉望','劉乙','唐','唐诗','tang','','[]','地祇逃秀境，神化或殷雷。',48,'全唐诗/poet.tang.48000.json','["地祇逃秀境，神化或殷雷。", "裂漢媧補合，高峰劒躍開。", "即今新定業，何世不遺才。", "若是浮名道，須言有禍胎。"]'),
('e7ff7d4a-095a-4294-9fc5-b63d9943da50','山中早起','劉乙','唐','唐诗','tang','','[]','雞調扶桑枝，秋空隱少微。',48,'全唐诗/poet.tang.48000.json','["雞調扶桑枝，秋空隱少微。", "闊雲霞並曜，高日月爭輝。", "若厥開天道，同初發帝機。", "以言當代事，閑闢紫宸扉。"]'),
('d09de01e-46be-4519-95fd-84305497a0e7','晚步','姚揆','唐','唐诗','tang','','[]','陋巷貧疑本姓顏，晚來閑步出林間。',64,'全唐诗/poet.tang.48000.json','["陋巷貧疑本姓顏，晚來閑步出林間。", "數聲長笛吹沈日，一片殘雲點破山。", "島寺漸疎敲石磬，漁家方半掩柴關。", "遲迴從此搜吟久，待得溪頭月上還。"]'),
('c5393e3e-bd78-4191-a8b9-3f72d83cc88f','秋日江東晚行','姚揆','唐','唐诗','tang','','[]','迢迢驅馬過江東，此際令人恨莫窮。',64,'全唐诗/poet.tang.48000.json','["迢迢驅馬過江東，此際令人恨莫窮。", "一撮秋煙堤上白，半輪殘日嶺頭紅。", "路岐滋味猶如舊，鄉曲聲音漸不同。", "含思看看到梁苑，畫樓絲竹徹遙空。"]'),
('d2e4e36b-8a58-4fdd-b8bc-038eb90343e9','題陶淵明醉石','陳光','唐','唐诗','tang','','[]','片石露寒色，先生遺素風。',48,'全唐诗/poet.tang.48000.json','["片石露寒色，先生遺素風。", "醉眠芳草合，吟起白雲空。", "道出乾坤外，聲齊日月中。", "我知彭澤後，千載與誰同。"]'),
('373f9734-c5bc-41c2-94a0-390f3ba37cb2','長安新柳','陳光','唐','唐诗','tang','','[]','九陌雲初霽，皇衢柳已新。',48,'全唐诗/poet.tang.48000.json','["九陌雲初霽，皇衢柳已新。", "不同天苑景，先得日邊春。", "色淺微含露，絲輕未惹塵。", "一枝方欲折，歸去及茲晨。"]'),
('0a3ce3af-8c7f-453f-952a-49939e8abf67','雪晴','楊凝式','唐','唐诗','tang','','[]','春來冰未泮，冬至雪初晴。',24,'全唐诗/poet.tang.48000.json','["春來冰未泮，冬至雪初晴。", "爲報方袍客，豐年瑞已成。"]'),
('dba889e3-1712-437e-9dca-bd9a3bda0c05','上安祿山','盧言','唐','唐诗','tang','','[]','象曰雲雷屯，大君理經綸。',24,'全唐诗/poet.tang.48000.json','["象曰雲雷屯，大君理經綸。", "馬上取天下，雪中朝海神。"]'),
('4ebe714d-e88c-4b5b-8a3a-6646649749a9','儲潭廟','裴諝','唐','唐诗','tang','','[]','江水上源急如箭，潭北轉急令目眩。',239,'全唐诗/poet.tang.48000.json','["江水上源急如箭，潭北轉急令目眩。", "中間十里澄漫漫，龍蛇若見若不見。", "老農老圃望天語，儲潭之神可致雨。", "質明齋服躬往奠，牢醴豐潔精誠舉。", "女巫紛紛堂下儛，色似授兮意似與。", "雲在山兮風在林，風雲忽起潭更深。", "氣霾祠宇連江陰，朝日不復照翠岑。", "迴溪口兮櫂清流，好風帶雨送到州。", "吏人雨立喜再拜，神兮靈兮如獻酬。", "城上樓兮危架空，登四望兮暗濛濛。", "不知兮千萬里，惠澤願兮與之同。", "我有言兮報匪徐，車騎復往禮如初。", "高垣墉兮大其門，灑掃丹雘壯神居。", "使過廟者之加敬，酒食貨財而有餘。", "神兮靈，神兮靈，匪享慢，享克誠。"]'),
('45ca4e35-8adb-47d5-b3f0-fe03dfbf3b7e','臘月中與韋戶曹游發生洞裴回之際見雙白蝙蝠三飛洞門時多異之同爲口號','任要','唐','唐诗','tang','','[]','山翠羃靈洞，洞深玄想微。',60,'全唐诗/poet.tang.48000.json','["山翠羃靈洞，洞深玄想微。", "一雙白蝙蝠，三度向明飛。", "雖然有兩翅，了自無毛衣。", "若非飽石髓，那得凌□□。", "偶見歸堪說，殊勝不見歸。"]'),
('5b257a1b-97a8-4299-a51d-7ac311cf30e7','臘月中遊發生洞裴回之際見雙白蝙蝠三飛洞門時多異之同爲口號','韋洪','唐','唐诗','tang','','[]','欲驗發生洞，先開冰雪行。',60,'全唐诗/poet.tang.49000.json','["欲驗發生洞，先開冰雪行。", "窺臨見二翼，色素飛無聲。", "狀類白蝙蝠，幽感騰化精。", "應知五馬來，啓蟄迎春榮。", "露冕□之久，鳴騶還慰情。"]'),
('c3191956-7b6e-4843-9ddf-7448eb40e1f2','蜀中經蠻後寄陶雍','馬乂','唐','唐诗','tang','','[]','酋馬渡瀘水，北來如鳥輕。',72,'全唐诗/poet.tang.49000.json','["酋馬渡瀘水，北來如鳥輕。", "幾年期鳳闕，一日破龜城。", "此地有征戰，誰家無死生。", "人悲還舊里，鳥喜下空營。", "弟姪意初定，交朋心尚驚。", "自從經難後，吟苦似猨聲。"]'),
('2f68a86b-19ff-4bbd-b476-4ff05dcc8fd3','沖佑觀','張紹','唐','唐诗','tang','','[]','大始未形，混沌無際。',240,'全唐诗/poet.tang.49000.json','["大始未形，混沌無際。", "上下開運，乾坤定位。", "日月麗天，山川鎮地。", "萬彙猶屯，三才始備。", "肇有神化，初生蒸民。", "上惟立德，下無疎親。", "皇風蕩蕩，黔首淳淳。", "天下有道，誰非聖人。", "開源嗜慾，澆漓俗盛。", "賢者避世，真人華命。", "八極神鄉，十州異境。", "翠阜丹丘，潛伏靈聖。", "惟彼武夷，實曰洞天。", "峰巒黛染，巖岫霞鮮。", "金房玉室，羽蓋雲軿。", "葬日風雨，會有神仙。", "國步多艱，皇綱中絕。", "四海九州，瓜分幅裂。", "稔禍陬隅，阻兵甌越。", "寂寞玄風，荒涼絳闕。", "赫赫烈祖，再造丕基。", "拱揖高讓，神人樂推。", "明明我后，允協昌基。", "功崇下武，德茂重熙。"]'),
('442510f6-107a-4c0d-9976-bb785ad60758','徹雲澗','鄭露','唐','唐诗','tang','','[]','延綿不可窮，寒光徹雲際。',24,'全唐诗/poet.tang.49000.json','["延綿不可窮，寒光徹雲際。", "落石早雷鳴，濺空春雨細。"]'),
('6960106b-1534-4af8-986b-b72d3371d90f','秋氣尚高涼','林披','唐','唐诗','tang','','[]','秋氣尚高涼，寒笛吹萬木。',38,'全唐诗/poet.tang.49000.json','["秋氣尚高涼，寒笛吹萬木。", "故人入我庭，相照不出屋。", "[山]川雖遠觀，高懷不能掬。"]'),
('8277c384-707a-4003-877d-889ccc98cd9c','五言贈諸法師','公孫杲','唐','唐诗','tang','','[]','駕鶴排朱霧，乘鸞入紫煙。',48,'全唐诗/poet.tang.49000.json','["駕鶴排朱霧，乘鸞入紫煙。", "凌晨味潭菊，薄暮翫峰蓮。", "玉葉低梁下，金飀引窗前。", "嘯傲雲霞際，留情鱗羽年。"]'),
('d62498da-feb2-46cd-99bf-755b2d58fab4','恆岳晨望有懷','李敻','唐','唐诗','tang','','[]','二儀均四序，五嶽分九州。',144,'全唐诗/poet.tang.49000.json','["二儀均四序，五嶽分九州。", "靈造良難測，神功匪易酬。", "恆山北臨岱，秀崿東跨幽。", "澒洞鎮河朔，嵯峨冠嵩丘。", "禋祠彰舊典，壇廟列平疇。", "古樹侵雲密，飛泉界道流。", "從官叨佐理，銜命奉珍羞。", "薦玉申誠效，鏘金諒有由。", "郊原照初日，林薄委徂秋。", "塞近風聲厲，川長霧氣收。", "他鄉饒感激，歸望切祈求。", "景福如光願，私門當復侯。"]'),
('0967c78c-71cb-4c41-8593-cd1e79f66010','偶宴西蜀摩訶池','暢甫','唐','唐诗','tang','','[]','珍木鬱清池，風荷左右披。',48,'全唐诗/poet.tang.49000.json','["珍木鬱清池，風荷左右披。", "淺觴寧及醉，慢舸不知移。", "蔭林簟光冷，照流簪影攲。", "胡爲獨羈者，雪涕向漣漪。"]'),
('cf6145e9-0387-4985-a218-f9c111ff2187','飲後獻時相','吳士矩','唐','唐诗','tang','','[]','一夕心期一種歡，那知疎散負杯盤。',32,'全唐诗/poet.tang.49000.json','["一夕心期一種歡，那知疎散負杯盤。", "尊前數片朝雲在，不許馮公子細看。"]'),
('38ebcfad-d617-45f5-9958-9b1e46416659','失題','吳黔','唐','唐诗','tang','','[]','故國海雲端，歸寧便整鞍。',48,'全唐诗/poet.tang.49000.json','["故國海雲端，歸寧便整鞍。", "里榮身上蒨，省罷手中蘭。", "燒急平蕪廣，風悲古木寒。", "謝公山色在，朝夕共誰觀。"]'),
('80a62b2d-a794-4dd5-8199-53cab6d5bdcd','題惠聚寺','崔融','唐','唐诗','tang','','[]','人莫嫌山小，僧還愛寺靈。',24,'全唐诗/poet.tang.49000.json','["人莫嫌山小，僧還愛寺靈。", "殿高神氣力，龍活客丹青。"]'),
('0beba8e6-fe30-40e6-a800-232fda0f31df','平望贈蚊','錢信','唐','唐诗','tang','','[]','安得神仙術，試爲施康濟。',24,'全唐诗/poet.tang.49000.json','["安得神仙術，試爲施康濟。", "使此平望村，如吾江子匯。"]'),
('a872373f-04df-41f1-a7d7-1e7446a13d3a','武康碧落觀','胡傳美','唐','唐诗','tang','','[]','仙宮碧落太微書，遺蹟依然掩故居。',64,'全唐诗/poet.tang.49000.json','["仙宮碧落太微書，遺蹟依然掩故居。", "幢節不歸天杳邈，煙霞空鎖日幽虛。", "不逢金簡扳雲洞，可惜瑤臺疊蘚除。", "欲脫儒衣陪羽客，傷心齒髮已凋疎。"]'),
('ac67c640-ab86-4d87-8bf8-e59ec4be20e8','白雲寺','許宏','唐','唐诗','tang','','[]','踏破苔痕一逕斑，白雲飛處見青山。',32,'全唐诗/poet.tang.49000.json','["踏破苔痕一逕斑，白雲飛處見青山。", "不知浮世塵中客，幾箇能知物外閑。"]'),
('a463edf8-c831-4242-8a82-312b608fa929','羅浮山','文丙','唐','唐诗','tang','','[]','羅浮多勝境，夢到固無因。',48,'全唐诗/poet.tang.49000.json','["羅浮多勝境，夢到固無因。", "知有長生藥，誰爲不死人。", "根雖盤地脉，勢自倚天津。", "未便甘休去，須棲老此身。"]'),
('f8550c82-6ace-43c8-85d7-aa36d0edc75e','牡丹','文丙','唐','唐诗','tang','','[]','萬物承春各鬬奇，百花分貴近亭池。',64,'全唐诗/poet.tang.49000.json','["萬物承春各鬬奇，百花分貴近亭池。", "開時若也姮娥見，落日那堪公子知。", "詩客筵中金琖滿，美人頭上玉釵垂。", "不同寒菊舒重九，只擬清香泛酒巵。"]'),
('a6372a20-80dd-4271-8666-cfd4faef92f2','蘚花','文丙','唐','唐诗','tang','','[]','寂寞人偏重，無心媿牡丹。',48,'全唐诗/poet.tang.49000.json','["寂寞人偏重，無心媿牡丹。", "秋風凋不得，流水泛應難。", "怪石從教徧，幽庭一任盤。", "若逢公子顧，重疊是朱欄。"]'),
('f0fc1dda-2f52-4d90-9a5d-b01ee817445e','新栽松','文丙','唐','唐诗','tang','','[]','可憐同百草，況負雪霜姿。',48,'全唐诗/poet.tang.49000.json','["可憐同百草，況負雪霜姿。", "歌舞地不尚，歲寒人自移。", "堦除添冷淡，毫末入思惟。", "盡道生雲洞，誰知露嶮巇。"]'),
('7c410ada-1bc1-49b9-a9f1-02bb71ad66cc','柳','文丙','唐','唐诗','tang','','[]','何事動吟哦，長□翠色和。',48,'全唐诗/poet.tang.49000.json','["何事動吟哦，長□翠色和。", "垂陰千樹少，送別一枝多。", "帶霧籠彭澤，搖風舞汴河。", "只因隋帝植，民力幾銷磨。"]'),
('03571e92-3df9-457b-ad8f-59810522e49c','仙巖四瀑布即事寄上祕書包監侍郎七兄吏部李侍郎十七兄婺州趙中丞處州齊諫議明州李九郎十四韻','路應','唐','唐诗','tang','','[]','絕境久蒙蔽，芟蘿方迨茲。',168,'全唐诗/poet.tang.49000.json','["絕境久蒙蔽，芟蘿方迨茲。", "樵蘇尚未及，冠冕誰能知。", "緣崖開逕小，架木度空危。", "水激千雷發，珠聯萬貫垂。", "陰晴狀非一，昏旦勢多奇。", "井識軒轅跡，壇餘漢武基。", "猨聲響深洞，巖影倒澄池。", "想像虬龍去，依稀羽客隨。", "翫奇目豈倦，尋異神忘疲。", "干雲松作蓋，積翠薜成帷。", "含意攀丹桂，凝情顧紫芝。", "芸香藹芳氣，冰鏡徹圓規。", "胥念滄波遠，徒懷魏闕期。", "徵黃應計日，莫鄙北山移。"]'),
('6543b844-5b3c-47c5-81fa-19e5d66a297d','奉和郎中遊仙巖四瀑布寄包祕監李吏部趙婺州中丞齊處州諫議十四韻','李縝','唐','唐诗','tang','','[]','符守分珪組，放情在丘巒。',168,'全唐诗/poet.tang.49000.json','["符守分珪組，放情在丘巒。", "悠然造雲族，忽爾登天壇。", "求古理方賾，翫奇物不殫。", "晴光散崖壁，瑞氣生芝蘭。", "中有四瀑水，奔流狀千般。", "風雲隱巖底，雨雪霏林端。", "晶晶含古色，颼颼引晨寒。", "澄潭見猨飲，潛穴知龍盤。", "坐憩苔石遍，仰窺杉桂攢。", "幽蹊創高躅，靈藥餘仙飱。", "攜賞喜康樂，示文驚建安。", "縑緗炳珠寶，中外貽同官。", "末調亦何爲，輒陪高唱難。", "慙非御徒者，還得依門欄。"]'),
('f5a000ba-4d74-413c-9312-8855b9ace078','奉和郎中遊仙山四瀑泉兼寄李吏部包祕監趙婺州齊處州','戴公懷','唐','唐诗','tang','','[]','今日永嘉守，復追山水遊。',168,'全唐诗/poet.tang.49000.json','["今日永嘉守，復追山水遊。", "因尋莽蒼野，遂得軒轅丘。", "訪古事難究，覽新情屢周。", "溪垂綠篠暗，巖度白雲幽。", "過石奇不盡，出林香更浮。", "憑高擁虎節，搏險窺龍湫。", "淙潨瀉三四，奔騰千萬秋。", "寒驚殷雷動，暑駭繁霜流。", "沫濺羣鳥外，光搖數峰頭。", "叢崖散滴瀝，近谷藏颼飀。", "況此特形勝，自餘非等儔。", "靈光掩五嶽，仙氣均十洲。", "書以謝羣彥，永將敘徽猷。", "當思共攀陟，東南看斗牛。"]'),
('feac3b9d-1e0e-4165-bf45-c8e73d8a51b9','奉和郎中遊仙山四瀑布兼寄李吏部包祕監判官','孟翔','唐','唐诗','tang','','[]','昔人恣探討，飛流稱石門。',132,'全唐诗/poet.tang.49000.json','["昔人恣探討，飛流稱石門。", "安知郡城側，別有神泉源。", "疏鑿意大禹，勤求聞軒轅。", "悠悠幾千歲，翳薈羣木繁。", "奇狀出蔽蔓，勝概畢討論。", "沿崖百丈落，奔注當空翻。", "下如散雨足，上擬屯雲根。", "變態凡幾處，靜神竟朝昏。", "渴賢寄珠玉，受馥尋蘭蓀。", "蘿蔦罥紫綬，巖隈駐朱轓。", "方思謝康樂，好事名空存。"]'),
('a8e44e64-1025-461e-bb50-b67b675cc4e3','晚眺','崔耿','唐','唐诗','tang','','[]','江溶流落景，山色凝暮煙。',36,'全唐诗/poet.tang.49000.json','["江溶流落景，山色凝暮煙。", "衰髮照秋日，壯心減昔年。", "愁吟長抱膝，孰訴高高天。"]'),
('42a843ee-5595-4cca-8304-653cb2f9cdd1','山下泉','宇文鼎','唐','唐诗','tang','','[]','可致清川廣，難量利物功。',24,'全唐诗/poet.tang.49000.json','["可致清川廣，難量利物功。", "涓流此山下，誰識去無窮。"]'),
('e10a174b-95ed-44bc-826a-27722263e9fd','永嘉經謝公石門山作','郭密之','唐','唐诗','tang','','[]','綿境經耳目，未嘗曠躋登。',120,'全唐诗/poet.tang.49000.json','["綿境經耳目，未嘗曠躋登。", "一窺石門險，再滌心神懵。", "洞壑閟金澗，欹崖盤石楞。", "陰潭下羃羃，秀嶺上層層。", "千丈瀑流蹇，半溪風雨絚。", "興餘志每愜，心遠道自弘。", "乘軺廣儲峙，祇命媿才能。", "輟櫂周氣象，捫條歷騫崩。", "忽如生羽翼，怳若將起騰。", "謝客今已矣，我來誰與朋。"]'),
('1b4337c3-dce4-4f2f-8ccf-0d0423cbc096','芳草','扈載','唐','唐诗','tang','','[]','幽芳無處無，幽處恨何如。',48,'全唐诗/poet.tang.49000.json','["幽芳無處無，幽處恨何如。", "倦客傷歸思，春風滿舊居。", "晚煙迷杳靄，朝露健扶疎。", "省傍靈光看，殘陽少皡區。"]'),
('175e031d-b606-4e6d-8e38-885d91b98377','任閬中下鄉檢田登艾蕭山北望','薛光謙','唐','唐诗','tang','','[]','觀農巡井邑，長望歷山川。',72,'全唐诗/poet.tang.49000.json','["觀農巡井邑，長望歷山川。", "擁澗開新耨，緣崖指火田。", "荒村無徑陌，古戍有風煙。", "瓠葉縈籬長，藤花繞架懸。", "岸高攢樹石，水淨寫雲天。", "迴首鄉關路，行歌猶喟然。"]'),
('bda7c151-ddf2-4a8f-b541-4b4b5ebec1a5','府尹王侍郎准制拜嶽因狀嵩高靈勝寄呈三十韻','尉遲汾','唐','唐诗','tang','','[]','雄雄天之中，峻極聞維嵩。',288,'全唐诗/poet.tang.49000.json','["雄雄天之中，峻極聞維嵩。", "作鎮盛標格，出雲爲雨風。", "瑞時物不癘，順澤年多豐。", "加高冠四方，視秩居三公。", "明朝虔昭報，頒祀歲嚴恭。", "署祝紆御札，詔賢導宸衷。", "皇皇三川守，馨德清明躬。", "肅徒奉蘭沐，竟夕玉華東。", "星漢耿齋戶，松泉寒壽宮。", "具修諒蠲吉，曙色猶葱曚。", "端儀大圭立，興俛聲玲瓏。", "挹瓚椒桂馥，奏金巖壑空。", "靈歆若有荅，彷彿傳祝工。", "卒事不遑偃，勝奇紛四叢。", "朝霞破靈嶂，錯落間蒼紅。", "動息形似蟻，玄黃氣如籠。", "奔傾千萬狀，羣嶽安比崇。", "日月襟袖捧，人天道路通。", "冥搜必殫竭，躋覽忘崎穹。", "踏翠徧諸剎，趣綿步難終。", "浮丘仙袂接，謝公屐齒窮。", "龍潭應下瞰，九曲當駭容。", "龍門計東豁，三臺有何蹤。", "金象語奚應，玉人光想融。"]'),
('016d6087-76ec-46fd-969d-f721daaad52a','早春陪敕使麻先生祭岳','馬令','唐','唐诗','tang','','[]','我皇盛文物，道化天地先。',168,'全唐诗/poet.tang.49000.json','["我皇盛文物，道化天地先。", "鞭撻走神鬼，玉帛禮山川。", "忽下袁州使，來遊紫洞前。", "青羊得處所，白鶴□時年。", "虔懇飛龍記，昭彰化鳥篇。", "□風半山水，□氣總雲煙。", "光抱昇中日，霞明五色天。", "山橫翠微外，室在綠潭邊。", "緹幕灰初庪，焚林火欲然。", "年光著草樹，春色換山泉。", "伊水來何日，嵩巖去幾千。", "山疑小天下，人是會神仙。", "葉令乘鳧入，浮丘駕鶴旋。", "麻姑幾年歲，三見海成田。"]'),
('523263a1-39fc-4d0e-a57f-a1cea1a64f5d','奉和郎中題仙巖瀑布十四韻','靈澈','唐','唐诗','tang','','[]','致閑在一郡，民安已三年。',168,'全唐诗/poet.tang.49000.json','["致閑在一郡，民安已三年。", "每懷貞士心，孫許猶差肩。", "採異百代後，得之古人前。", "捫險路坱圠，臨深聞潺湲。", "上有千歲樹，下飛百丈泉。", "清谷長雷雨，丹青凝霜煙。", "遙將大壑近，闇與方壺連。", "白石顏色寒，老藤花葉鮮。", "軒皇自茲去，喬木空依然。", "碧山東極海，明月高昇天。", "平野生竹柏，雖遠地不偏。", "永願酬國恩，自將布金田。", "穆穆早朝人，英英丹陛賢。", "誰思滄洲意，方欲涉臣川。"]'),
('f4a8b8bc-f766-4aa4-90ca-cc2c21188538','過商山','貫休','唐','唐诗','tang','','[]','吟緣橫翠憶天台，嘯狖啼猨見盡猜。',64,'全唐诗/poet.tang.49000.json','["吟緣橫翠憶天台，嘯狖啼猨見盡猜。", "四箇老人何處去，一聲仙鶴過溪來。", "皇城宮闕迴頭盡，紫閣煙霞爲我開。", "天際峰峰盡堪住，紅塵中去大悠哉。"]'),
('9b4ce6a3-84a2-4fbe-a30a-694ae0e47103','過西塞山','齊己','唐','唐诗','tang','','[]','空江平野流，風島葦颼颼。',48,'全唐诗/poet.tang.49000.json','["空江平野流，風島葦颼颼。", "殘日銜西塞，孤帆向北洲。", "邊鴻渡漢口，楚樹出吳頭。", "終日高雲裏，身依片石休。"]'),
('78be039b-1960-406e-8f10-099c3d3f6ad7','中秋月','可朋','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','登樓仍喜此宵晴，圓魄纔觀思便清。',64,'全唐诗/poet.tang.49000.json','["登樓仍喜此宵晴，圓魄纔觀思便清。", "海面乍浮猶隱映，天心高挂最分明。", "片雲想有神仙出，迴野應無鬼魅形。", "曾向洞庭湖上看，君山半霧水初平。"]'),
('6d0e1883-2457-4cbf-b71c-99c08c23e09e','僧院泉','修睦','唐','唐诗','tang','','[]','澄澈照人膽，深山只一般。',48,'全唐诗/poet.tang.49000.json','["澄澈照人膽，深山只一般。", "來難窮處所，心去助波瀾。", "砌曲夜聲苦，窗虛客夢闌。", "無心誰肯愛，時有老僧看。"]'),
('59685a89-eae4-4bcc-9309-49d356a21dc5','題僧院泉','修睦','唐','唐诗','tang','','[]','何處雲根新布得，歸仍半日在煙蘿。',64,'全唐诗/poet.tang.49000.json','["何處雲根新布得，歸仍半日在煙蘿。", "莫輕竹引經窗小，須信更深入耳多。", "繞砌雖然清自別，出門長恐濁相和。", "從此無心戀滄海，滄海無風亦起波。"]'),
('788a0b97-77e2-4303-bc76-e110893b9385','岳上作','修睦','唐','唐诗','tang','','[]','始好步青苔，蟬聲且莫催。',48,'全唐诗/poet.tang.49000.json','["始好步青苔，蟬聲且莫催。", "辛勤來到此，容易便言迴。", "遠水月未上，四方雲正開。", "更堪逢道侶，特地話天台。"]'),
('59655cc0-4c93-4f05-a410-5b7aa2df1750','望西山','修睦','唐','唐诗','tang','','[]','積翠異諸嶽，令人看莫休。',48,'全唐诗/poet.tang.49000.json','["積翠異諸嶽，令人看莫休。", "有時經暮雨，獨得倚高樓。", "雲外僧應老，林間水正秋。", "到頭歸隱處，豈在問嵩丘。"]'),
('31908e17-25e9-4c46-ab2f-dd36b4560dfb','題虎掊泉','修睦','唐','唐诗','tang','','[]','一自虎掊得，清聲四遠流。',48,'全唐诗/poet.tang.49000.json','["一自虎掊得，清聲四遠流。", "眾人憐爾處，長夜洗心頭。", "出谷花隨去，背巖猨下偷。", "林邊落江徼，風起雨翛翛。"]'),
('1e63342e-15a0-4546-b783-41de2efa6b51','松','修睦','唐','唐诗','tang','','[]','細韻颼颼入骨涼，影兼巢鶴過高牆。',32,'全唐诗/poet.tang.49000.json','["細韻颼颼入骨涼，影兼巢鶴過高牆。", "盤根一種依平地，自是梧桐不久長。"]'),
('9251c989-02ee-49b2-94f6-f6c8f67cac3a','岳陽對柳','修睦','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','誰此種秋色，令人看莫窮。',48,'全唐诗/poet.tang.49000.json','["誰此種秋色，令人看莫窮。", "正垂雲夢雨，不奈洞庭風。", "昔出長安道，獨遊隋苑東。", "當時今日思，須信苦相同。"]'),
('64f5f037-6dab-432b-8275-28d0907bfd8f','歸山吟','清豁','唐','唐诗','tang','','[]','聚如浮沫散如雲，聚不相將散不分。',32,'全唐诗/poet.tang.49000.json','["聚如浮沫散如雲，聚不相將散不分。", "入郭當時君是我，歸山今日我非君。"]'),
('0634a8c3-a658-40a2-b28a-89912d6e82d9','遊倚帝山二首 一','吳筠','唐','唐诗','tang','','[]','山間非吾心，物表翼所託。',96,'全唐诗/poet.tang.49000.json','["山間非吾心，物表翼所託。", "振衣超煩滓，策杖追岑壑。", "絕地窮㟏岈，造天究磐礴。", "邇臨煙霞積，逖睇宇宙廓。", "俯驚白雲涌，仰駭飛泉落。", "苔濃鮮翠屏，松古麗丹崿。", "目冀覩喬羨，心希馭龍鶴。", "乃知巢由情，豈伊猨鳥樂。"]'),
('9a79ab3d-9245-492b-8052-4545254bbf1c','遊倚帝山二首 二','吳筠','唐','唐诗','tang','','[]','茲山何獨秀，萬仞倚昊蒼。',72,'全唐诗/poet.tang.49000.json','["茲山何獨秀，萬仞倚昊蒼。", "晨躋煙霞趾，夕憩靈仙場。", "俯觀海上月，坐弄浮雲翔。", "松風振雅音，桂露含晴光。", "不出六合外，超然萬累忘。", "信彼古來士，巖棲道彌彰。"]'),
('b7f6143b-0e49-45a5-ae3f-c7203cad3f68','翰林院望終南山 一','吳筠','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','竊慕隱淪道，所歡巖穴居。',48,'全唐诗/poet.tang.49000.json','["竊慕隱淪道，所歡巖穴居。", "誰言忝休命，遂入承明廬。", "物情不可易，幽中未嘗攄。", "幸見終南山，岧嶢凌太虛。"]'),
('b58e1fb5-2c93-41e0-b131-5158933e3b03','翰林院望終南山 二','吳筠','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','青靄長不滅，白雲閑卷舒。',48,'全唐诗/poet.tang.49000.json','["青靄長不滅，白雲閑卷舒。", "悠然相探討，延望空躊躕。", "迹繫心無極，神超興有餘。", "何當解維縶，永託逍遙墟。"]'),
('afe7cf90-1b3f-418b-a6ac-71c7bdefdcb3','秋日彭蠡湖中觀廬山','吳筠','唐','唐诗','tang','','["\u5e90\u5c71", "\u592a\u6e56"]','泛舟太湖上，迴瞰茲山隈。',120,'全唐诗/poet.tang.49000.json','["泛舟太湖上，迴瞰茲山隈。", "萬頃滄波中，千峰鬱崔嵬。", "涼煙發爐嶠，秋日明帝臺。", "絕巔凌大漠，懸流瀉昭回。", "穹崇石梁引，岈豁天門開。", "飛鳥屢隱見，白雲時往來。", "超然契清賞，目醉心悠哉。", "董氏出六合，王君升九垓。", "誰言曠遐祀，庶可相追陪。", "從此永棲託，拂衣謝浮埃。"]'),
('f904d8e2-1cf4-4e4e-bbaa-1111e07063c2','秋日望倚帝山','吳筠','唐','唐诗','tang','','[]','楚服多奇山，靈表先倚帝。',96,'全唐诗/poet.tang.49000.json','["楚服多奇山，靈表先倚帝。", "孤秀白雲裏，青冥何崇麗。", "秋天已晴朗，晚日更澄霽。", "遠峰列在目，杳與神襟契。", "倏忽遺世間，宛如再登詣。", "伊予抱斯志，代處人煙閉。", "何事牽俗網，悠然負芝桂。", "朅來從隱淪，式保羨門計。"]'),
('6719377f-8be8-4c5e-b5f7-2bb9be74d1ba','薔薇花','李冶','唐','唐诗','tang','','[]','翠融紅綻渾無力，斜倚欄干似詫人。',64,'全唐诗/poet.tang.49000.json','["翠融紅綻渾無力，斜倚欄干似詫人。", "深處最宜香惹蝶，摘時兼恐焰燒春。", "當空巧結玲瓏帳，著地能鋪錦繡裀。", "最好凌晨和露看，碧紗窗外一枝新。"]'),
('e5cb1c78-9034-4076-85c4-529968ac34a5','柳','李冶','唐','唐诗','tang','','[]','最愛纖纖曲水濱，夕陽移影過青蘋。',64,'全唐诗/poet.tang.49000.json','["最愛纖纖曲水濱，夕陽移影過青蘋。", "東風又染一年綠，楚客更傷千里春。", "低葉已藏依岸櫂，高枝應閉上樓人。", "舞腰漸重煙光老，散作飛綿惹翠裀。"]'),
('df549d8e-42c9-480e-870e-e850117366e5','好時光','明皇帝','唐','唐诗','tang','','["\u60dc\u65f6", "\u7231\u60c5", "\u5a49\u7ea6"]','寶髻偏宜宮樣，蓮臉嫩，體紅香。',55,'全唐诗/poet.tang.49000.json','["寶髻偏宜宮樣，蓮臉嫩，體紅香。", "眉黛不須張敞畫，天教入鬢長。", "莫倚傾國貌，嫁取箇，有情郎。", "彼此當年少，莫負好時光。"]'),
('83d3c6fd-88ac-4ca0-9562-d04667679278','巫山一段雲 一','昭宗皇帝','唐','唐诗','tang','','[]','縹緲雲間質，盈盈波上身。',54,'全唐诗/poet.tang.49000.json','["縹緲雲間質，盈盈波上身。", "袖羅斜舉動埃塵，明豔不勝春。", "翠鬢晚妝煙重，寂寂陽臺一夢。", "冰眸蓮臉見長新，巫峽更何人。"]'),
('e3532bea-0327-47f6-945c-87158ad3b99d','巫山一段雲 二','昭宗皇帝','唐','唐诗','tang','','[]','蝶舞棃園雪，鶯啼柳帶煙。',54,'全唐诗/poet.tang.49000.json','["蝶舞棃園雪，鶯啼柳帶煙。", "小池殘日豔陽天，苧蘿山又山。", "青鳥不來愁絕，忍看鴛鴦雙結。", "春風一等少年心，閑情恨不禁。"]'),
('130b361d-eb7c-4795-a133-182b70d16fe0','菩薩蠻 一','昭宗皇帝','唐','唐诗','tang','','[]','登樓遙望秦宮殿，茫茫只見雙飛燕。',52,'全唐诗/poet.tang.49000.json','["登樓遙望秦宮殿，茫茫只見雙飛燕。", "渭水一條流，千山與萬丘。", "遠煙籠碧樹，陌上行人去。", "安得有英雄，迎歸大內中。"]'),
('cbc32a17-7b68-4c01-babe-d1a794540564','菩薩蠻 二','昭宗皇帝','唐','唐诗','tang','','[]','飄飄且在三峰下，秋風往往堪霑灑。',52,'全唐诗/poet.tang.49000.json','["飄飄且在三峰下，秋風往往堪霑灑。", "腸斷憶仙宮，朦朧煙霧中。", "思夢時時睡，不語長如醉。", "早晚是歸期，蒼穹知不知。"]'),
('6c9a932b-bd56-4e72-9ab0-fc8b319616a4','一葉落','後唐莊宗','唐','唐诗','tang','','["\u6000\u4eba", "\u5a49\u7ea6\u8bcd", "\u5a49\u7ea6", "\u5199\u666f", "\u60b2\u79cb"]','一葉落，搴朱箔，此時景物正蕭索。',38,'全唐诗/poet.tang.49000.json','["一葉落，搴朱箔，此時景物正蕭索。", "畫樓月影寒，西風吹羅幕。", "吹羅幕，往事思量著。"]'),
('8ab387cd-6e1b-4cb9-aa88-5e0113b45a21','如夢令','後唐莊宗','唐','唐诗','tang','','["\u601d\u5ff5", "\u5a49\u7ea6", "\u5bb4\u4f1a"]','曾宴桃源深洞，一曲清歌舞鳳。',40,'全唐诗/poet.tang.49000.json','["曾宴桃源深洞，一曲清歌舞鳳。", "長記別伊時，和淚出門相送。", "如夢，如夢，殘月落花煙重。"]'),
('f903077a-e55d-4f38-82b9-5ac800650a2e','陽臺夢','後唐莊宗','唐','唐诗','tang','','["\u601d\u5ff5", "\u5a49\u7ea6", "\u5973\u5b50"]','薄羅衫子金泥縫，困纖腰怯銖衣重。',57,'全唐诗/poet.tang.49000.json','["薄羅衫子金泥縫，困纖腰怯銖衣重。", "笑迎移步小蘭叢，嚲金翹玉鳳。", "嬌多情脈脈，羞把同心撚弄。", "楚天雲雨却相和，又入陽臺夢。"]'),
('c0c41411-2fdb-49c1-97ce-1f7e298fb6b6','歌頭','後唐莊宗','唐','唐诗','tang','','[]','賞芳春，暖風飄箔。',173,'全唐诗/poet.tang.49000.json','["賞芳春，暖風飄箔。", "鶯啼綠樹，輕煙籠晚閣。", "杏桃紅，開繁萼。", "靈和殿，禁柳千行斜，金絲絡。", "夏雲多，奇峰如削，紈扇動微涼，輕綃薄。", "梅雨霽，火雲爍。", "臨水檻，永日逃繁暑，泛觥酌。", "露華濃，冷高梧。", "彫萬葉，一霎晚風。", "蟬聲新雨歇，惜惜此光陰，如流水，東籬菊殘時，歎蕭索。", "繁陰積，歲時暮。", "景難留，不覺朱顏失却。", "好容光，且且須呼賓友。", "西園長宵，讌雲謠。", "歌皓齒，且行樂。"]'),
('15ec3147-5815-4d39-8b56-5de943732033','浣溪沙','南唐嗣主李璟','唐','唐诗','tang','','["\u6000\u4eba", "\u6625\u5929", "\u5199\u666f"]','風壓輕雲貼水飛，乍晴池館燕爭泥，沈郎多病不勝衣。',48,'全唐诗/poet.tang.49000.json','["風壓輕雲貼水飛，乍晴池館燕爭泥，沈郎多病不勝衣。", "沙上未聞鴻雁信，竹間時聽鷓鴣啼，此情惟有落花知。"]'),
('85ae4de5-86e8-4289-b094-a54a38026f38','攤破浣溪沙 一','南唐嗣主李璟','唐','唐诗','tang','','["\u601d\u5ff5", "\u95fa\u6028", "\u5199\u666f", "\u8377\u82b1", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd"]','菡萏香銷翠葉殘，西風愁起綠波間。',56,'全唐诗/poet.tang.49000.json','["菡萏香銷翠葉殘，西風愁起綠波間。", "還與韶光共顦顇，不堪看。", "細雨夢回雞塞遠，小樓吹徹玉笙寒。", "多少淚珠何限恨，倚闌干。"]'),
('f0df0cf6-8562-4040-9bcb-b4b98de81d78','攤破浣溪沙 二','南唐嗣主李璟','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u4f24\u6625", "\u5199\u666f", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u5a49\u7ea6"]','手卷真珠上玉鉤，依前春恨鎖重樓。',56,'全唐诗/poet.tang.49000.json','["手卷真珠上玉鉤，依前春恨鎖重樓。", "風裏落花誰是主，思悠悠。", "青鳥不傳雲外信，丁香空結雨中愁。", "回首淥波三峽暮，接天流。"]'),
('4b2dbf7b-accc-43ff-9417-01b63042eefd','漁父 一','後主煜','唐','唐诗','tang','','[]','浪花有意千里雪，桃花無言一隊春。',32,'全唐诗/poet.tang.49000.json','["浪花有意千里雪，桃花無言一隊春。", "一壺酒，一竿身，快活如儂有幾人。"]'),
('6b181549-9b0b-4b8a-acbd-850117557c39','漁父 二','後主煜','唐','唐诗','tang','','["\u5411\u5f80", "\u5199\u4eba", "\u751f\u6d3b", "\u95f2\u9002", "\u5199\u4eba\u8bd7", "\u6292\u6000"]','一櫂春風一葉舟，一綸繭縷一輕鉤。',32,'全唐诗/poet.tang.49000.json','["一櫂春風一葉舟，一綸繭縷一輕鉤。", "花滿渚，酒滿甌，萬頃波中得自由。"]'),
('6436c19b-b93a-41f9-96ba-8f6cc02e9012','憶江南 一','後主煜','唐','唐诗','tang','','["\u601d\u56fd", "\u5a49\u7ea6\u8bcd", "\u8bb0\u68a6", "\u5a49\u7ea6"]','多少恨，昨夜夢魂中。',32,'全唐诗/poet.tang.49000.json','["多少恨，昨夜夢魂中。", "還似舊時遊上苑，車如流水馬如龍，花月正春風。"]'),
('fc5d6d53-e6aa-4e1a-8ce5-98069da65a40','憶江南 二','後主煜','唐','唐诗','tang','','["\u601d\u5ff5", "\u6292\u60c5", "\u6545\u56fd"]','多少淚，霑袖復橫頤。',32,'全唐诗/poet.tang.49000.json','["多少淚，霑袖復橫頤。", "心事莫將和淚滴，鳳笙休向月明吹，腸斷更無疑。"]'),
('3ebe04ef-6213-4f12-b696-958a955c088e','憶江南 三','後主煜','唐','唐诗','tang','','[]','閑夢遠，南國正芳春。',32,'全唐诗/poet.tang.49000.json','["閑夢遠，南國正芳春。", "船上管弦江面綠，滿城飛絮混輕塵，愁殺看花人。"]'),
('d887dc7a-137b-4b39-9943-a012cb397f56','憶江南 四','後主煜','唐','唐诗','tang','','[]','閑夢遠，南國正清秋。',32,'全唐诗/poet.tang.49000.json','["閑夢遠，南國正清秋。", "千里江山寒色暮，蘆花深處泊孤舟，笛在月明樓。"]'),
('087babd8-0706-4fa7-a114-1b60a189d1de','擣練子 一','後主煜','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5b64\u72ec", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u5a49\u7ea6"]','深院靜，小庭空，斷續寒砧斷續風。',32,'全唐诗/poet.tang.49000.json','["深院靜，小庭空，斷續寒砧斷續風。", "無奈夜長人不寐，數聲和月到簾櫳。"]'),
('324936b5-b8c7-4445-aec2-0ced76d124fe','擣練子 二','後主煜','唐','唐诗','tang','','[]','雲鬟亂，晚妝殘，帶恨眉兒遠岫攢。',32,'全唐诗/poet.tang.49000.json','["雲鬟亂，晚妝殘，帶恨眉兒遠岫攢。", "斜托香顋春筍嬾，爲誰和淚倚闌干。"]'),
('6cf494bc-da88-441b-8190-f51a1cd33239','相見歡 一','後主煜','唐','唐诗','tang','','["\u5199\u82b1", "\u4eba\u751f", "\u82b1", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd"]','林花謝了春紅，太悤悤。',45,'全唐诗/poet.tang.49000.json','["林花謝了春紅，太悤悤。", "無奈朝來寒雨，晚來風。", "胭脂淚，相留醉，幾時重。", "自是人生長恨，水長東。"]'),
('fed4281e-1e15-41dd-a156-b4d97553b5be','相見歡 二','後主煜','唐','唐诗','tang','','["\u601d\u5ff5", "\u5b64\u72ec", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u5199\u666f", "\u521d\u4e2d\u53e4\u8bd7", "\u767b\u697c"]','無言獨上西樓，月如鉤。',45,'全唐诗/poet.tang.49000.json','["無言獨上西樓，月如鉤。", "寂寞梧桐深院，鎖清秋。", "翦不斷，理還亂，是離愁。", "別是一般滋味，在心頭。"]'),
('25bc24c7-fde4-4be6-8d0e-a16b1525ea4e','長相思 一','後主煜','唐','唐诗','tang','','["\u79cb\u5929", "\u5c71", "\u5199\u5c71", "\u63cf\u5199\u5c71", "\u76f8\u601d", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','一重山，兩重山。',44,'全唐诗/poet.tang.49000.json','["一重山，兩重山。", "山遠天高煙水寒，相思楓葉丹。", "菊花開，菊花殘。", "塞雁高飛人未還，一簾風月閑。"]'),
('191e4990-2397-4208-b5e8-39813345f6af','長相思 二','後主煜','唐','唐诗','tang','','[]','雲一緺，玉一梭。',44,'全唐诗/poet.tang.49000.json','["雲一緺，玉一梭。", "澹澹衫兒薄薄羅，輕顰雙黛螺。", "秋風多，雨如和。", "簾外芭蕉三兩窠，夜長人奈何。"]'),
('1d9fc470-fa99-4139-8b5a-321d331c01f3','浣溪沙 一','後主煜','唐','唐诗','tang','','[]','紅日已高三丈透，金鑪次第添香獸，紅錦地衣隨步皺。',48,'全唐诗/poet.tang.49000.json','["紅日已高三丈透，金鑪次第添香獸，紅錦地衣隨步皺。", "佳人舞點金釵溜，酒惡時拈花蘂齅，別殿遙聞簫鼓奏。"]'),
('11d72852-47c9-4659-971a-9b8b95277122','浣溪沙 二','後主煜','唐','唐诗','tang','','[]','轉燭飄蓬一夢歸，欲尋陳迹悵人非，天教心願與身違。',48,'全唐诗/poet.tang.49000.json','["轉燭飄蓬一夢歸，欲尋陳迹悵人非，天教心願與身違。", "待月池臺空逝水，蔭花樓閣漫斜暉，登臨不惜更霑衣。"]'),
('2d5f5235-966d-42c1-9d59-68d280a7386d','采桑子 一','後主煜','唐','唐诗','tang','','["\u601d\u5ff5", "\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929"]','轆轤金井梧桐晚，幾樹驚秋，晝雨如愁，百尺蝦鬚上玉鉤。',52,'全唐诗/poet.tang.49000.json','["轆轤金井梧桐晚，幾樹驚秋，晝雨如愁，百尺蝦鬚上玉鉤。", "瓊窗春斷雙蛾皺，回首邊頭，欲寄鱗游，九曲寒波不泝流。"]'),
('c893ac3e-c25e-49e9-afd0-a8bcc3d34f73','采桑子 二','後主煜','唐','唐诗','tang','','[]','亭前春逐紅英盡，舞態徘徊，細雨霏微，不放雙眉時暫開。',52,'全唐诗/poet.tang.49000.json','["亭前春逐紅英盡，舞態徘徊，細雨霏微，不放雙眉時暫開。", "綠窗冷靜芳音斷，香印成灰，可奈情懷，欲睡朦朧入夢來。"]'),
('eabb0b49-b82e-4047-a130-fa5b687f4948','菩薩蠻 一','後主煜','唐','唐诗','tang','','["\u5c11\u5973", "\u7231\u60c5"]','花明月暗籠輕霧，今宵好向郎邊去。',52,'全唐诗/poet.tang.49000.json','["花明月暗籠輕霧，今宵好向郎邊去。", "剗韤步香階，手提金縷鞋。", "畫堂南畔見，一晌偎人顫。", "好爲出來難，教君恣意憐。"]'),
('4a6be65e-27bf-4728-b8a7-95197ab48d07','菩薩蠻 二','後主煜','唐','唐诗','tang','','["\u5c11\u5973", "\u7231\u60c5"]','蓬萊院閉天台女，畫堂晝寢無人語。',52,'全唐诗/poet.tang.49000.json','["蓬萊院閉天台女，畫堂晝寢無人語。", "拋枕翠雲光，繡衣聞異香。", "潛來珠鎖動，驚覺鴛鴦夢。", "慢臉笑盈盈，相看無限情。"]'),
('f2f641d9-18c6-4a1c-89d0-5ddf84704730','菩薩蠻 三','後主煜','唐','唐诗','tang','','["\u7231\u60c5", "\u611f\u4f24"]','銅簧韻脆鏘寒竹，新聲慢奏移纖玉。',52,'全唐诗/poet.tang.49000.json','["銅簧韻脆鏘寒竹，新聲慢奏移纖玉。", "眼色暗相鉤，秋波橫欲流。", "雨雲深繡戶，來便諧衷素。", "宴罷又成空，夢迷春睡中。"]'),
('72ffbb94-d801-4c39-bf26-75150f2ce7a0','菩薩蠻 四','後主煜','唐','唐诗','tang','','["\u7231\u56fd", "\u601d\u6000"]','人生愁恨何能免，消魂獨我情何限。',52,'全唐诗/poet.tang.49000.json','["人生愁恨何能免，消魂獨我情何限。", "故國夢重歸，覺來雙淚垂。", "高樓誰與上，長記秋晴望。", "往事已成空，還如一夢中。"]'),
('e79bf420-dc28-48da-97f9-d3e07b3cb5f6','清平樂','後主煜','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u601d\u4e61", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd"]','別來春半，觸目愁腸斷。',54,'全唐诗/poet.tang.49000.json','["別來春半，觸目愁腸斷。", "砌下落梅如雪亂，拂了一身還滿。", "雁來音信無憑，路遙歸夢難成。", "離恨却如春草，更行更遠還生。"]'),
('7cf30f0e-9821-4fe2-b899-bc2703f5159d','喜遷鶯','後主煜','唐','唐诗','tang','','["\u601d\u5ff5", "\u65f6\u5149", "\u5199\u666f"]','曉月墜，宿雲微，無語枕頻欹。',57,'全唐诗/poet.tang.49000.json','["曉月墜，宿雲微，無語枕頻欹。", "夢回芳草思依依，天遠雁聲稀。", "啼鶯散，餘花亂，寂寞畫堂深院。", "片紅休埽儘從伊，留待舞人歸。"]'),
('1c02731a-b355-4a8d-bbb6-1acb8284bf67','阮郎歸','後主煜','唐','唐诗','tang','','["\u6625\u5929", "\u5973\u5b50", "\u5c71", "\u95fa\u6028"]','東風吹水日銜山，春來長是閑。',56,'全唐诗/poet.tang.49000.json','["東風吹水日銜山，春來長是閑。", "落花狼藉酒闌珊，笙歌醉夢間。", "春睡覺，晚妝殘，無人整翠鬟。", "留連光景惜朱顏，黃昏獨倚闌。"]'),
('692040b8-0c49-4532-b34c-0046af74232a','錦堂春','後主煜','唐','唐诗','tang','','["\u5199\u96e8", "\u5199\u98ce", "\u6292\u60c5", "\u98ce", "\u4eba\u751f", "\u96e8"]','昨夜風兼雨，簾幃颯颯秋聲。',55,'全唐诗/poet.tang.49000.json','["昨夜風兼雨，簾幃颯颯秋聲。", "燭殘漏滴頻欹枕，起坐不能平。", "世事漫隨流水，算來一夢浮生。", "醉鄉路穩宜頻到，此外不堪行。"]'),
('70c60aed-dd54-448a-a2da-207469cf71e5','應天長','後主煜','唐','唐诗','tang','','[]','一鉤初月臨妝鏡，蟬鬢鳳釵慵不整。',58,'全唐诗/poet.tang.49000.json','["一鉤初月臨妝鏡，蟬鬢鳳釵慵不整。", "重簾靜，層樓迥，惆悵落花風不定。", "柳堤芳草徑，夢斷轆轤金井。", "昨夜更闌酒醒，春愁過却病。"]'),
('079eab76-b38a-4a82-8a13-ac00e92b67c0','望遠行','後主煜','唐','唐诗','tang','','["\u6000\u4eba", "\u6625\u5929", "\u5973\u5b50"]','碧砌花光照眼明，朱扉長日鎮長扃。',64,'全唐诗/poet.tang.49000.json','["碧砌花光照眼明，朱扉長日鎮長扃。", "餘寒欲去夢難成，爐香煙冷自亭亭。", "遼陽月，秣陵砧，不傳消息但傳情。", "黃金臺下忽然驚，征人歸日二毛生。"]'),
('377b9884-059e-4076-8104-25857ae7d84e','浪淘沙 一','後主煜','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u611f\u4f24", "\u8bb0\u68a6", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u5a49\u7ea6"]','簾外雨潺潺，春意闌珊。',64,'全唐诗/poet.tang.49000.json','["簾外雨潺潺，春意闌珊。", "羅衾不耐五更寒，夢裏不知身是客，一晌貪歡。", "獨自暮凭闌，無限江山。", "別時容易見時難，流水落花春去也，天上人間。"]'),
('d9317285-0e91-4c01-8202-d97b2cd5abf4','浪淘沙 二','後主煜','唐','唐诗','tang','','[]','往事只堪哀，對景難排。',64,'全唐诗/poet.tang.49000.json','["往事只堪哀，對景難排。", "秋風庭院蘚侵階，一桁珠簾閑不卷，終日誰來。", "金劒已沈埋，壯氣蒿萊。", "晚涼天淨月華開，想得玉樓瑤殿影，空照秦淮。"]'),
('f32e4bf5-94ee-476e-871f-c547e24d1fc1','木蘭花','後主煜','唐','唐诗','tang','','[]','曉妝初了明肌雪，春殿嬪娥魚貫列。',64,'全唐诗/poet.tang.49000.json','["曉妝初了明肌雪，春殿嬪娥魚貫列。", "鳳簫聲斷水雲閑，重按霓裳歌徧徹。", "臨風誰更飄香屑，醉拍闌干情未切。", "歸時休放燭花紅，待蹋馬蹄清夜月。"]'),
('5b30f0ee-7708-4caa-b878-17b2fa3dbf65','虞美人 一','後主煜','唐','唐诗','tang','','["\u6625\u5929", "\u6000\u65e7", "\u5199\u666f", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd"]','風回小院庭蕪綠，柳眼春相續。',66,'全唐诗/poet.tang.49000.json','["風回小院庭蕪綠，柳眼春相續。", "凭闌半日獨無言，依舊竹聲新月，似當年。", "笙歌未散尊罍在，池面冰初解。", "燭明香暗畫樓深，滿鬢清霜殘雪，思難禁。"]'),
('b769cd89-478e-40af-9cdc-80cdc7423473','虞美人 二','後主煜','唐','唐诗','tang','','["\u601d\u5ff5", "\u54f2\u7406", "\u611f\u53f9", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u5a49\u7ea6"]','春花秋月何時了，往事知多少。',66,'全唐诗/poet.tang.49000.json','["春花秋月何時了，往事知多少。", "小樓昨夜又東風，故國不堪回首，月明中。", "雕闌玉砌應猶在，只是朱顏改。", "問君能有幾多愁，恰似一江春水，向東流。"]'),
('fcd2fbf3-006b-455f-b1c3-e35c2270331a','一斛珠','後主煜','唐','唐诗','tang','','[]','晚妝初過，沈檀輕注些兒箇，向人微露丁香顆。',67,'全唐诗/poet.tang.49000.json','["晚妝初過，沈檀輕注些兒箇，向人微露丁香顆。", "一曲清歌，暫引櫻桃破。", "羅袖裛殘殷色可，杯深旋被香醪涴，繡牀斜凭嬌無那。", "爛嚼紅茸，笑向檀郎唾。"]'),
('572f4c5e-0cb4-4643-98f9-cfbed581b50e','臨江仙','後主煜','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u7231\u56fd", "\u5fe7\u56fd\u5fe7\u6c11"]','櫻桃落盡春歸去，蝶飜輕粉雙飛。',68,'全唐诗/poet.tang.49000.json','["櫻桃落盡春歸去，蝶飜輕粉雙飛。", "子規啼月小樓西，玉鉤羅幕，惆悵暮煙垂。", "別巷寂寥人散後，望殘煙草低迷。", "爐香閑嫋鳳皇兒，空持羅帶，回首恨依依。"]'),
('cee2c436-21bb-419b-a1c5-dedfa2b9df6b','蝶戀花','後主煜','唐','唐诗','tang','','["\u601d\u5ff5", "\u5a49\u7ea6", "\u95fa\u6028"]','遙夜亭臯閑信步，纔過清明，漸覺傷春暮。',70,'全唐诗/poet.tang.49000.json','["遙夜亭臯閑信步，纔過清明，漸覺傷春暮。", "數點雨聲風約住，朦朧澹月雲來去。", "桃李依依香暗度，誰在鞦韆，笑裏輕輕語。", "一片芳心千萬緒，人間沒箇安排處。"]'),
('efee393d-cdbb-4780-8220-d4c29d69b15e','破陳子','後主煜','唐','唐诗','tang','','["\u8c6a\u653e", "\u611f\u4f24", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u7559\u604b", "\u5178\u6545"]','四十年來家國，三千里地山河。',72,'全唐诗/poet.tang.49000.json','["四十年來家國，三千里地山河。", "鳳闕龍樓連霄漢，玉樹瓊枝作煙蘿，幾曾識干戈？", "一旦歸爲臣虜，沈腰潘鬢銷磨。", "最是蒼黃辭廟日，教坊獨奏別離歌，垂淚對宮娥。"]'),
('cf6d988a-d303-448b-a273-3b5c931a8fea','醉妝詞','蜀主王衍','唐','唐诗','tang','','[]','者邊走，那邊走，只是尋花柳。',28,'全唐诗/poet.tang.49000.json','["者邊走，那邊走，只是尋花柳。", "那邊走，者邊走，莫厭金杯酒。"]'),
('b53c33bc-5951-4623-b974-7da3cea14c00','甘州曲','蜀主王衍','唐','唐诗','tang','','[]','畫羅裙，能解束。',34,'全唐诗/poet.tang.49000.json','["畫羅裙，能解束。", "稱腰身，柳眉桃臉不勝春。", "薄媚足精神，可惜淪落在風塵。"]'),
('94abda6b-1345-4fe2-9817-85ca2796bc39','木蘭花','後蜀主孟昶','唐','唐诗','tang','','[]','冰肌玉骨清無汗，水殿風來暗香滿。',64,'全唐诗/poet.tang.49000.json','["冰肌玉骨清無汗，水殿風來暗香滿。", "繡簾一點月窺人，欹枕釵橫雲鬢亂。", "起來瓊戶啓無聲，時見疎星渡河漢。", "屈指西風幾時來，只恐流年暗中換。"]'),
('a7980a53-95de-40a8-9a87-95dd9c93208d','回波樂','李景伯','唐','唐诗','tang','','[]','回波爾時酒巵，微臣職在箴規。',28,'全唐诗/poet.tang.49000.json','["回波爾時酒巵，微臣職在箴規。", "侍宴既過三爵，諠譁竊恐非儀。"]'),
('f3c17135-5240-4731-b63e-f2b8f38a4174','回波樂','沈佺期','唐','唐诗','tang','','[]','回波爾時佺期，流向嶺外生歸。',28,'全唐诗/poet.tang.49000.json','["回波爾時佺期，流向嶺外生歸。", "身名已蒙齒錄，袍笏未復牙緋。"]'),
('e3a3e537-35fb-4b2c-946c-b534996f5027','回波樂','裴談','唐','唐诗','tang','','[]','回波爾時栲栳，怕婦也是大好。',28,'全唐诗/poet.tang.49000.json','["回波爾時栲栳，怕婦也是大好。", "外邊祗有裴談，內裏無過李老。"]'),
('411f845b-3a45-4c82-b91a-363d77f4c36f','舞馬詞 一','張說','唐','唐诗','tang','','[]','萬玉朝宗鳳扆，千金率領龍媒。',28,'全唐诗/poet.tang.49000.json','["萬玉朝宗鳳扆，千金率領龍媒。", "眄鼓凝驕蹀躞，聽歌弄影徘徊。"]'),
('a4e4c3a0-ad43-4032-9399-9269529d1445','舞馬詞 二','張說','唐','唐诗','tang','','[]','天鹿遙徵衛叔，日龍上借羲和。',28,'全唐诗/poet.tang.49000.json','["天鹿遙徵衛叔，日龍上借羲和。", "將共兩驂爭舞，來隨八駿齊歌。"]'),
('5c4d085a-6d18-4a8e-b8a3-9bd113b64202','舞馬詞 三','張說','唐','唐诗','tang','','[]','綵旄八佾成行，時龍五色因方。',28,'全唐诗/poet.tang.49000.json','["綵旄八佾成行，時龍五色因方。", "屈膝銜杯赴節，傾心獻壽無疆。"]'),
('da38e39b-fa6d-47f0-a4a6-66254560c765','舞馬詞 四','張說','唐','唐诗','tang','','[]','帝皁龍駒沛艾，星闌驥子權奇。',28,'全唐诗/poet.tang.49000.json','["帝皁龍駒沛艾，星闌驥子權奇。", "騰倚驤洋應節，繁驕接迹不移。"]'),
('2ec43f54-be64-4219-8f1a-b0234cc347b3','舞馬詞 五','張說','唐','唐诗','tang','','[]','二聖先天合德，羣靈率土可封。',28,'全唐诗/poet.tang.49000.json','["二聖先天合德，羣靈率土可封。", "擊石驂驔紫燕，摐金顧步蒼龍。"]'),
('3cd4c930-9c6e-48d1-9e99-a11829d26134','舞馬詞 六','張說','唐','唐诗','tang','','[]','聖君出震應籙，神馬浮河獻圖。',28,'全唐诗/poet.tang.49000.json','["聖君出震應籙，神馬浮河獻圖。", "足蹋天庭鼓舞，心將帝樂踟躕。"]'),
('d0927bec-fc6f-4c90-a66c-5c770dd47b1d','蹋歌詞 一','崔液','唐','唐诗','tang','','[]','綵女迎金屋，仙姬出畫堂。',36,'全唐诗/poet.tang.49000.json','["綵女迎金屋，仙姬出畫堂。", "鴛鴦裁錦袖，翡翠貼花黃。", "歌響舞分行，豔色動流光。"]'),
('a41345e0-994a-4afc-af0d-f64fab5f8950','蹋歌詞 二','崔液','唐','唐诗','tang','','[]','庭際花微落，樓前漢已橫。',36,'全唐诗/poet.tang.49000.json','["庭際花微落，樓前漢已橫。", "金壺催夜盡，羅袖舞寒輕。", "樂笑暢歡情，未半著天明。"]'),
('9a305428-c083-4b95-acb1-855ebcd09873','桂殿秋 一','李白','唐','唐诗','tang','','[]','仙女下，董雙成，漢殿夜涼吹玉笙。',32,'全唐诗/poet.tang.49000.json','["仙女下，董雙成，漢殿夜涼吹玉笙。", "曲終却從仙官去，萬戶千門惟月明。"]'),
('861a8e22-08c6-4c52-a1f0-bf481d0ccbe7','桂殿秋 二','李白','唐','唐诗','tang','','[]','河漢女，玉鍊顏，雲軿往往在人間。',32,'全唐诗/poet.tang.49000.json','["河漢女，玉鍊顏，雲軿往往在人間。", "九霄有路去無跡，嫋嫋香風生佩環。"]'),
('d5da9d7d-1e52-4992-8be5-73e556b07e0b','清平調 一','李白','唐','唐诗','tang','','["\u5973\u5b50", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u8d5e\u7f8e", "\u8fd1\u4ee3\u66f2\u8f9e"]','雲想衣裳花想容，春風拂檻露華濃。',32,'全唐诗/poet.tang.49000.json','["雲想衣裳花想容，春風拂檻露華濃。", "若非羣玉山頭見，會向瑤臺月下逢。"]'),
('59063901-7dbc-4f22-974f-ddccab675cbc','清平調 二','李白','唐','唐诗','tang','','["\u5973\u5b50", "\u8fd1\u4ee3\u66f2\u8f9e", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','一枝紅豔露凝香，雲雨巫山枉斷腸。',32,'全唐诗/poet.tang.49000.json','["一枝紅豔露凝香，雲雨巫山枉斷腸。", "借問漢宮誰得似，可憐飛燕倚新妝。"]'),
('f91f3117-2bf2-4d12-999a-aca174124715','清平調 三','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u5199\u4eba", "\u82b1", "\u5199\u82b1"]','名花傾國兩相歡，常得君王帶笑看。',32,'全唐诗/poet.tang.49000.json','["名花傾國兩相歡，常得君王帶笑看。", "解得春風無限恨，沈香亭北倚闌干。"]'),
('64d66549-1b3e-4a28-84be-590777c9b5b5','連理枝 一','李白','唐','唐诗','tang','','[]','雪蓋宮樓閉，羅幕昏金翠。',42,'全唐诗/poet.tang.49000.json','["雪蓋宮樓閉，羅幕昏金翠。", "鬬壓闌干，香心澹薄，梅梢輕倚。", "噴寶猊香燼麝煙濃，馥紅綃翠被。"]'),
('f5e39c65-60fd-49d1-ba82-3f46a6be880d','連理枝 二','李白','唐','唐诗','tang','','[]','淺畫雲垂帔，點滴昭陽淚。',42,'全唐诗/poet.tang.49000.json','["淺畫雲垂帔，點滴昭陽淚。", "咫尺宸居，君恩斷絕，似遙千里。", "望水晶簾外竹枝寒，守羊車未至。"]'),
('f98b9110-23de-481c-bd87-bcdf2c14d05c','菩薩蠻','李白','唐','唐诗','tang','','["\u8c6a\u653e", "\u5199\u666f", "\u79cb\u5929", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u6000\u4eba", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','平林漠漠煙如織，寒山一帶傷心碧。',52,'全唐诗/poet.tang.49000.json','["平林漠漠煙如織，寒山一帶傷心碧。", "暝色入高樓，有人樓上愁。", "玉階空佇立，宿鳥歸飛急。", "何處是歸程，長亭更短亭。"]'),
('35f9a3a0-9e54-4450-930d-f6bdc051ba1f','憶秦娥','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u8c6a\u653e", "\u5fe7\u6101", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5973\u5b50", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','簫聲咽，秦娥夢斷秦樓月。',56,'全唐诗/poet.tang.49000.json','["簫聲咽，秦娥夢斷秦樓月。", "秦樓月，年年柳色，灞陵傷別。", "樂遊原上清秋節，咸陽古道音塵絕。", "音塵絕，西風殘照，漢家陵闕。"]'),
('eae8a09d-b5b5-42bc-b196-2853ba90fc32','清平樂 一','李白','唐','唐诗','tang','','[]','禁庭春晝，鶯羽披新繡。',54,'全唐诗/poet.tang.49000.json','["禁庭春晝，鶯羽披新繡。", "百草巧求花下鬬，祗賭珠璣滿斗。", "日晚却理殘妝，御前閑舞霓裳。", "誰道腰肢窈窕，折旋笑得君王。"]'),
('12a47c99-b1dd-47cf-8a1a-d0aed438ee47','清平樂 二','李白','唐','唐诗','tang','','[]','禁闈秋夜，月探金窗罅。',54,'全唐诗/poet.tang.49000.json','["禁闈秋夜，月探金窗罅。", "玉帳鴛鴦噴蘭麝，時落銀燈香灺。", "女伴莫話孤眠，六宮羅綺三千。", "一笑皆生百媚，宸衷教在誰邊。"]'),
('32654d69-48c7-4d34-ab41-939387e218f3','清平樂 三','李白','唐','唐诗','tang','','[]','煙深水闊，音信無由達。',54,'全唐诗/poet.tang.49000.json','["煙深水闊，音信無由達。", "惟有碧天雲外月，偏照懸懸離別。", "盡日感事傷懷，愁眉似鎖難開。", "夜夜長留半被，待君魂夢歸來。"]'),
('a56513d2-5de0-4941-b2f1-e0d33d681f20','清平樂 四','李白','唐','唐诗','tang','','[]','鸞衾鳳褥，夜夜常孤宿。',54,'全唐诗/poet.tang.49000.json','["鸞衾鳳褥，夜夜常孤宿。", "更被銀臺紅蠟燭，學妾淚珠相續。", "花貌些子時光，拋人遠泛瀟湘。", "欹枕悔聽寒漏，聲聲滴斷愁腸。"]'),
('b1815804-563b-47ad-ace0-013a657a2454','清平樂 五','李白','唐','唐诗','tang','','[]','畫堂晨起，來報雪花墜。',54,'全唐诗/poet.tang.49000.json','["畫堂晨起，來報雪花墜。", "高卷簾櫳看佳瑞，皓色遠迷庭砌。", "盛氣光引爐煙，素草寒生玉佩。", "應是天仙狂醉，亂把白雲揉碎。"]'),
('a651660b-9ffb-4a39-bade-6f08a9a191c8','欸乃曲 一','元結','唐','唐诗','tang','','[]','偶存名跡在人間，順俗與時未安閑。',32,'全唐诗/poet.tang.49000.json','["偶存名跡在人間，順俗與時未安閑。", "來謁大官兼問政，扁舟却入九疑山。"]'),
('825b4d77-f788-4fe9-8d4c-d03295a8d129','欸乃曲 二','元結','唐','唐诗','tang','','[]','湘江二月春水平，滿月和風宜夜行。',32,'全唐诗/poet.tang.49000.json','["湘江二月春水平，滿月和風宜夜行。", "唱橈欲過平陽戍，守吏相呼問姓名。"]'),
('47b69d9d-22a9-4cd2-8034-4a66ba168d04','欸乃曲 三','元結','唐','唐诗','tang','','[]','千里楓林煙雨深，無朝無暮有猨吟。',32,'全唐诗/poet.tang.49000.json','["千里楓林煙雨深，無朝無暮有猨吟。", "倚橈靜聽曲中意，好似雲山韶濩音。"]'),
('cafd6c88-e504-478a-817d-5fc1928fe196','欸乃曲 四','元結','唐','唐诗','tang','','[]','零陵郡北湘水東，浯溪形勝滿湘中。',32,'全唐诗/poet.tang.49000.json','["零陵郡北湘水東，浯溪形勝滿湘中。", "溪口石顛堪自逸，誰能相伴作漁翁。"]'),
('319a4c84-ee02-4d8c-b2db-a10bb20d7b1f','欸乃曲 五','元結','唐','唐诗','tang','','[]','下瀧船似入深淵，上瀧船似欲升天。',32,'全唐诗/poet.tang.49000.json','["下瀧船似入深淵，上瀧船似欲升天。", "瀧南始到九疑郡，應絕高人乘興船。"]'),
('d7916ae3-233e-46e1-97e1-7d561fb204f9','漁父 一','張志和','唐','唐诗','tang','','["\u5c71\u6c34", "\u5199\u666f", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u56db\u5e74\u7ea7\u4e0b\u518c", "\u5199\u4eba", "\u6292\u6000"]','西塞山前白鷺飛，桃花流水鱖魚肥。',32,'全唐诗/poet.tang.49000.json','["西塞山前白鷺飛，桃花流水鱖魚肥。", "青箬笠，綠蓑衣，斜風細雨不須歸。"]'),
('ec66e4c3-c21a-4d18-99f1-a21d0efcb1d7','漁父 二','張志和','唐','唐诗','tang','','["\u957f\u6c5f"]','釣臺漁父褐爲裘，兩兩三三舴艋舟。',32,'全唐诗/poet.tang.49000.json','["釣臺漁父褐爲裘，兩兩三三舴艋舟。", "能縱櫂，慣乘流，長江白浪不曾憂。"]'),
('6d4c05b5-a879-4d95-b890-8774117b6f9f','漁父 三','張志和','唐','唐诗','tang','','[]','霅溪灣裏釣魚翁，舴艋爲家西復東。',32,'全唐诗/poet.tang.49000.json','["霅溪灣裏釣魚翁，舴艋爲家西復東。", "江上雪，浦邊風，笑著荷衣不歎窮。"]'),
('0f61f362-16e8-495e-bfbd-5914a758f42f','漁父 四','張志和','唐','唐诗','tang','','[]','松江蟹舍主人歡，菰飯蓴羹亦共餐。',32,'全唐诗/poet.tang.49000.json','["松江蟹舍主人歡，菰飯蓴羹亦共餐。", "楓葉落，荻花乾，醉宿漁舟不覺寒。"]'),
('37f68ce7-c771-45ee-96cc-c9107e641ec1','漁父 五','張志和','唐','唐诗','tang','','[]','青草湖中月正圓，巴陵漁父櫂歌連。',32,'全唐诗/poet.tang.49000.json','["青草湖中月正圓，巴陵漁父櫂歌連。", "釣車子，橛頭船，樂在風波不用仙。"]'),
('d2d0b16b-1d7b-4735-8773-324bf0191675','漁父','張松齡','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','樂是風波釣是閑，草堂松檜已勝攀。',32,'全唐诗/poet.tang.49000.json','["樂是風波釣是閑，草堂松檜已勝攀。", "太湖水，洞庭山，狂風浪起且須還。"]'),
('0a815f47-0331-40fe-9500-3a1b698b2deb','章臺柳','韓翃','唐','唐诗','tang','','[]','章臺柳，章臺柳，往日依依今在否？縱使長條似舊垂，也應攀折他人手。',32,'全唐诗/poet.tang.49000.json','["章臺柳，章臺柳，往日依依今在否？縱使長條似舊垂，也應攀折他人手。"]'),
('c467bd98-a27b-4810-8178-38eb61269796','三臺 一','韋應物','唐','唐诗','tang','','[]','一年一年老去，明日後日花開。',28,'全唐诗/poet.tang.49000.json','["一年一年老去，明日後日花開。", "未報長安平定，萬國豈得銜杯。"]'),
('a4a3ccdd-a8e6-45da-afcc-12a1db60f2c5','三臺 二','韋應物','唐','唐诗','tang','','[]','冰泮寒塘水綠，雨餘百草皆生。',28,'全唐诗/poet.tang.49000.json','["冰泮寒塘水綠，雨餘百草皆生。", "朝來衡門無事，晚下高齋有情。"]'),
('ee3f8beb-8c76-4c7f-930c-ce1d566cced3','調笑令 一','韋應物','唐','唐诗','tang','','["\u5bd3\u4eba", "\u5b64\u72ec", "\u8c6a\u653e", "\u9a6c", "\u5199\u9a6c"]','胡馬，胡馬，遠放燕支山下。',40,'全唐诗/poet.tang.49000.json','["胡馬，胡馬，遠放燕支山下。", "跑沙跑雪獨嘶，東望西望路迷。", "迷路，迷路，邊草無窮日暮。"]'),
('ab3d4352-40f7-4d0c-9809-d591da9f2c45','調笑令 二','韋應物','唐','唐诗','tang','','[]','河漢，河漢，曉挂秋城漫漫。',40,'全唐诗/poet.tang.49000.json','["河漢，河漢，曉挂秋城漫漫。", "愁人起望相思，塞北江南別離。", "離別，離別，河漢雖同路絕。"]'),
('4826c899-c283-4054-84a9-6a290c6c62db','三臺 一','王建','唐','唐诗','tang','','[]','魚藻池邊射鴨，芙蓉苑裏看花。',28,'全唐诗/poet.tang.49000.json','["魚藻池邊射鴨，芙蓉苑裏看花。", "日色柘袍相似，不著紅鸞扇遮。"]'),
('fc2e8477-7436-4e4c-9b8c-bf242a325691','三臺 二','王建','唐','唐诗','tang','','[]','池北池南草綠，殿前殿後花紅。',28,'全唐诗/poet.tang.49000.json','["池北池南草綠，殿前殿後花紅。", "天子千秋萬歲，未央明月清風。"]'),
('55ea44f4-fd09-4fc2-a06c-b0012ff44281','三臺 三','王建','唐','唐诗','tang','','[]','揚州橋邊小婦，長干市裏商人。',28,'全唐诗/poet.tang.49000.json','["揚州橋邊小婦，長干市裏商人。", "三年不得消息，各自拜鬼求神。"]'),
('a6d96ec6-f3d5-429e-9e29-52c108f34561','三臺 四','王建','唐','唐诗','tang','','[]','青草湖邊草色，飛猨嶺上猨聲。',28,'全唐诗/poet.tang.49000.json','["青草湖邊草色，飛猨嶺上猨聲。", "萬里三湘客到，有風有雨人行。"]'),
('4325ee75-6b58-4d3e-b6ad-3b3df49f7f24','三臺 五','王建','唐','唐诗','tang','','[]','樹頭花落花開，道上人去人來。',28,'全唐诗/poet.tang.49000.json','["樹頭花落花開，道上人去人來。", "朝愁暮愁即老，百年幾度三臺。"]'),
('50b9cd44-6c49-4e7e-95d0-ef47fc4a00a0','三臺 六','王建','唐','唐诗','tang','','[]','鬬身彊健且爲，頭白齒落難追。',28,'全唐诗/poet.tang.49000.json','["鬬身彊健且爲，頭白齒落難追。", "準擬百年千歲，能得幾許多時。"]'),
('53640410-5611-4d86-83ed-c0aa7f2e4930','調笑令 一','王建','唐','唐诗','tang','','["\u548f\u7269", "\u65f6\u5149", "\u4e50\u5e9c", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u548f\u7269\u8bd7", "\u611f\u6168"]','團扇，團扇，美人竝來遮面。',40,'全唐诗/poet.tang.49000.json','["團扇，團扇，美人竝來遮面。", "玉顏顦顇三年，誰復商量管弦。", "弦管，弦管，春草昭陽路斷。"]'),
('1b5ad1b1-6a9c-492b-860b-936e922323da','調笑令 二','王建','唐','唐诗','tang','','[]','胡蝶，胡蝶，飛上金枝玉葉。',40,'全唐诗/poet.tang.49000.json','["胡蝶，胡蝶，飛上金枝玉葉。", "君前對舞春風，百葉桃花樹紅。", "紅樹，紅樹，燕語鶯啼日暮。"]'),
('7324810b-af18-4a39-af66-bbf93c45f247','調笑令 三','王建','唐','唐诗','tang','','[]','羅袖，羅袖，暗舞春風依舊。',40,'全唐诗/poet.tang.49000.json','["羅袖，羅袖，暗舞春風依舊。", "遙看歌舞玉樓，好日新妝坐愁。", "愁坐，愁坐，一世虛生虛過。"]'),
('2b730ae2-7e32-4eb7-9b37-e1844e83a743','調笑令 四','王建','唐','唐诗','tang','','[]','楊柳，楊柳，日暮白沙渡口。',40,'全唐诗/poet.tang.49000.json','["楊柳，楊柳，日暮白沙渡口。", "船頭江水茫茫，商人少婦斷腸。", "腸斷，腸斷，鷓鴣夜飛失伴。"]'),
('125198bd-4bfd-43ef-ae9c-74bbd8fc114e','調笑令','戴叔倫','唐','唐诗','tang','','["\u8c6a\u653e", "\u5199\u666f", "\u8fb9\u585e", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u601d\u4e61", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','邊草，邊草，邊草盡來兵老。',40,'全唐诗/poet.tang.49000.json','["邊草，邊草，邊草盡來兵老。", "山南山北雪晴，千里萬里月明。", "明月，明月，胡笳一聲愁絕。"]'),
('45868452-c3f4-449b-be00-11027f4d11c5','紇那曲 一','劉禹錫','唐','唐诗','tang','','[]','楊柳鬱青青，竹枝無限情。',24,'全唐诗/poet.tang.49000.json','["楊柳鬱青青，竹枝無限情。", "同郎一回顧，聽唱紇那聲。"]'),
('9f443629-464c-4f44-aab8-ebd11e96e133','紇那曲 二','劉禹錫','唐','唐诗','tang','','[]','蹋曲興無窮，調同辭不同。',24,'全唐诗/poet.tang.49000.json','["蹋曲興無窮，調同辭不同。", "願郎千萬壽，長作主人翁。"]'),
('f98769ab-7570-403c-9cc4-b0a37f53b128','憶江南 一','劉禹錫','唐','唐诗','tang','','[]','春去也，多謝洛城人。',32,'全唐诗/poet.tang.49000.json','["春去也，多謝洛城人。", "弱柳從風疑舉袂，叢蘭裛露似霑巾，獨坐亦含嚬。"]'),
('8ba48f1b-7fa7-4af7-b4ee-dabca81e4aa6','憶江南 二','劉禹錫','唐','唐诗','tang','','[]','春去也，共惜豔陽年。',32,'全唐诗/poet.tang.49000.json','["春去也，共惜豔陽年。", "猶有桃花流水上，無辭竹葉醉尊前，惟待見青天。"]'),
('fe80a80e-47ab-4df7-9caf-38696df0a6d2','瀟湘神 一','劉禹錫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u548f\u7269", "\u5a49\u7ea6"]','湘水流，湘水流，九疑雲物至今愁。',32,'全唐诗/poet.tang.49000.json','["湘水流，湘水流，九疑雲物至今愁。", "若問二妃何處所，零陵芳草露中秋。"]'),
('bb5def99-f902-458f-be0a-0cf05a46f34b','瀟湘神 二','劉禹錫','唐','唐诗','tang','','["\u6000\u53e4", "\u548f\u7269", "\u54c0\u6028", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u548f\u7269\u8bd7", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','斑竹枝，斑竹枝，淚痕點點寄相思。',32,'全唐诗/poet.tang.49000.json','["斑竹枝，斑竹枝，淚痕點點寄相思。", "楚客欲聽瑤瑟怨，瀟湘深夜月明時。"]'),
('d114e7b2-6988-42a2-9715-8bb1571d760d','拋毬樂 一','劉禹錫','唐','唐诗','tang','','[]','五色繡團圓，登君玳瑁筵。',36,'全唐诗/poet.tang.49000.json','["五色繡團圓，登君玳瑁筵。", "最宜紅燭下，偏稱落花前。", "上客如先起，應須贈一船。"]'),
('0e2e08eb-8931-40e3-94b8-3e0938dc9947','拋毬樂 二','劉禹錫','唐','唐诗','tang','','[]','春早見花枝，朝朝恨發遲。',36,'全唐诗/poet.tang.49000.json','["春早見花枝，朝朝恨發遲。", "及看花落後，却憶未開時。", "幸有拋毬樂，一杯君莫辭。"]'),
('90ad61e9-31b9-47da-8e98-880130a5bb2e','花非花','白居易','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u611f\u609f", "\u4eba\u751f", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','花非花，霧非霧，夜半來，天明去。',32,'全唐诗/poet.tang.49000.json','["花非花，霧非霧，夜半來，天明去。", "來如春夢不多時，去似朝雲無覓處。"]'),
('0449a6d9-ad81-4cea-99d4-70018fc863a2','憶江南 一','白居易','唐','唐诗','tang','','["\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u56db\u5e74\u7ea7\u4e0b\u518c", "\u6c34", "\u666f\u70b9", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5c0f\u5b66\u53e4\u8bd7"]','江南好，風景舊曾諳。',32,'全唐诗/poet.tang.49000.json','["江南好，風景舊曾諳。", "日出江花紅勝火，春來江水綠如藍，能不憶江南。"]'),
('4e8038d4-685d-47fe-a65f-3fb103a42f50','憶江南 二','白居易','唐','唐诗','tang','','[]','江南憶，最憶是杭州。',32,'全唐诗/poet.tang.49000.json','["江南憶，最憶是杭州。", "山寺月中尋桂子，郡亭枕上看潮頭，何日更重遊。"]'),
('23124f06-e77f-4e20-b28c-f848c1a7479d','憶江南 三','白居易','唐','唐诗','tang','','[]','江南憶，其次憶吳宮。',32,'全唐诗/poet.tang.49000.json','["江南憶，其次憶吳宮。", "吳酒一杯春竹葉，吳娃雙舞醉芙蓉，早晚得相逢。"]'),
('9a0bfa8a-591e-437b-bd39-b5fdbd5b5bd2','如夢令 一','白居易','唐','唐诗','tang','','["\u6292\u60c5"]','前度小花靜院，不比尋常時見。',40,'全唐诗/poet.tang.49000.json','["前度小花靜院，不比尋常時見。", "見了又還休，愁却等閑分散。", "腸斷，腸斷，記取釵橫鬢亂。"]'),
('03c21a01-73a7-4bb0-b5aa-0852c8fce6fb','如夢令 二','白居易','唐','唐诗','tang','','[]','落月西窗驚起，好箇怱怱些子。',40,'全唐诗/poet.tang.49000.json','["落月西窗驚起，好箇怱怱些子。", "鬒鬢嚲輕鬆，凝了一雙秋水。", "告你，告你，休向人間整理。"]'),
('cdaa4410-880c-4830-b7ef-d770ecdc28cc','如夢令 三','白居易','唐','唐诗','tang','','["\u6292\u60c5"]','頻日雅歡幽會，打得來來越曬。',40,'全唐诗/poet.tang.49000.json','["頻日雅歡幽會，打得來來越曬。", "說著暫分飛，蹙損一雙眉黛。", "無奈，無奈，兩箇心兒總待。"]'),
('a4c60d0e-3945-4461-a9e1-d1d025227880','長相思 一','白居易','唐','唐诗','tang','','["\u5a49\u7ea6", "\u5c71\u6c34", "\u76f8\u601d", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5973\u5b50", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','汴水流，泗水流，流到瓜洲古渡頭，吳山點點愁。',44,'全唐诗/poet.tang.49000.json','["汴水流，泗水流，流到瓜洲古渡頭，吳山點點愁。", "思悠悠，恨悠悠，恨到歸時方始休，月明人倚樓。"]'),
('854a4e93-dc1b-4bde-a05c-d647097f9dcc','長相思 二','白居易','唐','唐诗','tang','','[]','深畫眉，淺畫眉，蟬鬢鬅鬙雲滿衣，陽臺行雨回。',44,'全唐诗/poet.tang.49000.json','["深畫眉，淺畫眉，蟬鬢鬅鬙雲滿衣，陽臺行雨回。", "巫山高，巫山低，暮雨瀟瀟郎不歸，空房獨守時。"]'),
('ad3ff46e-1956-472a-9a70-d9f43d2084ba','謫仙怨','劉長卿','唐','唐诗','tang','','["\u601d\u5ff5", "\u9001\u522b", "\u5199\u666f", "\u5a49\u7ea6"]','晴川落日初低，惆悵孤舟解攜。',56,'全唐诗/poet.tang.49000.json','["晴川落日初低，惆悵孤舟解攜。", "鳥向平蕪遠近，人隨流水東西。", "白雲千里萬里，明月前溪後溪。", "獨恨長沙謫去，江潭春草萋萋。"]'),
('ba3d87f9-cdcb-4f70-ac65-b69464a62794','廣謫仙怨','竇弘餘','唐','唐诗','tang','','[]','胡塵犯闕衝關，金輅提攜玉顏。',56,'全唐诗/poet.tang.49000.json','["胡塵犯闕衝關，金輅提攜玉顏。", "雲雨此時蕭散，君王何日歸還。", "傷心朝恨暮恨，回首千山萬山。", "獨望天邊初月，蛾眉猶自彎彎。"]'),
('afdfbef0-2c07-4161-bc63-e5840e94a833','廣謫仙怨','康駢','唐','唐诗','tang','','[]','晴山礙目橫天，綠疊君王馬前。',56,'全唐诗/poet.tang.49000.json','["晴山礙目橫天，綠疊君王馬前。", "鑾輅西巡蜀國，龍顏東望秦川。", "曲江魂斷芳草，妃子愁凝暮煙。", "長笛此時吹罷，何言獨爲嬋娟。"]'),
('21360c26-9b3a-490b-a231-8fc91d7ceca7','八六子','杜牧','唐','唐诗','tang','','["\u5bab\u6028", "\u5199\u4eba", "\u5b64\u5bc2", "\u60c6\u6005", "\u5199\u4eba\u8bd7"]','洞房深，畫屏燈照，山色凝翠沈沈。',110,'全唐诗/poet.tang.49000.json','["洞房深，畫屏燈照，山色凝翠沈沈。", "聽夜雨，冷滴芭蕉，驚斷紅窗好夢，龍煙細飄繡衾。", "辭恩久歸長信，鳳帳蕭疎，椒殿閑扃。", "輦路苔侵，繡簾垂，遲遲漏傳丹禁。", "蕣華偷悴，翠鬟羞整，愁坐望處，金輿漸遠。", "何時綵仗重臨，正消魂，梧桐又移翠陰。"]'),
('d46a229e-476e-4696-bd0a-4a5a9f8fe6aa','憶江南','崔懷寶','唐','唐诗','tang','','[]','平生願，願作樂中箏。',32,'全唐诗/poet.tang.49000.json','["平生願，願作樂中箏。", "得近玉人纖手子，砑羅裙上放嬌聲，便死也爲榮。"]'),
('f8dc5127-3cd8-44b8-8be0-7474b3c50891','閑中好','鄭符','唐','唐诗','tang','','[]','閑中好，盡日松爲侶。',22,'全唐诗/poet.tang.49000.json','["閑中好，盡日松爲侶。", "此趣人不知，輕風度僧語。"]'),
('c4b63d22-e387-4bb6-9770-811082b02653','閑中好','段成式','唐','唐诗','tang','','[]','閑中好，塵務不縈心。',22,'全唐诗/poet.tang.49000.json','["閑中好，塵務不縈心。", "坐對當窗木，看移三面陰。"]'),
('2f87a7a6-f620-4d6c-a446-09fa9c0d8fbc','閑中好','張希復','唐','唐诗','tang','','[]','閑中好，幽磬度聲遲。',22,'全唐诗/poet.tang.49000.json','["閑中好，幽磬度聲遲。", "卷上論題肇，畫盡僧姓支。"]'),
('d99e2f5e-ee89-4cd7-a863-57c59f6580c1','南歌子 一','溫庭筠','唐','唐诗','tang','','["\u5a49\u7ea6", "\u5a49\u7ea6\u8bcd", "\u5973\u5b50", "\u76f8\u601d"]','手裏金鸚鵡，胸前繡鳳凰。',28,'全唐诗/poet.tang.49000.json','["手裏金鸚鵡，胸前繡鳳凰。", "偷眼暗形相。", "不如從嫁與，作鴛鴦。"]'),
('49a955c2-6df5-4738-8cbb-92439838ae5d','南歌子 二','溫庭筠','唐','唐诗','tang','','["\u5199\u4eba", "\u7231\u60c5"]','似帶如絲柳，團酥握雪花。',28,'全唐诗/poet.tang.49000.json','["似帶如絲柳，團酥握雪花。", "簾卷玉鉤斜。", "九衢塵欲暮，逐香車。"]'),
('4079336c-10ee-4be9-b3e2-f441de49255a','南歌子 三','溫庭筠','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50", "\u7231\u60c5"]','倭墮低梳髻，連娟細掃眉。',28,'全唐诗/poet.tang.49000.json','["倭墮低梳髻，連娟細掃眉。", "終日兩相思。", "爲君憔悴盡，百花時。"]'),
('584bfc0d-09cb-4658-ae15-bf501081ad0a','南歌子 四','溫庭筠','唐','唐诗','tang','','[]','臉上金霞細，眉間翠鈿深。',28,'全唐诗/poet.tang.49000.json','["臉上金霞細，眉間翠鈿深。", "欹枕覆鴛衾。", "隔簾鸎百轉，感君心。"]'),
('29d3df5c-6e64-422a-a069-15fd99d50250','南歌子 五','溫庭筠','唐','唐诗','tang','','[]','撲蘂添黃子，呵花滿翠鬟。',28,'全唐诗/poet.tang.49000.json','["撲蘂添黃子，呵花滿翠鬟。", "鴛枕映屏山。", "月明三五夜，對芳顏。"]'),
('2408519c-0eef-4b3b-b96c-a1259ed1922e','南歌子 六','溫庭筠','唐','唐诗','tang','','[]','轉盼如波眼，娉婷似柳腰。',28,'全唐诗/poet.tang.49000.json','["轉盼如波眼，娉婷似柳腰。", "花裏暗相招。", "憶君腸欲斷，恨春宵。"]'),
('9e189e4f-276d-4a7e-8e00-8863c6147dd7','南歌子 七','溫庭筠','唐','唐诗','tang','','[]','嬾拂鴛鴦枕，休縫翡翠裙。',28,'全唐诗/poet.tang.49000.json','["嬾拂鴛鴦枕，休縫翡翠裙。", "羅帳罷爐熏。", "近來心更切，爲思君。"]'),
('7f11f101-e336-46bd-abc2-85695fb6f265','荷葉杯 一','溫庭筠','唐','唐诗','tang','','[]','一點露珠凝冷，波影，滿池塘。',29,'全唐诗/poet.tang.49000.json','["一點露珠凝冷，波影，滿池塘。", "綠莖紅豔兩相亂，腸斷，水風涼。"]'),
('bc72eed6-4019-476d-931b-f188b00963c2','荷葉杯 二','溫庭筠','唐','唐诗','tang','','["\u5c11\u5973", "\u6708\u591c", "\u79cb\u5929", "\u5b64\u72ec", "\u6c34", "\u611f\u4f24"]','鏡水夜來秋月，如雪，采蓮時。',29,'全唐诗/poet.tang.49000.json','["鏡水夜來秋月，如雪，采蓮時。", "小娘紅粉對寒浪，惆悵，正思惟。"]'),
('4bbcb4bd-3d77-4200-8159-27a16d599c93','荷葉杯 三','溫庭筠','唐','唐诗','tang','','[]','楚女欲歸南浦，朝雨，濕愁紅。',29,'全唐诗/poet.tang.49000.json','["楚女欲歸南浦，朝雨，濕愁紅。", "小船搖漾入花裏，波起，隔西風。"]'),
('8fedbcda-2e90-45b2-bca9-5ce76a39b0c6','憶江南 一','溫庭筠','唐','唐诗','tang','','["\u6000\u4eba", "\u5a49\u7ea6\u8bcd", "\u5987\u5973", "\u5199\u666f", "\u5a49\u7ea6"]','千萬恨，恨極在天涯。',32,'全唐诗/poet.tang.49000.json','["千萬恨，恨極在天涯。", "山月不知心裏事，水風空落眼前花，搖曳碧雲斜。"]'),
('d636903d-bd15-4d66-8198-e245421b2d43','憶江南 二','溫庭筠','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e5d\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5185)", "\u95fa\u6028", "\u65e0\u5948", "\u521d\u4e2d\u53e4\u8bd7", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','梳洗罷，獨倚望江樓。',32,'全唐诗/poet.tang.49000.json','["梳洗罷，獨倚望江樓。", "過盡千帆皆不是，斜暉脈脈水悠悠，腸斷白蘋洲。"]'),
('3a3c48ce-3087-4345-9060-bcace431fa06','蕃女怨 一','溫庭筠','唐','唐诗','tang','','[]','萬枝香雪開已遍，細雨雙燕。',38,'全唐诗/poet.tang.49000.json','["萬枝香雪開已遍，細雨雙燕。", "鈿蟬箏，金雀扇，畫梁相見。", "鴈門消息不歸來，又飛回。"]'),
('2f47370d-d3b1-405d-822c-14cb1bccd6ff','蕃女怨 二','溫庭筠','唐','唐诗','tang','','[]','磧南沙上驚鴈起，飛雪千里。',38,'全唐诗/poet.tang.49000.json','["磧南沙上驚鴈起，飛雪千里。", "玉連環，金鏃箭，年年征戰。", "畫樓離恨錦屏空，杏花紅。"]'),
('0347b7f5-9733-4661-94b3-d32e7b2e41c1','遐方怨 一','溫庭筠','唐','唐诗','tang','','[]','憑繡檻，解羅幃。',39,'全唐诗/poet.tang.49000.json','["憑繡檻，解羅幃。", "未得君書，斷腸瀟湘春鴈飛。", "不知征馬幾時歸。", "海棠花謝也，雨霏霏。"]'),
('d8e18621-ec00-42be-88be-ead999a9b448','遐方怨 二','溫庭筠','唐','唐诗','tang','','["\u5199\u4eba", "\u5973\u5b50", "\u5199\u4eba\u8bd7"]','花半拆，雨初晴。',39,'全唐诗/poet.tang.49000.json','["花半拆，雨初晴。", "未卷珠簾，夢殘惆悵聞曉鸎。", "宿妝眉淺粉山橫。", "約鬟鸞鏡裏，繡羅輕。"]'),
('2352b4ff-5ef8-4823-a9aa-c40b51317d91','訴衷情','溫庭筠','唐','唐诗','tang','','[]','鸎語，花舞，春晝午，雨霏微。',44,'全唐诗/poet.tang.49000.json','["鸎語，花舞，春晝午，雨霏微。", "金帶枕，宮錦，鳳凰帷。", "柳弱燕交飛，依依。", "遼陽音信稀，夢中歸。"]'),
('09e2a67e-6769-40cb-8e77-5d3997fc0910','定西番 一','溫庭筠','唐','唐诗','tang','','[]','漢使昔年離別，攀弱柳，折寒梅，上高臺。',43,'全唐诗/poet.tang.49000.json','["漢使昔年離別，攀弱柳，折寒梅，上高臺。", "千里玉關春雪，鴈來人不來。", "羌笛一聲愁絕，月裴回。"]'),
('8c9069ed-53b4-4a1d-a7ee-a8886755fe84','定西番 二','溫庭筠','唐','唐诗','tang','','[]','海燕欲飛調羽，萱草綠，杏花紅，隔簾櫳。',43,'全唐诗/poet.tang.49000.json','["海燕欲飛調羽，萱草綠，杏花紅，隔簾櫳。", "雙鬢翠霞金縷，一枝春豔濃。", "樓上月明三五，瑣窗中。"]'),
('4335ddbc-1bb4-40a8-a1cc-7d54f28b9da7','定西番 三','溫庭筠','唐','唐诗','tang','','[]','細雨曉鸎春晚，人似玉，柳如眉，正相思。',43,'全唐诗/poet.tang.49000.json','["細雨曉鸎春晚，人似玉，柳如眉，正相思。", "羅幕翠簾初卷，鏡中花一枝。", "腸斷塞門消息，鴈來稀。"]'),
('309d735a-1524-4b44-bdcd-fabcfa11b5de','思帝鄉','溫庭筠','唐','唐诗','tang','','[]','花花，滿枝紅似霞。',44,'全唐诗/poet.tang.49000.json','["花花，滿枝紅似霞。", "羅袖畫簾腸斷，卓香車。", "回面共人閑語，戰箆金鳳斜。", "惟有阮郎春盡，不歸家。"]'),
('013cb0b3-b1fa-4af0-90a4-7a9b726de72a','酒泉子 一','溫庭筠','唐','唐诗','tang','','["\u6625\u5929", "\u6000\u8fdc", "\u5973\u5b50"]','花映柳條，閑向綠萍池上。',50,'全唐诗/poet.tang.49000.json','["花映柳條，閑向綠萍池上。", "凭欄干，窺細浪，雨蕭蕭。", "近來音信兩疎索，洞房空寂寞。", "掩銀屏，垂翠箔，度春宵。"]'),
('b09b9100-ebd2-4273-bce3-ddd1e4aaa0c2','酒泉子 二','溫庭筠','唐','唐诗','tang','','["\u6000\u4eba", "\u6292\u60c5", "\u6625\u5929", "\u5973\u5b50"]','日映紗窗，金鴨小屏山碧。',50,'全唐诗/poet.tang.49000.json','["日映紗窗，金鴨小屏山碧。", "故鄉春，煙靄隔，背蘭釭。", "宿妝惆悵倚高閣，千里雲影薄。", "草初齊，花又落，燕雙飛。"]'),
('b7cf2121-6dad-4ab1-87d5-617011d94aea','酒泉子 三','溫庭筠','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u4eba", "\u601d\u4e61", "\u4f24\u522b"]','楚女不歸，樓枕小河春水。',50,'全唐诗/poet.tang.49000.json','["楚女不歸，樓枕小河春水。", "月孤明，風又起，杏花稀。", "玉釵斜篸雲鬟重，裙上金縷鳳。", "八行書，千里夢，鴈南飛。"]'),
('2af81995-8280-4643-97c8-6338ac5b6823','酒泉子 四','溫庭筠','唐','唐诗','tang','','["\u6292\u60c5", "\u5b64\u5bc2", "\u5199\u666f", "\u76f8\u601d"]','羅帶惹香，猶繫別時紅豆。',51,'全唐诗/poet.tang.49000.json','["羅帶惹香，猶繫別時紅豆。", "淚痕新，金縷舊，斷離腸。", "一雙嬌燕語雕梁，還是去年時節。", "綠楊濃，芳草歇，柳花狂。"]'),
('5d0722d8-d700-4352-aa87-65ebb23e15a3','玉蝴蝶','溫庭筠','唐','唐诗','tang','','["\u79bb\u522b", "\u6000\u4eba", "\u79cb\u5929", "\u76f8\u601d"]','秋風淒切傷離，行客未歸時。',49,'全唐诗/poet.tang.49000.json','["秋風淒切傷離，行客未歸時。", "塞外草先衰，江南鴈到遲。", "芙蓉凋嫩臉，楊柳墮新眉。", "搖落使人悲，斷腸誰得知。"]'),
('10cb84f1-60b5-4f09-8534-4e0c7cba518d','女冠子 一','溫庭筠','唐','唐诗','tang','','[]','含嬌含笑，宿翠殘紅窈窕，鬢如蟬。',50,'全唐诗/poet.tang.49000.json','["含嬌含笑，宿翠殘紅窈窕，鬢如蟬。", "寒玉簪秋水，輕紗卷碧煙。", "雪胸鸞鏡裏，琪樹鳳樓前。", "寄語青娥伴，早求仙。"]'),
('9d6d08c3-7cc8-4d52-ba70-7182b5e9a82b','女冠子 二','溫庭筠','唐','唐诗','tang','','[]','霞帔雲髮，鈿鏡仙容似雪，畫愁眉。',50,'全唐诗/poet.tang.49000.json','["霞帔雲髮，鈿鏡仙容似雪，畫愁眉。", "遮語回輕扇，含羞下繡幃。", "玉樓相望久，花洞恨來遲。", "早晚乘鸞去，莫相遺。"]'),
('1a0f1a5e-baa5-4627-aff1-6ffdac55ca26','歸國遙 一','溫庭筠','唐','唐诗','tang','','[]','香玉，翠鳳寶釵垂{罒/彔}𦌉，鈿筐交勝金粟，越羅春水綠。',54,'全唐诗/poet.tang.49000.json','["香玉，翠鳳寶釵垂{罒/彔}𦌉，鈿筐交勝金粟，越羅春水綠。", "畫堂照簾殘燭，夢餘更漏促。", "謝娘無限心曲，曉屏山斷續。"]'),
('0083a2d5-c7d0-4be7-a8c3-7c76ebbfe3fe','歸國遙 二','溫庭筠','唐','唐诗','tang','','[]','雙臉，小鳳戰箆金颭豔，舞衣無力風歛，藕絲秋色染。',50,'全唐诗/poet.tang.49000.json','["雙臉，小鳳戰箆金颭豔，舞衣無力風歛，藕絲秋色染。", "錦帳繡幃斜掩，露珠清曉簟。", "粉心黃蘂花靨，黛眉山兩點。"]'),
('20e442bb-ecba-4adc-94cd-67ab05096349','菩薩蠻 一','溫庭筠','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5a49\u7ea6", "\u5973\u5b50", "\u95fa\u6028", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','小山重疊金明滅，鬢雲欲度香顋雪。',52,'全唐诗/poet.tang.49000.json','["小山重疊金明滅，鬢雲欲度香顋雪。", "嬾起畫蛾眉，弄妝梳洗遲。", "照花前後鏡，花面交相映。", "新帖繡羅襦，雙雙金鷓鴣。"]'),
('9f1328cc-d58f-4320-a56a-1f8c2c2b07a4','菩薩蠻 二','溫庭筠','唐','唐诗','tang','','[]','水精簾裏頗黎枕，暖香惹夢鴛鴦錦。',52,'全唐诗/poet.tang.49000.json','["水精簾裏頗黎枕，暖香惹夢鴛鴦錦。", "江上柳如煙，鴈飛殘月天。", "藕絲秋色淺，人勝參差翦。", "雙鬢隔香紅，玉釵頭上風。"]'),
('3d653ca8-6648-457e-9174-9787265e7a12','菩薩蠻 三','溫庭筠','唐','唐诗','tang','','[]','蘂黃無限當山額，宿妝隱笑紗窗隔。',52,'全唐诗/poet.tang.49000.json','["蘂黃無限當山額，宿妝隱笑紗窗隔。", "相見牡丹時，暫來還別離。", "翠釵金作股，釵上蝶雙舞。", "心事竟誰知，月明花滿枝。"]'),
('94d5cd0f-ec65-45e1-83e2-eb316bb347c4','菩薩蠻 四','溫庭筠','唐','唐诗','tang','','[]','翠翹金縷雙鸂鶒，水文細起春池碧。',52,'全唐诗/poet.tang.49000.json','["翠翹金縷雙鸂鶒，水文細起春池碧。", "池上海棠梨，雨晴紅滿枝。", "繡衫遮笑靨，煙草黏飛蝶。", "青瑣對芳菲，玉關音信稀。"]'),
('2d3a1249-3b58-4360-996c-8c9408a8cb0e','菩薩蠻 五','溫庭筠','唐','唐诗','tang','','[]','杏花含露團香雪，綠楊陌上多離別。',52,'全唐诗/poet.tang.49000.json','["杏花含露團香雪，綠楊陌上多離別。", "燈在月朧明，覺來聞曉鸎。", "玉鉤褰翠幕，妝淺舊眉薄。", "春夢正關情，鏡中蟬鬢輕。"]'),
('e57f3096-5a69-444e-8454-517585ad99a4','菩薩蠻 六','溫庭筠','唐','唐诗','tang','','[]','玉樓明月長相憶，柳絲嫋娜春無力。',52,'全唐诗/poet.tang.49000.json','["玉樓明月長相憶，柳絲嫋娜春無力。", "門外草萋萋，送君聞馬嘶。", "畫羅金翡翠，香燭銷成淚。", "花落子規啼，綠窗殘夢迷。"]'),
('129d6ad5-e635-4562-9e39-615b639c1d71','菩薩蠻 七','溫庭筠','唐','唐诗','tang','','[]','鳳凰相對盤金縷，牡丹一夜經微雨。',52,'全唐诗/poet.tang.49000.json','["鳳凰相對盤金縷，牡丹一夜經微雨。", "明鏡照新妝，鬢輕雙臉長。", "畫樓相望久，闌外垂絲柳。", "音信不歸來，社前雙燕回。"]'),
('b0d6dc9e-67cb-4925-8136-7065816e7dd3','菩薩蠻 八','溫庭筠','唐','唐诗','tang','','[]','牡丹花謝鸎聲歇，綠楊滿院中庭月。',52,'全唐诗/poet.tang.49000.json','["牡丹花謝鸎聲歇，綠楊滿院中庭月。", "相憶夢難成，背窗燈半明。", "翠鈿金壓臉，寂寞香閨掩。", "人遠淚闌干，燕飛春又殘。"]'),
('aec61346-5b64-4770-9e3e-1a29ae2c80c1','菩薩蠻 九','溫庭筠','唐','唐诗','tang','','[]','滿宮明月梨花白，故人萬里關山隔。',52,'全唐诗/poet.tang.49000.json','["滿宮明月梨花白，故人萬里關山隔。", "金鴈一雙飛，淚痕霑繡衣。", "小園芳草綠，家住越溪曲。", "楊柳色依依，燕歸君不歸。"]'),
('a35ef9ce-aeb6-4e0e-914d-1aab3aebe6bb','菩薩蠻 十','溫庭筠','唐','唐诗','tang','','["\u79bb\u522b", "\u5973\u5b50", "\u76f8\u601d"]','寶函鈿雀金鸂鶒，沈香閣上吳山碧。',52,'全唐诗/poet.tang.49000.json','["寶函鈿雀金鸂鶒，沈香閣上吳山碧。", "楊柳又如絲，驛橋春雨時。", "畫樓音信斷，芳草江南岸。", "鸞鏡與花枝，此情誰得知。"]'),
('54967543-bf02-46b8-bd97-d49b6919ccc5','菩薩蠻 十一','溫庭筠','唐','唐诗','tang','','[]','南園滿地堆輕絮，愁聞一霎清明雨。',52,'全唐诗/poet.tang.49000.json','["南園滿地堆輕絮，愁聞一霎清明雨。", "雨後却斜陽，杏花零落香。", "無言勻睡臉，枕上屏山掩。", "時節欲黃昏，無憀獨倚門。"]'),
('a11c4a1d-0988-4501-b592-756fa6317cd8','菩薩蠻 十二','溫庭筠','唐','唐诗','tang','','[]','夜來皓月纔當午，重簾悄悄無人語。',52,'全唐诗/poet.tang.49000.json','["夜來皓月纔當午，重簾悄悄無人語。", "深處麝煙長，臥時留薄妝。", "當年還自惜，往事那堪憶。", "花露月明殘，錦衾知曉寒。"]'),
('c158c424-8616-486f-b519-a348a703b5a6','菩薩蠻 十三','溫庭筠','唐','唐诗','tang','','[]','雨晴夜合玲瓏日，萬枝香嫋紅絲拂。',56,'全唐诗/poet.tang.49000.json','["雨晴夜合玲瓏日，萬枝香嫋紅絲拂。", "閑夢憶金堂，滿庭萱草長。", "繡簾垂{罒/彔}𦌉，眉黛遠山綠。", "春水渡溪橋，凭闌魂欲消。"]'),
('1280cd85-731d-4ca7-8f5f-6d70b862a775','菩薩蠻 十四','溫庭筠','唐','唐诗','tang','','[]','竹風輕動庭除冷，珠簾月上玲瓏影。',52,'全唐诗/poet.tang.49000.json','["竹風輕動庭除冷，珠簾月上玲瓏影。", "山枕隱濃妝，綠檀金鳳凰。", "兩蛾愁黛淺，故國吳宮遠。", "春恨正關情，畫樓殘點聲。"]'),
('1346cd4b-1453-4020-93fe-99d397977198','菩薩蠻 十五','溫庭筠','唐','唐诗','tang','','[]','玉纖彈處真珠落，流多暗濕鉛華薄。',52,'全唐诗/poet.tang.49000.json','["玉纖彈處真珠落，流多暗濕鉛華薄。", "春露浥朝花，秋波浸晚霞。", "風流心上物，本爲風流出。", "看取薄情人，羅衣無此痕。"]'),
('97837150-d035-4bee-90a1-704fc2f1906f','清平樂 一','溫庭筠','唐','唐诗','tang','','[]','上陽春晚，宮女愁蛾淺。',54,'全唐诗/poet.tang.49000.json','["上陽春晚，宮女愁蛾淺。", "新歲清平思同輦，爭奈長安路遠。", "鳳帳鴛被徒熏，寂寞花瑣千門。", "競把黃金買賦，爲妾將上明君。"]'),
('692f8ff9-36e0-46d9-b47e-9ddbcebfd6a8','清平樂 二','溫庭筠','唐','唐诗','tang','','[]','洛陽愁絕，楊柳花飄雪。',54,'全唐诗/poet.tang.49000.json','["洛陽愁絕，楊柳花飄雪。", "終日行人爭攀折，橋下水流嗚咽。", "上馬爭勸離觴，南浦鸎聲斷腸。", "愁殺平原年少，回首揮淚千行。"]'),
('9b13c8eb-d23f-4587-a32f-45c6e8503c88','更漏子 一','溫庭筠','唐','唐诗','tang','','["\u5a49\u7ea6", "\u76f8\u601d", "\u5973\u5b50", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','柳絲長，春雨細，花外漏聲迢遞。',58,'全唐诗/poet.tang.49000.json','["柳絲長，春雨細，花外漏聲迢遞。", "驚塞鴈，起城烏，畫屏金鷓鴣。", "香霧薄，透簾幕，惆悵謝家池閣。", "紅燭背，繡簾垂，夢長君不知。"]'),
('4dfde7bc-49f5-4fbd-b0c2-c089c1575cec','更漏子 二','溫庭筠','唐','唐诗','tang','','[]','星斗稀，鐘鼓歇，簾外曉鸎殘月。',58,'全唐诗/poet.tang.49000.json','["星斗稀，鐘鼓歇，簾外曉鸎殘月。", "蘭露重，柳風斜，滿庭堆落花。", "虛閣上，倚闌望，還似去年惆悵。", "春欲暮，思無窮，舊歡如夢中。"]'),
('3e512119-eba8-4410-9cbf-e22eff3aef96','更漏子 三','溫庭筠','唐','唐诗','tang','','[]','金雀釵，紅粉面，花裏暫時相見。',58,'全唐诗/poet.tang.49000.json','["金雀釵，紅粉面，花裏暫時相見。", "知我意，感君憐，此情須問天。", "香作穗，蠟成淚，還似兩人心意。", "山枕膩，錦衾寒，覺來更漏殘。"]'),
('bd66a36e-6a76-4fc2-afef-fda908827990','更漏子 四','溫庭筠','唐','唐诗','tang','','[]','相見稀，相憶久，眉淺淡煙如柳。',58,'全唐诗/poet.tang.49000.json','["相見稀，相憶久，眉淺淡煙如柳。", "垂翠幕，結同心，待郎熏繡衾。", "城上月，白如雪，蟬鬢美人愁絕。", "宮樹暗，鵲橋橫，玉籤初報明。"]'),
('eb839cc2-8338-4352-8e8a-9bb2267aec34','更漏子 五','溫庭筠','唐','唐诗','tang','','[]','背江樓，臨海月，城上角聲嗚咽。',58,'全唐诗/poet.tang.49000.json','["背江樓，臨海月，城上角聲嗚咽。", "堤柳動，島煙昏，兩行征鴈分。", "京口路，歸帆渡，正是芳菲欲度。", "銀燭盡，玉繩低，一聲村落雞。"]'),
('238276c5-45e7-40f9-ad7c-dd1f1dbbc334','更漏子 六','溫庭筠','唐','唐诗','tang','','[]','玉爐香，紅蠟淚，偏照畫堂秋思。',58,'全唐诗/poet.tang.49000.json','["玉爐香，紅蠟淚，偏照畫堂秋思。", "眉翠薄，鬢雲殘，夜長衾枕寒。", "梧桐樹，三更雨，不道離情正苦。", "一葉葉，一聲聲，空階滴到明。"]'),
('1e69e38f-b892-4d36-9905-33fb2fe6c14e','河瀆神 一','溫庭筠','唐','唐诗','tang','','[]','河上望叢祠，廟前春雨來時。',57,'全唐诗/poet.tang.49000.json','["河上望叢祠，廟前春雨來時。", "楚山無限鳥飛遲，蘭櫂空傷別離。", "何處杜鵑啼不歇，豔紅開盡如血。", "蟬鬢美人愁絕，百花芳草佳節。"]'),
('58012e00-5719-457d-b52d-bf978ec22547','河瀆神 二','溫庭筠','唐','唐诗','tang','','[]','孤廟對寒潮，西陵風雨瀟瀟。',57,'全唐诗/poet.tang.49000.json','["孤廟對寒潮，西陵風雨瀟瀟。", "謝娘惆悵倚蘭橈，淚流玉筯千條。", "暮天愁聽思歸樂，早梅香滿山郭。", "回首兩情蕭索，離魂何處飄泊。"]'),
('6a8ae2f7-d5b9-4cc6-bb6e-be9c7b44a2ab','河瀆神 三','溫庭筠','唐','唐诗','tang','','[]','銅鼓賽神來，滿庭幡蓋裴回。',57,'全唐诗/poet.tang.49000.json','["銅鼓賽神來，滿庭幡蓋裴回。", "水村江浦過風雷，楚山如畫煙開。", "離別艣聲空蕭索，玉容惆悵妝薄。", "青麥燕飛落落，卷簾愁對珠閣。"]'),
('ba91117a-dd0e-4455-8975-99ef02e8b843','河傳 一','溫庭筠','唐','唐诗','tang','','[]','江畔，相喚。',69,'全唐诗/poet.tang.49000.json','["江畔，相喚。", "曉妝鮮，仙景箇女采蓮。", "請君莫向那岸邊，少年，好花新滿船。", "紅袖搖曳逐風輭，垂玉腕，腸向柳絲斷。", "浦南歸，浦北歸，莫知，晚來人已稀。"]'),
('59640eba-5492-4033-8a8c-86b1c43dc6da','河傳 二','溫庭筠','唐','唐诗','tang','','[]','湖上，閑望。',69,'全唐诗/poet.tang.49000.json','["湖上，閑望。", "雨蕭蕭，煙浦花橋路遙。", "謝娘翠蛾愁不銷，終朝，夢魂迷晚潮。", "蕩子天涯歸櫂遠，春已晚，鸎語空腸斷。", "若耶溪，溪水西，柳堤，不聞郎馬嘶。"]'),
('3b5c549d-af0b-4f05-9e78-763658c137e5','河傳 三','溫庭筠','唐','唐诗','tang','','[]','同伴，相喚。',69,'全唐诗/poet.tang.49000.json','["同伴，相喚。", "杏花稀，夢裏每愁依違。", "仙客一去燕已飛，不歸，淚痕空滿衣。", "天際雲鳥引情遠，春已晚，煙靄渡南苑。", "雪梅香，柳帶長，小娘，轉令人意傷。"]'),
('d0874544-8b86-4a63-bbf4-cfccf26114ab','木蘭花','溫庭筠','唐','唐诗','tang','','[]','家臨長信往來道，乳燕雙雙拂煙草。',64,'全唐诗/poet.tang.49000.json','["家臨長信往來道，乳燕雙雙拂煙草。", "油壁車輕金犢肥，流蘇帳曉春雞早。", "籠中嬌鳥暖猶睡，簾外落花閑不掃。", "衰桃一樹近前池，似惜容顏鏡中老。"]'),
('a1cdb255-eda0-45b8-8b59-5894c442174a','竹枝 一','皇甫松','唐','唐诗','tang','','[]','檳榔花發鷓鴣啼，雄飛煙瘴雌亦飛。',16,'全唐诗/poet.tang.49000.json','["檳榔花發鷓鴣啼，雄飛煙瘴雌亦飛。"]'),
('73c6fda5-4058-45ad-b06e-ff18a10b2ec6','竹枝 二','皇甫松','唐','唐诗','tang','','[]','木棉花盡荔支垂，千花萬花待郎歸。',16,'全唐诗/poet.tang.49000.json','["木棉花盡荔支垂，千花萬花待郎歸。"]'),
('ba8145c8-9eff-4780-9aa5-6e726c198f75','竹枝 三','皇甫松','唐','唐诗','tang','','[]','芙蓉竝蔕一心連，花侵槅子眼應穿。',16,'全唐诗/poet.tang.49000.json','["芙蓉竝蔕一心連，花侵槅子眼應穿。"]'),
('698d2590-f28a-4943-854e-390329352e7f','竹枝 四','皇甫松','唐','唐诗','tang','','[]','筵中蠟燭淚珠紅，合歡桃核兩人同。',16,'全唐诗/poet.tang.49000.json','["筵中蠟燭淚珠紅，合歡桃核兩人同。"]'),
('c6c142a7-3387-4665-92d9-b3630f385dbd','竹枝 五','皇甫松','唐','唐诗','tang','','[]','斜江風起動橫波，劈開蓮子苦心多。',16,'全唐诗/poet.tang.49000.json','["斜江風起動橫波，劈開蓮子苦心多。"]'),
('ed3f9d13-10e8-47cc-a74b-b9c109247630','竹枝 六','皇甫松','唐','唐诗','tang','','[]','山頭桃花谷底杏，兩花窈窕遙相映。',16,'全唐诗/poet.tang.49000.json','["山頭桃花谷底杏，兩花窈窕遙相映。"]'),
('ad0cd96c-0d2a-4e18-98cc-86b5f5cd0e9a','摘得新 一','皇甫松','唐','唐诗','tang','','[]','酌一巵，須教玉笛吹。',32,'全唐诗/poet.tang.49000.json','["酌一巵，須教玉笛吹。", "錦筵紅蠟燭，莫來遲。", "繁紅一夜經風雨，是空枝。"]'),
('60996354-2277-4a59-a0fd-cce8c675181f','摘得新 二','皇甫松','唐','唐诗','tang','','[]','摘得新，枝枝葉葉春。',32,'全唐诗/poet.tang.49000.json','["摘得新，枝枝葉葉春。", "管弦兼美酒，最關人。", "平生都得幾十度，展香茵。"]'),
('08fe7156-eb95-411d-809c-51d92c029aa3','采蓮子 一','皇甫松','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5973\u5b50", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','菡萏香連十頃陂，小姑貪戲采蓮遲。',32,'全唐诗/poet.tang.49000.json','["菡萏香連十頃陂，小姑貪戲采蓮遲。", "晚來弄水船頭濕，更脫紅裙裹鴨兒。"]'),
('d489d9db-9571-459d-aceb-8a912abb453c','采蓮子 二','皇甫松','唐','唐诗','tang','','["\u7231\u60c5", "\u5199\u666f", "\u6c5f\u5357", "\u79cb\u5929", "\u5a49\u7ea6"]','船動湖光灩灩秋，貪看年少信船流。',32,'全唐诗/poet.tang.49000.json','["船動湖光灩灩秋，貪看年少信船流。", "無端隔水拋蓮子，遙被人知半日羞。"]'),
('81f23259-5fc8-488a-9523-85f7759ba8df','拋毬樂 一','皇甫松','唐','唐诗','tang','','[]','紅撥一聲飄，輕裘墜越綃。',36,'全唐诗/poet.tang.49000.json','["紅撥一聲飄，輕裘墜越綃。", "帶翻金孔雀，香滿繡蜂腰。", "少少拋分數，花枝正索饒。"]'),
('8af29ea4-4586-4743-ac50-a1569721e712','拋毬樂 二','皇甫松','唐','唐诗','tang','','[]','金蹙花毬小，真珠繡帶垂。',36,'全唐诗/poet.tang.49000.json','["金蹙花毬小，真珠繡帶垂。", "幾回衝蠟燭，千度入香懷。", "上客終須醉，觥盂且亂排。"]'),
('8f659dbb-07e0-4ff0-bf9c-b53d5bde41fe','憶江南 一','皇甫松','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5a49\u7ea6", "\u5199\u666f", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','蘭燼落，屏上暗紅蕉。',32,'全唐诗/poet.tang.49000.json','["蘭燼落，屏上暗紅蕉。", "閑夢江南梅熟日，夜船吹笛雨瀟瀟，人語驛邊橋。"]'),
('c9a2319e-63d7-4f0d-8009-4f4e1e613015','憶江南 二','皇甫松','唐','唐诗','tang','','[]','樓上寢，殘月下簾旌。',32,'全唐诗/poet.tang.49000.json','["樓上寢，殘月下簾旌。", "夢見秣陵惆悵事，桃花柳絮滿江城，雙髻坐吹笙。"]'),
('b45591f0-1efa-41b4-98c1-4c24d16a2ecf','天仙子 一','皇甫松','唐','唐诗','tang','','[]','晴野鷺鷥飛一隻，水葓花發秋江碧。',40,'全唐诗/poet.tang.49000.json','["晴野鷺鷥飛一隻，水葓花發秋江碧。", "劉郎此日別天仙，登綺席，淚珠滴，十二晚峰青歷歷。"]'),
('505369c9-16c4-4d03-b3c5-e60564f3f9ce','天仙子 二','皇甫松','唐','唐诗','tang','','[]','躑躅花開紅照水，鷓鴣飛遶青山觜。',40,'全唐诗/poet.tang.49000.json','["躑躅花開紅照水，鷓鴣飛遶青山觜。", "行人經歲始歸來，千萬里，錯相倚，懊惱天仙應有以。"]'),
('cedfa8ac-6f74-4a8a-bedb-7d27bb702a38','怨回紇 一','皇甫松','唐','唐诗','tang','','[]','白首南朝女，愁聽異域歌。',48,'全唐诗/poet.tang.49000.json','["白首南朝女，愁聽異域歌。", "收兵頡利國，飲馬胡盧河。", "毳布腥膻久，穹廬歲月多。", "雕窠城上宿，吹笛淚滂沱。"]'),
('9b5cb663-1c54-4cd8-aa89-74de2c388491','怨回紇 二','皇甫松','唐','唐诗','tang','','[]','祖席駐征櫂，開帆候信潮。',48,'全唐诗/poet.tang.49000.json','["祖席駐征櫂，開帆候信潮。", "隔筵桃葉泣，吹管杏花飄。", "船去鷗飛閣，人歸塵上橋。", "別離惆悵淚，江路濕紅蕉。"]'),
('ed5a41e7-878b-4ca5-babb-5b575d05c643','酒泉子','司空圖','唐','唐诗','tang','','["\u60dc\u65f6", "\u53d9\u4e8b", "\u6292\u60c5", "\u82b1", "\u5199\u82b1", "\u5a49\u7ea6"]','買得杏花，十載歸來方始坼。',53,'全唐诗/poet.tang.49000.json','["買得杏花，十載歸來方始坼。", "假山西畔藥闌東，滿枝紅。", "旋開旋落旋成空，白髮多情人更惜。", "黃昏把酒祝東風，且從容。"]'),
('3f2af012-09a6-46db-b130-907df31e785b','生查子 一','韓偓','唐','唐诗','tang','','[]','侍女動妝匳，故故驚人睡。',24,'全唐诗/poet.tang.49000.json','["侍女動妝匳，故故驚人睡。", "那知本未眠，背面偷垂淚。"]'),
('ceb48c64-76c5-4f2d-b560-bc32e30394e1','生查子 二','韓偓','唐','唐诗','tang','','[]','嬾卸鳳凰釵，羞入鴛鴦被。',24,'全唐诗/poet.tang.49000.json','["嬾卸鳳凰釵，羞入鴛鴦被。", "時復見殘燈，和煙墜金穗。"]'),
('d69d25c6-8b19-466a-8b96-e349dbc99fb7','浣溪沙 一','韓偓','唐','唐诗','tang','','[]','攏鬢新收玉步搖，背燈初解繡裙腰，枕寒衾冷異香焦。',48,'全唐诗/poet.tang.49000.json','["攏鬢新收玉步搖，背燈初解繡裙腰，枕寒衾冷異香焦。", "深院不關春寂寂，落花和雨夜迢迢，恨情殘醉却無聊。"]'),
('27179e3f-b16b-4a28-98ca-7bdd076cecaf','浣溪沙 二','韓偓','唐','唐诗','tang','','["\u5199\u666f", "\u8377\u82b1", "\u5a49\u7ea6"]','宿醉離愁慢髻鬟，六銖衣薄惹輕寒，慵紅悶翠掩青鸞。',48,'全唐诗/poet.tang.49000.json','["宿醉離愁慢髻鬟，六銖衣薄惹輕寒，慵紅悶翠掩青鸞。", "羅韈況兼金菡萏，雪肌仍是玉琅玕，骨香腰細更沈檀。"]'),
('c4c7fb93-ea8c-4722-a737-0dbca1405089','浣溪沙','張曙','唐','唐诗','tang','','["\u5a49\u7ea6\u8bcd", "\u5a49\u7ea6", "\u5199\u666f", "\u76f8\u601d"]','枕障熏爐隔繡帷，二年終日苦相思，杏花明月始應知。',48,'全唐诗/poet.tang.49000.json','["枕障熏爐隔繡帷，二年終日苦相思，杏花明月始應知。", "天上人間何處去，舊歡新夢覺來時，黃昏微雨畫簾垂。"]'),
('0e3cdbdd-48b2-4716-a5e7-f2934bda41fe','卜算子慢','鍾輻','唐','唐诗','tang','','[]','桃花院落，煙重露寒，寂寞禁煙晴晝。',109,'全唐诗/poet.tang.49000.json','["桃花院落，煙重露寒，寂寞禁煙晴晝。", "風拂珠簾，還記去年時候，惜春心，不喜閑窗繡。", "倚屏山，和衣睡覺，醺醺暗消殘酒。", "獨倚危闌久，把玉筍偷彈，黛蛾輕鬬。", "一點相思，萬般自家甘受，抽金釵，欲買丹青手。", "寫別來，容顏寄與，使知人清瘦。"]'),
('29942425-f596-4d56-89b2-81637d2b2bb3','訴衷情 一','韋莊','唐','唐诗','tang','','[]','燭燼香殘簾半卷，夢初驚。',42,'全唐诗/poet.tang.49000.json','["燭燼香殘簾半卷，夢初驚。", "花欲謝，深夜，月籠明。", "何處按歌聲，輕輕。", "舞衣塵暗生，負春情。"]'),
('8f0d6c56-de58-4992-b48d-77d5917a5ceb','訴衷情 二','韋莊','唐','唐诗','tang','','[]','碧沼紅芳煙雨靜，倚蘭橈。',42,'全唐诗/poet.tang.49000.json','["碧沼紅芳煙雨靜，倚蘭橈。", "垂玉佩，交帶，嫋纖腰。", "鴛夢隔星橋，迢迢。", "越羅香暗銷，墜花翹。"]'),
('60a1bd30-5033-4c03-a8c8-4d91eec6b630','天仙子 一','韋莊','唐','唐诗','tang','','[]','悵望前回夢裏期，看花不語苦尋思。',40,'全唐诗/poet.tang.49000.json','["悵望前回夢裏期，看花不語苦尋思。", "露桃宮裏小腰肢。", "眉眼細，鬢雲垂，惟有多情宋玉知。"]'),
('648900d9-6999-4909-a943-9add2ad2bcac','天仙子 二','韋莊','唐','唐诗','tang','','[]','深夜歸來長酩酊，扶入流蘇猶未醒。',40,'全唐诗/poet.tang.49000.json','["深夜歸來長酩酊，扶入流蘇猶未醒。", "醺醺酒氣麝蘭和。", "驚睡覺，笑呵呵，長笑人生能幾何。"]'),
('e0a1ccbc-8cc5-4f3c-a024-8303e3ab0bc7','天仙子 三','韋莊','唐','唐诗','tang','','[]','蟾彩霜華夜不分，天外鴻聲枕上聞。',40,'全唐诗/poet.tang.49000.json','["蟾彩霜華夜不分，天外鴻聲枕上聞。", "繡衾香冷嬾重熏。", "人寂寂，葉紛紛，纔睡依前夢見君。"]'),
('aac76176-db3b-4990-89e6-8a3230869e0d','天仙子 四','韋莊','唐','唐诗','tang','','[]','夢覺雲屏依舊空，杜鵑聲咽隔簾櫳。',40,'全唐诗/poet.tang.49000.json','["夢覺雲屏依舊空，杜鵑聲咽隔簾櫳。", "玉郎薄倖去無蹤。", "一日日，恨重重，淚界蓮顋兩線紅。"]'),
('409e5539-3379-47f8-9a13-77300a699ae2','天仙子 五','韋莊','唐','唐诗','tang','','[]','金似衣裳玉似身，眼如秋水鬢如雲。',40,'全唐诗/poet.tang.49000.json','["金似衣裳玉似身，眼如秋水鬢如雲。", "霞帬月帔一羣羣。", "來洞口，望煙分，劉阮不歸春日曛。"]'),
('0c390026-5dde-4d21-80f0-dd5746be495c','江城子 一','韋莊','唐','唐诗','tang','','[]','恩重嬌多情易傷，漏更長，解鴛鴦。',43,'全唐诗/poet.tang.49000.json','["恩重嬌多情易傷，漏更長，解鴛鴦。", "朱脣未動，先覺口脂香。", "緩揭繡衾抽皓腕，移鳳枕，枕檀郎。"]'),
('0f52ad30-ca30-4833-a1b4-a5752441b6ed','江城子 二','韋莊','唐','唐诗','tang','','[]','髻鬟狼藉黛眉長，出蘭房，別檀郎。',43,'全唐诗/poet.tang.49000.json','["髻鬟狼藉黛眉長，出蘭房，別檀郎。", "角聲嗚咽，星斗漸微茫。", "露冷月殘人未起，留不住，淚千行。"]'),
('f287557f-c276-4aeb-bcd1-20533cab8bdb','定西番 一','韋莊','唐','唐诗','tang','','[]','挑盡金燈紅燼，人灼灼，漏遲遲，未眠時。',43,'全唐诗/poet.tang.49000.json','["挑盡金燈紅燼，人灼灼，漏遲遲，未眠時。", "斜倚銀屏無語，閑愁上翠眉。", "悶殺梧桐殘雨，滴相思。"]'),
('14f3ee46-1944-49a7-8ea7-9fd5d0534321','定西番 二','韋莊','唐','唐诗','tang','','[]','芳草叢生縷結，花豔豔，雨濛濛，曉庭中。',43,'全唐诗/poet.tang.49000.json','["芳草叢生縷結，花豔豔，雨濛濛，曉庭中。", "塞遠久無音問，愁銷鏡裏紅。", "紫燕黃鸝猶至，恨何窮。"]'),
('8e1d6b9c-aa84-4309-b105-2700ed07d9da','思帝鄉 一','韋莊','唐','唐诗','tang','','[]','雲髻墜，鳳釵垂。',41,'全唐诗/poet.tang.49000.json','["雲髻墜，鳳釵垂。", "髻墜釵垂無力，枕函欹。", "翡翠屏深月落，漏依依。", "說盡人間天上，兩心知。"]'),
('e995761d-3ea2-4f50-b1e6-62d2916b6244','思帝鄉 二','韋莊','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5a49\u7ea6", "\u6625\u6e38", "\u5199\u666f", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','春日遊，杏花吹滿頭。',42,'全唐诗/poet.tang.49000.json','["春日遊，杏花吹滿頭。", "陌上誰家年少，足風流。", "妾擬將身嫁與，一生休。", "縱被無情棄，不能羞。"]'),
('f04cc740-75db-467e-a766-ad7b18c13acb','上行杯 一','韋莊','唐','唐诗','tang','','[]','芳草灞陵春岸，柳煙深，滿樓弦管，一曲離聲腸寸斷。',50,'全唐诗/poet.tang.49000.json','["芳草灞陵春岸，柳煙深，滿樓弦管，一曲離聲腸寸斷。", "今日送君千萬，紅縷玉盤金鏤盞。", "須勸，珍重意，莫辭滿。"]'),
('f6271cce-f1d1-4d87-b001-ef3199659743','上行杯 二','韋莊','唐','唐诗','tang','','[]','白馬玉鞭金轡，少年郎，離別容易，迢遰去程千萬里。',50,'全唐诗/poet.tang.49000.json','["白馬玉鞭金轡，少年郎，離別容易，迢遰去程千萬里。", "惆悵異鄉雲水，滿酌一杯勸和淚。", "須愧，珍重意，莫辭醉。"]'),
('d7e043d8-a51c-4c01-8ad7-0a78cc51212f','酒泉子','韋莊','唐','唐诗','tang','','[]','月落星沈，樓上美人春睡。',51,'全唐诗/poet.tang.49000.json','["月落星沈，樓上美人春睡。", "綠雲欹，金枕膩，畫屏深。", "子規啼破相思夢，曙色東方纔動。", "柳煙輕，花露重，思難任。"]'),
('f8e58789-d4a7-4a8b-98a7-14c44b87f29e','女冠子 一','韋莊','唐','唐诗','tang','','["\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u79bb\u522b", "\u7231\u60c5", "\u76f8\u601d", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','四月十七，正是去年今日。',50,'全唐诗/poet.tang.49000.json','["四月十七，正是去年今日。", "別君時。", "忍淚佯低面，含羞半歛眉。", "不知魂已斷，空有夢相隨。", "除却天邊月，沒人知。"]'),
('df261b12-9ddf-42f6-b0b7-7f571ca32d43','女冠子 二','韋莊','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u7231\u60c5", "\u76f8\u601d", "\u79bb\u522b", "\u5a49\u7ea6", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','昨夜夜半，枕上分明夢見。',50,'全唐诗/poet.tang.49000.json','["昨夜夜半，枕上分明夢見。", "語多時。", "依舊桃花面，頻低柳葉眉。", "半羞還半喜，欲去又依依。", "覺來知是夢，不勝悲。"]'),
('5f9bf347-2367-4cbd-b762-2b008d540ead','浣溪沙 一','韋莊','唐','唐诗','tang','','["\u6625\u5929", "\u5973\u5b50", "\u5bd2\u98df\u8282", "\u6000\u5ff5"]','清曉妝成寒食天，柳毬斜嫋間花鈿，卷簾直出畫堂前。',48,'全唐诗/poet.tang.49000.json','["清曉妝成寒食天，柳毬斜嫋間花鈿，卷簾直出畫堂前。", "指點牡丹初綻朵，日高猶自凭朱闌，含嚬不語恨春殘。"]'),
('27d48bf9-2972-47a2-af8f-d5ecbdb6bb27','浣溪沙 二','韋莊','唐','唐诗','tang','','[]','欲上鞦韆四體慵，擬交人送又心忪，畫堂簾幕月明風。',48,'全唐诗/poet.tang.49000.json','["欲上鞦韆四體慵，擬交人送又心忪，畫堂簾幕月明風。", "此夜有情誰不極，隔牆梨雪又玲瓏，玉容憔悴惹微紅。"]'),
('6ccf5f82-bcb1-4419-810d-a62543d95d9a','浣溪沙 三','韋莊','唐','唐诗','tang','','[]','惆悵夢餘山月斜，孤燈照壁背紅紗，小樓高閣謝娘家。',48,'全唐诗/poet.tang.49000.json','["惆悵夢餘山月斜，孤燈照壁背紅紗，小樓高閣謝娘家。", "暗想玉容何所似，一枝春雪凍梅花，滿身香霧簇朝霞。"]'),
('e4c15d56-fee2-4bfc-bbe7-f1597c011a12','浣溪沙 四','韋莊','唐','唐诗','tang','','[]','綠樹藏鶯鶯正啼，柳絲斜拂白銅鞮，弄珠江上草萋萋。',48,'全唐诗/poet.tang.49000.json','["綠樹藏鶯鶯正啼，柳絲斜拂白銅鞮，弄珠江上草萋萋。", "日暮飲歸何處客，繡鞍驄馬一聲嘶，滿身蘭麝醉如泥。"]'),
('c09f0c10-d20a-4398-aded-2b26242c24b5','浣溪沙 五','韋莊','唐','唐诗','tang','','["\u79bb\u522b", "\u5a49\u7ea6", "\u76f8\u601d"]','夜夜相思更漏殘，傷心明月凭闌干，想君思我錦衾寒。',48,'全唐诗/poet.tang.49000.json','["夜夜相思更漏殘，傷心明月凭闌干，想君思我錦衾寒。", "咫尺畫堂深似海，憶來惟把舊書看，幾時攜手入長安。"]'),
('f470a0cf-9d73-4333-b964-0dd3d17b87fe','歸國遙 一','韋莊','唐','唐诗','tang','','[]','春欲暮，滿地落花紅帶雨。',51,'全唐诗/poet.tang.49000.json','["春欲暮，滿地落花紅帶雨。", "惆悵玉籠鸚鵡，單棲無伴侶。", "南望去程何許，問花花不語。", "早晚得同歸去，恨無雙翠羽。"]'),
('05f64de6-deea-407f-bc8d-d8aed979198b','歸國遙 二','韋莊','唐','唐诗','tang','','[]','金翡翠，爲我南飛傳我意。',51,'全唐诗/poet.tang.49000.json','["金翡翠，爲我南飛傳我意。", "罨畫橋邊春水，幾年花下醉。", "別後只知相愧，淚珠難遠寄。", "羅幕繡幃鴛被，舊歡如夢裏。"]'),
('04b24e8a-0e53-4fc1-971f-544a78678b7d','歸國遙 三','韋莊','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50", "\u6625\u5929", "\u5199\u666f", "\u79bb\u522b", "\u611f\u4f24"]','春欲晚，戲蝶遊蜂花爛熳。',51,'全唐诗/poet.tang.49000.json','["春欲晚，戲蝶遊蜂花爛熳。", "日落謝家池館，柳絲金縷斷。", "睡覺綠鬟風亂，畫屏雲雨散。", "閑倚博山長歎，淚流霑皓腕。"]'),
('945bf525-5f20-4196-b1ed-215bd81a8359','菩薩蠻 一','韋莊','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u79bb\u522b", "\u601d\u5f52", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','紅樓別夜堪惆悵，香燈半卷流蘇帳。',52,'全唐诗/poet.tang.49000.json','["紅樓別夜堪惆悵，香燈半卷流蘇帳。", "殘月出門時，美人和淚辭。", "琵琶金翠羽，弦上黃鶯語。", "勸我早歸家，綠窗人似花。"]'),
('9ebbdc32-a162-4a80-a574-0f5e3d760474','菩薩蠻 二','韋莊','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u6c5f\u5357", "\u5a49\u7ea6", "\u601d\u4e61", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','人人盡說江南好，遊人只合江南老。',52,'全唐诗/poet.tang.49000.json','["人人盡說江南好，遊人只合江南老。", "春水碧於天，畫船聽雨眠。", "壚邊人似月，皓腕凝雙雪。", "未老莫還鄉，還鄉須斷腸。"]'),
('e2bacaeb-1887-47d7-af57-7290792457e1','菩薩蠻 三','韋莊','唐','唐诗','tang','','[]','如今却憶江南樂，當時年少春衫薄。',52,'全唐诗/poet.tang.49000.json','["如今却憶江南樂，當時年少春衫薄。", "騎馬倚斜橋，滿樓紅袖招。", "翠屏金屈曲，醉入花叢宿。", "此度見花枝，白頭誓不歸。"]'),
('41ed887c-70da-4087-825a-17237e55d36e','菩薩蠻 四','韋莊','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u996e\u9152", "\u611f\u4f24", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','勸君今夜須沈醉，尊前莫話明朝事。',52,'全唐诗/poet.tang.49000.json','["勸君今夜須沈醉，尊前莫話明朝事。", "珍重主人心，酒深情亦深。", "須愁春漏短，莫訴金杯滿。", "遇酒且呵呵，人生能幾何。"]'),
('bf8c2e39-5d2a-44de-a03e-342d5dfde5bb','菩薩蠻 五','韋莊','唐','唐诗','tang','','["\u5e26\u6709\u5730\u540d", "\u5a49\u7ea6", "\u601d\u4e61", "\u5199\u666f", "\u5730\u540d"]','洛陽城裏春光好，洛陽才子他鄉老。',52,'全唐诗/poet.tang.49000.json','["洛陽城裏春光好，洛陽才子他鄉老。", "柳暗魏王堤，此時心轉迷。", "桃花春水淥，水上鴛鴦浴。", "凝恨對殘暉，憶君君不知。"]'),
('8c50941b-6279-4578-8856-a78d4979b186','更漏子','韋莊','唐','唐诗','tang','','[]','鐘鼓寒，樓閣暝，月照古桐金井。',58,'全唐诗/poet.tang.49000.json','["鐘鼓寒，樓閣暝，月照古桐金井。", "深院閉，小庭空，落花香露紅。", "煙柳重，春霧薄，燈背水窗高閣。", "閑倚戶，暗霑衣，待郎郎不歸。"]'),
('e37e4e0d-877d-4a64-942b-ff4a09b5f1dc','謁金門 一','韋莊','唐','唐诗','tang','','[]','春雨足，染就一溪新綠。',53,'全唐诗/poet.tang.49000.json','["春雨足，染就一溪新綠。", "柳外飛來雙羽玉，弄晴相對浴。", "樓外翠簾高軸，倚遍闌干幾曲。", "雲淡水平煙樹簇，寸心千里目。"]'),
('9dd0d319-9822-44f2-961e-48bb8b5ba9e0','謁金門 二','韋莊','唐','唐诗','tang','','[]','春漏促，金燼暗挑殘燭。',53,'全唐诗/poet.tang.49000.json','["春漏促，金燼暗挑殘燭。", "一夜簾前風撼竹，夢魂相斷續。", "有箇嬌饒如玉，夜夜繡屏孤宿。", "閑抱琵琶尋舊曲，遠山眉黛綠。"]'),
('a8bda54b-7a15-4aaa-9499-f6fa2bf05ad6','謁金門 三','韋莊','唐','唐诗','tang','','["\u6000\u4eba", "\u6292\u60c5"]','空相憶，無記得傳消息。',53,'全唐诗/poet.tang.49000.json','["空相憶，無記得傳消息。", "天上嫦娥人不識，寄書何處覓。", "新睡覺來無力，不忍把君書跡。", "滿院落花春寂寂，斷腸芳草碧。"]'),
('7e2402f5-f813-40e4-9f86-dbf38f616036','清平樂 一','韋莊','唐','唐诗','tang','','[]','春愁南陌，故國音書隔。',54,'全唐诗/poet.tang.49000.json','["春愁南陌，故國音書隔。", "細雨霏霏梨花白，燕拂畫簾金額。", "盡日相望王孫，塵滿衣上淚痕。", "誰向橋邊吹笛，駐馬西望銷魂。"]'),
('c076f044-0efb-4ae8-9a9a-3c47a5c15a35','清平樂 二','韋莊','唐','唐诗','tang','','["\u601d\u5ff5", "\u6000\u4eba", "\u5973\u5b50", "\u6101\u95f7"]','野花芳草，寂寞關山道。',54,'全唐诗/poet.tang.49000.json','["野花芳草，寂寞關山道。", "柳吐金絲鶯語早，惆悵香閨暗老。", "羅帶悔結同心，獨凭朱闌思深。", "夢覺半牀斜月，小窗風觸鳴琴。"]'),
('81b97e4e-af85-4bcd-a594-11e7f6a5c9a8','清平樂 三','韋莊','唐','唐诗','tang','','[]','何處遊女，蜀國多雲雨。',54,'全唐诗/poet.tang.49000.json','["何處遊女，蜀國多雲雨。", "雲解有情花解語，窣地繡羅金縷。", "妝成不整金鈿，含羞待月鞦韆。", "住在綠槐陰裏，門臨春水橋邊。"]'),
('2f2bcc99-5451-437b-bb0b-043bac45ffee','清平樂 四','韋莊','唐','唐诗','tang','','["\u5199\u4eba", "\u79bb\u522b", "\u6101\u7eea", "\u76f8\u601d", "\u5973\u5b50"]','鶯啼殘月，繡閣香燈滅。',54,'全唐诗/poet.tang.49000.json','["鶯啼殘月，繡閣香燈滅。", "門外馬嘶郎欲別，正是落花時節。", "妝成不畫蛾眉，含愁獨倚金扉。", "去路香塵莫掃，掃即郎去歸遲。"]'),
('f17969b6-0bc4-4f85-9748-9473a24611b4','清平樂 五','韋莊','唐','唐诗','tang','','[]','瑣窗春暮，滿地梨花雨。',54,'全唐诗/poet.tang.49000.json','["瑣窗春暮，滿地梨花雨。", "君不歸來情又去，紅淚散霑金縷。", "夢魂飛斷煙波，傷心不奈春何。", "空把金針獨坐，鴛鴦愁繡雙窠。"]'),
('2859d179-5e3c-4f0f-864a-e1fc4a0a50ea','清平樂 六','韋莊','唐','唐诗','tang','','[]','綠楊春雨，金線飄千縷。',54,'全唐诗/poet.tang.49000.json','["綠楊春雨，金線飄千縷。", "花拆香枝黃鸝語，玉勒雕鞍何處。", "碧窗望斷燕鴻，翠簾睡眼溟濛。", "寶瑟誰家彈罷，含悲斜倚屏風。"]'),
('576d3866-0cdd-47c3-b984-b4187626504d','喜遷鶯 一','韋莊','唐','唐诗','tang','','[]','人洶洶，鼓𪔜𪔜，襟袖五更風。',57,'全唐诗/poet.tang.49000.json','["人洶洶，鼓𪔜𪔜，襟袖五更風。", "大羅天上月朦朧，騎馬上虛空。", "香滿衣，雲滿路，鸞鳳遶身飛舞。", "霓旌絳節一羣羣，引見玉華君。"]'),
('ce339bc5-b84f-47ff-baf2-23547c59aee0','喜遷鶯 二','韋莊','唐','唐诗','tang','','["\u6292\u60c5", "\u5fc3\u60c5", "\u5fd7\u5411"]','街鼓動，禁城開，天上探人回。',57,'全唐诗/poet.tang.49000.json','["街鼓動，禁城開，天上探人回。", "鳳銜金牓出雲來，平地一聲雷。", "鶯已遷，龍已化，一夜滿城車馬。", "家家樓上簇神仙，爭看鶴沖天。"]'),
('c8771b7e-31ed-43e0-95b8-8de053a25b5c','應天長 一','韋莊','唐','唐诗','tang','','[]','綠槐陰裏黃鶯語，深院無人春晝午。',60,'全唐诗/poet.tang.49000.json','["綠槐陰裏黃鶯語，深院無人春晝午。", "畫簾垂，金鳳舞，寂寞繡屏香一炷。", "碧天雲，無定處。", "空有夢魂來去，夜夜綠窗風雨，斷腸君信否。"]'),
('ef64ed93-a515-4994-880e-8f40af963dc2','應天長 二','韋莊','唐','唐诗','tang','','["\u7231\u60c5", "\u76f8\u601d"]','別來半歲音書絕，一寸離腸千萬結。',60,'全唐诗/poet.tang.49000.json','["別來半歲音書絕，一寸離腸千萬結。", "難相見，易相別，又是玉樓花似雪。", "暗相思，無處說。", "惆悵夜來煙月，想得此時情切，淚霑紅袖黦。"]'),
('f53a2bf4-c829-44ba-8c81-8693863afda6','荷葉杯 一','韋莊','唐','唐诗','tang','','[]','絕代佳人難得，傾國，花下見無期。',60,'全唐诗/poet.tang.49000.json','["絕代佳人難得，傾國，花下見無期。", "一雙愁黛遠山眉，不忍更思惟。", "閑掩翠屏金鳳，殘夢，羅幕畫堂空。", "碧天無路信難通，惆悵舊房櫳。"]'),
('bd5fe2ff-1cf1-4fac-bfcd-43e84b648303','荷葉杯 二','韋莊','唐','唐诗','tang','','["\u7231\u60c5", "\u56de\u5fc6", "\u76f8\u601d"]','記得那年花下，深夜，初識謝娘時。',60,'全唐诗/poet.tang.49000.json','["記得那年花下，深夜，初識謝娘時。", "水堂西面畫簾垂，攜手暗相期。", "惆悵曉鶯殘月，相別，從此隔音塵。", "如今俱是異鄉人，相見更無因。"]'),
('a627e058-f359-400d-b882-1956d7553b52','河傳 一','韋莊','唐','唐诗','tang','','[]','何處，煙雨。',66,'全唐诗/poet.tang.49000.json','["何處，煙雨。", "隋堤春暮，柳色蔥蘢。", "畫橈金縷，翠旗高颭香風，水光融。", "青娥殿脚春妝媚，輕雲裏，綽約司花妓。", "江都宮闕，清淮月映迷樓，古今愁。"]'),
('5de4d457-4cd6-4892-b9b4-c174300d84fd','河傳 二','韋莊','唐','唐诗','tang','','[]','春晚，風暖。',66,'全唐诗/poet.tang.49000.json','["春晚，風暖。", "錦城花滿，狂殺遊人。", "玉鞭金勒尋勝，馳驟輕塵，惜良辰。", "翠蛾爭勸臨邛酒，纖纖手，拂面垂絲柳。", "歸時煙裏鐘鼓，正是黃昏，暗銷魂。"]'),
('72e9adc5-9268-4f69-a46e-6a5677f23b1e','河傳 三','韋莊','唐','唐诗','tang','','[]','錦浦，春女。',66,'全唐诗/poet.tang.49000.json','["錦浦，春女。", "繡衣金縷，霧薄雲輕。", "花深柳暗，時節正是清明，雨初晴。", "玉鞭魂斷煙霞路，鶯鶯語，一望巫山雨。", "香塵隱映，遙望翠檻紅樓，黛眉愁。"]'),
('f983e804-e0fb-4bfb-93c4-3aa96b99951a','怨王孫','韋莊','唐','唐诗','tang','','[]','錦里，蠶市。',66,'全唐诗/poet.tang.49000.json','["錦里，蠶市。", "滿街珠翠，千萬紅妝。", "玉蟬金雀，寶髻花簇鳴璫，繡衣長。", "日斜歸去人難見，青樓遠，隊隊行雲散。", "不知今夜，何處深鎖蘭房，隔仙鄉。"]'),
('43a3024c-bc2d-40ef-99ee-69c92029ff94','木蘭花','韋莊','唐','唐诗','tang','','["\u6000\u4eba", "\u5987\u5973", "\u95fa\u6028"]','獨上小樓春欲暮，愁望玉關芳草路。',48,'全唐诗/poet.tang.49000.json','["獨上小樓春欲暮，愁望玉關芳草路。", "消息斷，不逢人，却歛細眉歸繡戶。", "坐看落花空歎息，羅袂溼班紅淚滴。"]'),
('16f4e1bd-d34d-41bf-8ee8-18f9eb86abd0','小重山','韋莊','唐','唐诗','tang','','["\u5199\u4eba", "\u5bab\u5ef7", "\u60c6\u6005", "\u5199\u4eba\u8bd7"]','一閉昭陽春又春，夜寒宮漏永，夢君恩。',70,'全唐诗/poet.tang.49000.json','["一閉昭陽春又春，夜寒宮漏永，夢君恩。", "臥思陳事暗消魂，羅衣濕，紅袂有啼痕。", "歌吹隔重閽，遶庭芳草綠，倚長門。", "萬般惆悵向誰論，凝情立，宮殿欲黃昏。"]'),
('d6335c7b-0752-416f-b144-04bf07c94a7a','望遠行','韋莊','唐','唐诗','tang','','[]','欲別無言倚畫屏，含恨暗傷情。',71,'全唐诗/poet.tang.49000.json','["欲別無言倚畫屏，含恨暗傷情。", "謝家庭樹錦雞鳴，殘月落邊城。", "人欲別，馬頻嘶，綠槐千里長堤。", "出門芳草路萋萋，雲雨別來易東西。", "不忍別君後，却入舊香閨。"]'),
('83ae33fd-c0bf-435b-8aa7-40a68032c1bb','憶江南 一','牛嶠','唐','唐诗','tang','','["\u548f\u7269", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u6292\u6000", "\u5199\u9e1f", "\u548f\u7269\u8bd7"]','銜泥燕，飛到畫堂前。',32,'全唐诗/poet.tang.49000.json','["銜泥燕，飛到畫堂前。", "占得杏梁安穩處，體輕惟有主人憐，堪羨好因緣。"]'),
('d619d441-4db4-4b8b-bd04-2c0d25ca1f5d','憶江南 二','牛嶠','唐','唐诗','tang','','["\u5a49\u7ea6", "\u95fa\u6028"]','紅繡被，兩兩間鴛鴦。',32,'全唐诗/poet.tang.49000.json','["紅繡被，兩兩間鴛鴦。", "不是鳥中偏愛爾，爲緣交頸睡南塘，全勝薄情郎。"]'),
('10c6a4e6-090c-4e6f-91aa-5bf00c51e3d1','西溪子','牛嶠','唐','唐诗','tang','','[]','捍撥雙盤金鳳，蟬鬢玉釵搖動。',41,'全唐诗/poet.tang.49000.json','["捍撥雙盤金鳳，蟬鬢玉釵搖動。", "畫堂前，人不語，弦解語。", "彈到昭君怨處，翠蛾愁，不擡頭。"]'),
('928e25d3-5590-45f9-9438-6e43f6ad912e','江城子 一','牛嶠','唐','唐诗','tang','','[]','鵁鶄飛起郡城東，碧江空，半灘風。',43,'全唐诗/poet.tang.49000.json','["鵁鶄飛起郡城東，碧江空，半灘風。", "越王宮殿，蘋葉藕花中。", "簾卷水樓魚浪起，千片雪，雨濛濛。"]'),
('970288bc-72e8-4562-886f-742df1e9f7c1','江城子 二','牛嶠','唐','唐诗','tang','','[]','極浦煙消水鳥飛，離筵分手時，送金巵。',45,'全唐诗/poet.tang.49000.json','["極浦煙消水鳥飛，離筵分手時，送金巵。", "渡口楊花，狂雪任風吹。", "日暮空江波浪急，芳草岸，柳如絲。"]'),
('9b9ae734-4332-45a6-8597-09215dc98ea2','定西番','牛嶠','唐','唐诗','tang','','["\u6292\u60c5", "\u8fb9\u585e", "\u601d\u4e61"]','紫塞月明千里，金甲冷，戍樓寒，夢長安。',43,'全唐诗/poet.tang.49000.json','["紫塞月明千里，金甲冷，戍樓寒，夢長安。", "鄉思望中天闊，漏殘星亦殘。", "畫角數聲嗚咽，雪漫漫。"]'),
('58fd3c08-9571-47c0-bad1-78410254b711','望江怨','牛嶠','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u60c6\u6005", "\u5199\u666f"]','東風急，惜別花時手頻執。',42,'全唐诗/poet.tang.49000.json','["東風急，惜別花時手頻執。", "羅幃愁獨入，馬嘶殘雨春蕪溼。", "倚門立，寄語薄情郎，粉香和淚泣。"]'),
('cc496acd-cf60-425e-977a-6cd5890bc7bc','女冠子 一','牛嶠','唐','唐诗','tang','','[]','綠雲高髻，點翠勻紅時世。',50,'全唐诗/poet.tang.49000.json','["綠雲高髻，點翠勻紅時世。", "月如眉，淺笑含雙靨，低聲唱小詞。", "眼看惟恐化，魂蕩欲相隨。", "玉趾回嬌步，約佳期。"]'),
('c3e8a854-a2c6-4d14-8419-84833fefc300','女冠子 二','牛嶠','唐','唐诗','tang','','[]','錦江煙水，卓女燒春濃美。',50,'全唐诗/poet.tang.49000.json','["錦江煙水，卓女燒春濃美。", "小檀霞，繡帶芙蓉帳，金釵芍藥花。", "額黃侵膩髮，臂釧透紅紗。", "柳暗鶯啼處，認郎家。"]'),
('f8688116-8a79-4f55-b891-57e0a2ab539c','女冠子 三','牛嶠','唐','唐诗','tang','','[]','星冠霞帔，住在蘂珠宮裏。',53,'全唐诗/poet.tang.49000.json','["星冠霞帔，住在蘂珠宮裏。", "佩丁當，明翠搖蟬翼，纖珪理宿妝。", "醮壇春[草]晝綠，藥院杏花香。", "青鳥傳心事，寄劉郎。"]'),
('a8883ccb-4c65-4edf-b701-2f4475fff026','女冠子 四','牛嶠','唐','唐诗','tang','','[]','雙飛雙舞，春晝後園鶯語。',50,'全唐诗/poet.tang.49000.json','["雙飛雙舞，春晝後園鶯語。", "卷羅幃，錦字書封了，銀河雁過遲。", "鴛鴦排寶帳，豆蔻繡連枝。", "不語勻珠淚，落花時。"]'),
('8e8faa58-047a-41e4-b7ea-c7ffd5756dab','酒泉子','牛嶠','唐','唐诗','tang','','[]','記得去年，煙暖杏園花正發，雪飄香。',51,'全唐诗/poet.tang.49000.json','["記得去年，煙暖杏園花正發，雪飄香。", "江草綠，柳絲長。", "鈿車纖手卷簾望，眉學春山樣。", "鳳釵低嫋翠鬟上，落梅妝。"]'),
('ce8e3f43-0b34-4613-9bb7-cf85071a188b','菩薩蠻 一','牛嶠','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5", "\u5a49\u7ea6"]','舞帬香暖金泥鳳，畫梁語燕驚殘夢。',52,'全唐诗/poet.tang.49000.json','["舞帬香暖金泥鳳，畫梁語燕驚殘夢。", "門外柳花飛，玉郎猶未歸。", "愁勻紅粉淚，眉翦春山翠。", "何處是遼陽，錦屏春晝長。"]'),
('3ab37595-767b-4924-902f-5f962bbef068','菩薩蠻 二','牛嶠','唐','唐诗','tang','','[]','柳花飛處鶯聲急，晴街春色香車立。',52,'全唐诗/poet.tang.49000.json','["柳花飛處鶯聲急，晴街春色香車立。", "金鳳小簾開，臉波和恨來。", "今宵求夢想，難到青樓上。", "贏得一場愁，鴛衾誰竝頭。"]'),
('408bd8a3-b987-4b88-ba8b-27b7c55a8d39','菩薩蠻 三','牛嶠','唐','唐诗','tang','','[]','玉釵風動春幡急，交枝紅杏籠煙泣。',52,'全唐诗/poet.tang.49000.json','["玉釵風動春幡急，交枝紅杏籠煙泣。", "樓上望卿卿，窗寒新雨晴。", "熏爐蒙翠被，繡帳鴛鴦睡。", "何處有相知，羨他初畫眉。"]'),
('cd8c6f79-c324-446b-8fab-63a4a36b3eaa','菩薩蠻 四','牛嶠','唐','唐诗','tang','','[]','畫屏重疊巫陽翠，楚神尚有行雲意。',52,'全唐诗/poet.tang.49000.json','["畫屏重疊巫陽翠，楚神尚有行雲意。", "朝暮幾般心，向他情謾深。", "風流今古隔，虛作瞿塘客。", "山月照山花，夢回燈影斜。"]'),
('d1383a58-f130-4560-872f-16975ba2be0b','菩薩蠻 五','牛嶠','唐','唐诗','tang','','["\u5199\u4eba", "\u7231\u60c5"]','風簾燕舞鶯啼柳，妝臺約鬢低纖手。',52,'全唐诗/poet.tang.49000.json','["風簾燕舞鶯啼柳，妝臺約鬢低纖手。", "釵重髻盤珊，一枝紅牡丹。", "門前行樂客，白馬嘶春色。", "故故墜金鞭，回頭應眼穿。"]'),
('9736d5ab-5e6a-4145-b9f5-812346504b2b','菩薩蠻 六','牛嶠','唐','唐诗','tang','','[]','綠雲鬢上飛金雀，愁眉歛翠春煙薄。',52,'全唐诗/poet.tang.49000.json','["綠雲鬢上飛金雀，愁眉歛翠春煙薄。", "香閣掩芙蓉，畫屏山幾重。", "窗寒天欲曙，猶結同心苣。", "啼粉涴羅衣，問郎何日歸。"]'),
('ca98eb76-6e78-4be7-8c2a-f7aa5120807c','菩薩蠻 七','牛嶠','唐','唐诗','tang','','[]','玉爐冰簟鴛鴦錦，粉融香汗流山枕。',52,'全唐诗/poet.tang.49000.json','["玉爐冰簟鴛鴦錦，粉融香汗流山枕。", "簾外轆轤聲，歛眉含笑驚。", "柳陰煙漠漠，低鬢蟬釵落。", "須作一生拌，盡君今日歡。"]'),
('42537e91-a63a-4a7d-9a88-984ed29cebfe','更漏子 一','牛嶠','唐','唐诗','tang','','[]','星漸稀，漏頻轉，何處輪臺聲怨？',58,'全唐诗/poet.tang.49000.json','["星漸稀，漏頻轉，何處輪臺聲怨？", "香閣掩，杏花紅，月明楊柳風。", "挑錦字，記情事，惟願兩心相似。", "收淚語，背燈眠，玉釵橫枕邊。"]'),
('70e96b97-0ab9-4e42-9066-c09e9c22062b','更漏子 二','牛嶠','唐','唐诗','tang','','["\u6000\u4eba", "\u6625\u591c", "\u5973\u5b50", "\u5a49\u7ea6", "\u5a49\u7ea6\u8bcd"]','春夜闌，更漏促，金燼暗挑殘燭。',58,'全唐诗/poet.tang.49000.json','["春夜闌，更漏促，金燼暗挑殘燭。", "驚夢斷，錦屏深，兩鄉明月心。", "閨草碧，望歸客，還是不知消息。", "孤負我，悔憐君，告天天不聞。"]'),
('163ba0fa-887c-439b-99a0-fd0eb8b88a7b','更漏子 三','牛嶠','唐','唐诗','tang','','[]','南浦情，紅粉淚，爭奈兩人深意。',58,'全唐诗/poet.tang.49000.json','["南浦情，紅粉淚，爭奈兩人深意。", "低翠黛，卷征衣，馬嘶霜葉飛。", "招手別，寸腸結，還是去年時節。", "書託鴈，夢歸家，覺來江月斜。"]'),
('6542e176-1eda-46ad-b194-766687bf07a2','感恩多 一','牛嶠','唐','唐诗','tang','','[]','兩條紅粉淚，多少香閨意。',48,'全唐诗/poet.tang.49000.json','["兩條紅粉淚，多少香閨意。", "彊攀桃李枝，歛愁眉。", "陌上鶯啼蝶舞，柳花飛。", "柳花飛，願得郎心，憶家還早歸。"]'),
('a9baccb8-a483-4afe-b770-2afc73061001','感恩多 二','牛嶠','唐','唐诗','tang','','[]','自從南浦別，愁見丁香結。',49,'全唐诗/poet.tang.49000.json','["自從南浦別，愁見丁香結。", "近來情轉深，憶鴛衾。", "幾度將書託煙雁，淚盈襟。", "淚盈襟，禮月求天，願君知我心。"]'),
('28fe9c16-8842-4526-b672-5d2bc076f184','應天長 一','牛嶠','唐','唐诗','tang','','[]','玉樓春望晴煙滅，舞衫斜卷金條脫。',58,'全唐诗/poet.tang.49000.json','["玉樓春望晴煙滅，舞衫斜卷金條脫。", "黃鸝嬌轉聲初歇，杏花飄盡龍山雪。", "鳳釵低赴節，筵上王孫愁絕。", "鴛鴦對銜羅結，兩情深夜月。"]'),
('5077b7b5-aff5-4943-9c5d-54e2cfe7b04f','應天長 二','牛嶠','唐','唐诗','tang','','[]','雙眉澹薄藏心事，清夜背燈嬌又醉。',60,'全唐诗/poet.tang.49000.json','["雙眉澹薄藏心事，清夜背燈嬌又醉。", "玉釵橫，山枕膩，寶帳鴛鴦春睡美。", "別經時，無限意，虛道相思憔悴。", "莫信綵箋書裏，賺人腸斷字。"]'),
('7dc0e15b-99fb-4b43-9d68-748973e5b3cf','木蘭花','牛嶠','唐','唐诗','tang','','[]','春入橫塘搖淺浪，花落小園空惆悵。',64,'全唐诗/poet.tang.49000.json','["春入橫塘搖淺浪，花落小園空惆悵。", "此情誰信爲狂夫，恨翠愁紅流枕上。", "小玉窗前嗔燕語，紅淚滴穿金線縷。", "雁歸不見報郎歸，織成錦字封過與。"]'),
('14278baf-d668-4f66-bb4d-24fedb2cb0b3','西溪子','毛文錫','唐','唐诗','tang','','[]','昨夜西溪遊賞，芳樹奇花千樣。',43,'全唐诗/poet.tang.49000.json','["昨夜西溪遊賞，芳樹奇花千樣。", "鎖春光，金尊滿，聽弦管，嬌妓舞衫香暖。", "不覺到斜暉，馬馱歸。"]'),
('cf186ac2-650d-456c-9bb1-a36a20f856b0','何滿子','毛文錫','唐','唐诗','tang','','[]','紅粉樓前月照，碧紗窗外鶯啼。',42,'全唐诗/poet.tang.49000.json','["紅粉樓前月照，碧紗窗外鶯啼。", "夢斷遼陽音信，那堪獨守空閨。", "恨對百花時節，王孫綠草萋萋。"]'),
('e9062fca-80cc-4502-8c34-895e76254acc','訴衷情 一','毛文錫','唐','唐诗','tang','','[]','桃花流水漾縱橫，春晝彩霞明。',50,'全唐诗/poet.tang.49000.json','["桃花流水漾縱橫，春晝彩霞明。", "劉郎去，阮郎行，惆悵恨難平。", "愁坐對雲屏，筭歸程。", "何時攜手洞邊迎，訴衷情。"]'),
('fda6ff9e-3e61-4fb1-a7d5-4049df22cbb8','訴衷情 二','毛文錫','唐','唐诗','tang','','[]','鴛鴦交頸繡衣輕，碧沼藕花馨。',50,'全唐诗/poet.tang.49000.json','["鴛鴦交頸繡衣輕，碧沼藕花馨。", "偎藻荇，映蘭汀，和雨浴浮萍。", "思婦對心驚，想邊庭。", "何時解佩掩雲屏，訴衷情。"]'),
('3f6984d9-50a0-4932-be6f-de39922b55c7','中興樂','毛文錫','唐','唐诗','tang','','[]','豆蔻花繁煙豔深，丁香輭結同心。',51,'全唐诗/poet.tang.49000.json','["豆蔻花繁煙豔深，丁香輭結同心。", "翠鬟女，相與，共淘金。", "紅蕉葉裏猩猩語，鴛鴦浦。", "鏡中鸞舞，絲雨，隔荔枝陰。"]'),
('df5cc165-e84c-4264-be9f-0c448b52acbd','醉花間 一','毛文錫','唐','唐诗','tang','','["\u5b64\u72ec", "\u5199\u666f", "\u76f8\u601d", "\u5a49\u7ea6\u8bcd", "\u5973\u5b50", "\u5a49\u7ea6"]','休相問，怕相問，相問還添恨。',50,'全唐诗/poet.tang.49000.json','["休相問，怕相問，相問還添恨。", "春水滿塘生，鸂鶒還相趂。", "昨夜雨霏霏，臨明寒一陣。", "偏憶戍樓人，久絕邊庭信。"]'),
('9e33f186-98a8-4265-a778-5f7823b6a051','醉花間 二','毛文錫','唐','唐诗','tang','','[]','深相憶，莫相憶，相憶情難極。',50,'全唐诗/poet.tang.49000.json','["深相憶，莫相憶，相憶情難極。", "銀漢是紅牆，一帶遙相隔。", "金盤珠露滴，兩岸榆花白。", "風搖玉佩清，今夕爲何夕。"]'),
('20f53ecf-d518-4729-bd7b-85fd7c305b80','酒泉子','毛文錫','唐','唐诗','tang','','[]','綠樹春深，燕語鶯啼聲斷續，惠風飄蕩入芳叢，惹殘紅。',53,'全唐诗/poet.tang.49000.json','["綠樹春深，燕語鶯啼聲斷續，惠風飄蕩入芳叢，惹殘紅。", "柳絲無力嫋煙空，金盞不辭須滿酌，海棠花下思朦朧，醉春風。"]'),
('c62ce412-033e-4d02-985b-ada9f1d9d30d','紗窗恨 一','毛文錫','唐','唐诗','tang','','[]','新春燕子還來至，一雙飛。',50,'全唐诗/poet.tang.49000.json','["新春燕子還來至，一雙飛。", "壘巢泥溼時時墜，涴人衣。", "後園裏看百花發，香風拂，繡戶金扉。", "月照紗窗，恨依依。"]'),
('b46f1171-6084-4779-b5ac-b4ff94cb868f','紗窗恨 二','毛文錫','唐','唐诗','tang','','[]','雙雙蝶翅塗鉛粉，咂花心。',52,'全唐诗/poet.tang.49000.json','["雙雙蝶翅塗鉛粉，咂花心。", "綺窗繡戶飛來穩，畫堂陰。", "二三月，愛隨風絮，伴落花，來拂衣襟。", "更剪輕羅片，傅黃金。"]'),
('8da3b86d-fc0d-433a-92ef-3563755e008a','戀情深 一','毛文錫','唐','唐诗','tang','','[]','滴滴銅壺寒漏咽，醉紅樓月。',50,'全唐诗/poet.tang.49000.json','["滴滴銅壺寒漏咽，醉紅樓月。", "宴餘香殿會鴛衾，蕩春心。", "真珠簾下曉光侵，鶯語隔瓊林。", "寶帳欲開慵起，戀情深。"]'),
('26d55ba2-3ef9-43e6-a641-5833e9e36d25','戀情深 二','毛文錫','唐','唐诗','tang','','["\u5bb4\u996e", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','玉殿春濃花爛熳，簇神仙伴。',50,'全唐诗/poet.tang.49000.json','["玉殿春濃花爛熳，簇神仙伴。", "羅帬窣地縷黃金，奏清音。", "酒闌歌罷兩沈沈，一笑動君心。", "永願作鴛鴦伴，戀情深。"]'),
('2751a3d4-960b-441b-aab4-3ec968b7ab20','浣溪沙','毛文錫','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u5973\u5b50", "\u4e03\u5915\u8282"]','七夕年年信不違，銀河清淺白雲微，蟾光鵲影伯勞飛。',48,'全唐诗/poet.tang.49000.json','["七夕年年信不違，銀河清淺白雲微，蟾光鵲影伯勞飛。", "每恨蟪蛄憐婺女，幾回嬌妒下鴛機，今宵嘉會兩依依。"]'),
('34c36951-16be-4bc2-9561-21dec19872aa','攤破浣溪沙','毛文錫','唐','唐诗','tang','','[]','春水輕波浸綠苔，枇杷洲上紫檀開。',56,'全唐诗/poet.tang.49000.json','["春水輕波浸綠苔，枇杷洲上紫檀開。", "晴日眠沙鸂鶒穩，暖相偎。", "羅韈生塵遊女過，有人逢著弄珠回。", "蘭麝飄香初解佩，忘歸來。"]'),
('969947f5-257e-43e2-b9ff-e0809b414652','贊浦子','毛文錫','唐','唐诗','tang','','[]','錦帳添香睡，金爐換夕薰。',50,'全唐诗/poet.tang.49000.json','["錦帳添香睡，金爐換夕薰。", "嬾結芙蓉帶，慵拖翡翠帬。", "正是柳夭桃媚，那堪暮雨朝雲。", "宋玉高唐意，裁瓊欲贈君。"]'),
('fe97cb2b-f02f-4131-b12f-a2a645811cab','巫山一段雲 一','毛文錫','唐','唐诗','tang','','[]','雨霽巫山上，雲輕映碧天。',52,'全唐诗/poet.tang.49000.json','["雨霽巫山上，雲輕映碧天。", "遠風吹散又相連，十二晚峰前。", "暗濕啼猨樹，高籠過客船。", "朝朝暮暮楚江邊，幾度降神仙。"]'),
('94130927-4287-4310-b913-830f44ee9919','巫山一段雲 二','毛文錫','唐','唐诗','tang','','[]','貌掩巫山色，才過濯錦波。',52,'全唐诗/poet.tang.49000.json','["貌掩巫山色，才過濯錦波。", "阿誰提筆上銀河，月裏寫嫦娥。", "薄薄施鉛粉，盈盈挂綺羅。", "菖蒲花役夢魂多，年代屬元和。"]'),
('c7ecd0cd-2eed-4bf2-9d35-0b195786cf4d','柳含煙 一','毛文錫','唐','唐诗','tang','','["\u67f3\u6811", "\u8bbd\u523a"]','隋堤柳，汴河旁。',54,'全唐诗/poet.tang.49000.json','["隋堤柳，汴河旁。", "夾岸綠陰千里，龍舟鳳舸木蘭香。", "錦帆張。", "因夢江南春景好，一路流蘇羽葆。", "笙歌未盡起橫流，鎖春愁。"]'),
('bf4b0bfc-db3b-4414-86b5-5c6336dc6bfd','柳含煙 二','毛文錫','唐','唐诗','tang','','["\u79bb\u522b", "\u67f3\u6811"]','河橋柳，占芳春。',54,'全唐诗/poet.tang.49000.json','["河橋柳，占芳春。", "映水含煙拂路，幾回攀折贈行人。", "暗傷神。", "樂府吹爲橫笛曲，能使離腸斷續。", "不如移植在金門，近天恩。"]'),
('97e6cd60-58d6-4103-8e43-2983b9420e16','柳含煙 三','毛文錫','唐','唐诗','tang','','["\u67f3\u6811"]','章臺柳，近垂旒。',54,'全唐诗/poet.tang.49000.json','["章臺柳，近垂旒。", "低拂往來冠蓋，朦朧春色滿皇州。", "瑞煙浮。", "直與路邊江畔別，免被離人攀折。", "最憐京兆畫蛾眉，葉纖時。"]'),
('42ce5af4-ec0e-4aa8-b12c-105f59f30bb9','柳含煙 四','毛文錫','唐','唐诗','tang','','["\u67f3\u6811"]','御溝柳，占春多。',54,'全唐诗/poet.tang.49000.json','["御溝柳，占春多。", "半出宮牆婀娜，有時倒景醮輕羅。", "麴塵波。", "昨日金鑾巡上苑，風亞舞腰纖輭。", "栽培得地近皇宮，瑞煙濃。"]'),
('3fc7d738-46c7-4859-b6a9-ec689b4435ea','更漏子','毛文錫','唐','唐诗','tang','','[]','春夜闌，春恨切，花外子規啼月。',58,'全唐诗/poet.tang.49000.json','["春夜闌，春恨切，花外子規啼月。", "人不見，夢難憑，紅紗一點燈。", "偏怨別，是芳節，庭下丁香千結。", "宵霧散，曉霞暉，梁間雙燕飛。"]'),
('45ba5f8f-a727-4a3f-8d99-93b6b358f0c8','喜遷鶯','毛文錫','唐','唐诗','tang','','[]','芳春景，曖晴煙。',57,'全唐诗/poet.tang.49000.json','["芳春景，曖晴煙。", "喬木見鶯遷，傳枝偎葉語關關，飛過綺叢間。", "錦翼鮮，金毳輭。", "百轉千嬌相喚，碧紗窗曉怕聞聲，驚破鴛鴦暖。"]'),
('79301f14-2794-4905-aaae-f2197be7fa69','應天長','毛文錫','唐','唐诗','tang','','["\u79bb\u522b", "\u7231\u60c5"]','平江波暖鴛鴦語，兩兩釣船歸極浦。',58,'全唐诗/poet.tang.49000.json','["平江波暖鴛鴦語，兩兩釣船歸極浦。", "蘆洲一夜風和雨，飛起淺沙翹雪鷺。", "漁燈明遠渚，蘭櫂今宵何處。", "羅袂從風輕舉，愁殺采蓮女。"]'),
('79c0ac1e-aa0f-48ec-981f-47eca5978fc5','月宮春','毛文錫','唐','唐诗','tang','','[]','水晶宮裏桂花開，神仙探幾回。',57,'全唐诗/poet.tang.49000.json','["水晶宮裏桂花開，神仙探幾回。", "紅芳金蘂繡重臺，低傾瑪瑙杯。", "玉兔銀蟾爭守護，姮娥姹女戲相偎。", "遙聽鈞天九奏，玉皇親看來。"]'),
('901ead4c-b1c3-449c-913a-a238f97978fe','虞美人 一','毛文錫','唐','唐诗','tang','','[]','鴛鴦對浴銀塘暖，水面蒲梢短。',68,'全唐诗/poet.tang.49000.json','["鴛鴦對浴銀塘暖，水面蒲梢短。", "垂楊低拂麴塵波，蛛絲結網露珠多，滴圓荷。", "遙思桃葉吳江碧，便是天河隔。", "錦鱗紅鬣影沈沈，想思空有夢相尋，意難任。"]'),
('649ce5d7-4e66-4c97-9679-ceafd5eda125','虞美人 二','毛文錫','唐','唐诗','tang','','[]','寶檀金縷鴛鴦枕，綬帶盤宮錦。',68,'全唐诗/poet.tang.49000.json','["寶檀金縷鴛鴦枕，綬帶盤宮錦。", "夕陽低映小窗明，南園綠樹語鶯鶯，夢難成。", "玉爐香煖頻添炷，滿地飄輕絮。", "珠簾不卷度沈煙，庭前閑立畫鞦韆，豔陽天。"]'),
('f263c2d1-2f56-49da-825a-2c9d6e4c52b6','臨江仙','毛文錫','唐','唐诗','tang','','[]','暮蟬聲盡落斜陽，銀蟾影挂瀟湘。',68,'全唐诗/poet.tang.49000.json','["暮蟬聲盡落斜陽，銀蟾影挂瀟湘。", "黃陵廟側水茫茫，楚山紅樹，煙雨隔高唐。", "岸泊漁燈風颭碎，白蘋遠散濃香。", "靈娥鼓瑟韻清商，朱弦淒切，雲散碧天長。"]'),
('512921f2-22f5-4d35-ba7e-7844b6036b7b','接賢賓','毛文錫','唐','唐诗','tang','','[]','香韉鏤襜五色驄，值春景初融。',70,'全唐诗/poet.tang.49000.json','["香韉鏤襜五色驄，值春景初融。", "流珠噴沫躞蹀，汗血流紅。", "少年公子能乘馭，金鑣玉轡瓏璁。", "爲惜珊瑚鞭不下，驕生百步千蹤。", "信穿花，從拂柳，向九陌追風。"]'),
('e5c48f52-f0fc-4481-9e89-a924da744f4b','贊成功','毛文錫','唐','唐诗','tang','','[]','海棠未坼，萬點深紅，香包緘結一重重。',76,'全唐诗/poet.tang.49000.json','["海棠未坼，萬點深紅，香包緘結一重重。", "似含羞態，邀勒春風，蜂來蝶去，任遶芳叢。", "昨夜微雨，飄灑庭中，忽聞聲滴井邊桐。", "美人驚起，坐聽晨鐘，快教折取，戴玉瓏璁。"]'),
('9d8c7eeb-c699-42a1-9ca3-b33d199727da','甘州遍 一','毛文錫','唐','唐诗','tang','','[]','春光好，公子愛閑遊，足風流。',78,'全唐诗/poet.tang.49000.json','["春光好，公子愛閑遊，足風流。", "金鞍白馬，雕弓寶劒，紅纓錦襜出長楸。", "花蔽膝，玉銜頭。", "尋芳逐勝歡宴，絲竹不曾休。", "美人唱，揭調是甘州。", "醉紅樓，堯年舜日，樂聖永無憂。"]'),
('284c4514-9fdc-4384-8fe7-7bab47101ae1','甘州遍 二','毛文錫','唐','唐诗','tang','','[]','秋風緊，平磧雁行低，陣雲齊。',78,'全唐诗/poet.tang.49000.json','["秋風緊，平磧雁行低，陣雲齊。", "蕭蕭颯颯，邊聲四起，愁聞戍角與征鼙。", "青塚北，黑山西。", "沙飛聚散無定，往往路人迷。", "鐵衣冷，戰馬血霑蹄。", "破蕃奚，鳳皇詔下，步步躡丹梯。"]'),
('a76b4d1f-ef7f-4292-9618-7524558e218f','漁父','和凝','唐','唐诗','tang','','[]','白芷汀寒立鷺鷥，蘋風輕翦浪花時。',32,'全唐诗/poet.tang.49000.json','["白芷汀寒立鷺鷥，蘋風輕翦浪花時。", "煙冪冪，日遲遲，香引芙蓉惹釣絲。"]'),
('8dff7809-ba84-4a19-aec5-09732afa609e','天仙子 一','和凝','唐','唐诗','tang','','["\u5199\u4eba", "\u795e\u8bdd", "\u5199\u4eba\u8bd7"]','柳色披衫金縷鳳，纖手輕拈紅豆弄。',40,'全唐诗/poet.tang.49000.json','["柳色披衫金縷鳳，纖手輕拈紅豆弄。", "翠蛾雙斂正含情，桃花洞，瑤臺夢，一片春愁誰與共。"]'),
('4a2b41e5-416e-4f61-8643-73d38785b06e','天仙子 二','和凝','唐','唐诗','tang','','[]','洞口春紅飛䔩䔩，仙子含愁眉黛綠。',40,'全唐诗/poet.tang.49000.json','["洞口春紅飛䔩䔩，仙子含愁眉黛綠。", "阮郎何事不歸來，嬾燒金，慵篆玉，流水桃花空斷續。"]'),
('b6929f5f-002f-4ef5-83e8-541abd39c916','江城子 一','和凝','唐','唐诗','tang','','["\u7231\u60c5"]','初夜含嬌入洞房，理殘妝，柳眉長。',43,'全唐诗/poet.tang.49000.json','["初夜含嬌入洞房，理殘妝，柳眉長。", "翡翠屏中，親爇玉爐香。", "整頓金鈿呼小玉，排紅燭，待潘郎。"]'),
('43378641-1a09-4f04-a37a-68d0970b9be7','江城子 二','和凝','唐','唐诗','tang','','["\u7231\u60c5", "\u5973\u5b50"]','竹裏風生月上門，理秦箏，對雲屏。',43,'全唐诗/poet.tang.49000.json','["竹裏風生月上門，理秦箏，對雲屏。", "輕撥朱弦，恐亂馬嘶聲。", "含恨含嬌獨自語，今夜約，太遲生。"]'),
('624ca79b-6004-4e4d-b70a-771d4e6acc72','江城子 三','和凝','唐','唐诗','tang','','["\u7231\u60c5", "\u5973\u5b50"]','斗轉星移玉漏頻，已三更，對棲鶯。',43,'全唐诗/poet.tang.49000.json','["斗轉星移玉漏頻，已三更，對棲鶯。", "歷歷花間，似有馬蹄聲。", "含笑整衣開繡戶，斜斂手，下階迎。"]'),
('bd00244e-0599-4466-af79-adff05968464','江城子 四','和凝','唐','唐诗','tang','','["\u7231\u60c5", "\u5973\u5b50"]','迎得郎來入繡闈，語相思，連理枝。',43,'全唐诗/poet.tang.49000.json','["迎得郎來入繡闈，語相思，連理枝。", "鬢亂釵垂，梳墮印山眉。", "婭姹含情嬌不語，纖玉手，撫郎衣。"]'),
('62e05466-f3a4-4c8d-9e86-2e3dedc34e48','江城子 五','和凝','唐','唐诗','tang','','["\u79bb\u522b", "\u7231\u60c5", "\u5973\u5b50"]','帳裏鴛鴦交頸情，恨雞聲，天已明。',43,'全唐诗/poet.tang.49000.json','["帳裏鴛鴦交頸情，恨雞聲，天已明。", "愁見街前，還是說歸程。", "臨上馬時期後會，待梅綻，月初生。"]'),
('2d70ffe5-4958-4c6e-a650-8e713d28bfcd','何滿子 一','和凝','唐','唐诗','tang','','["\u5a49\u7ea6", "\u5199\u4eba", "\u7231\u6155", "\u5973\u5b50", "\u5199\u4eba\u8bd7"]','正是破瓜年幾，含情慣得人饒。',43,'全唐诗/poet.tang.49000.json','["正是破瓜年幾，含情慣得人饒。", "桃李精神鸚鵡舌，可堪虛度良宵。", "却愛藍羅帬子，羨他長束纖腰。"]'),
('92caaad4-0f16-4570-8c22-20f88c26f75a','何滿子 二','和凝','唐','唐诗','tang','','[]','寫得魚牋無限，其如花鎖春暉。',42,'全唐诗/poet.tang.49000.json','["寫得魚牋無限，其如花鎖春暉。", "目斷巫山雲雨，空教殘夢依依。", "却愛熏香小鴨，羨他長在屏帷。"]'),
('ab08b410-e465-4000-b0d3-125df9cee911','望梅花','和凝','唐','唐诗','tang','','[]','春草全無消息，臘雪猶餘蹤跡。',44,'全唐诗/poet.tang.49000.json','["春草全無消息，臘雪猶餘蹤跡。", "越嶺寒枝香自折，冷豔奇芳堪惜。", "何事壽陽無處覓，吹入誰家橫笛。"]'),
('eea06d1f-a4b1-493f-a3b2-94fd24308883','薄命女','和凝','唐','唐诗','tang','','[]','天欲曉，宮漏穿花聲繚繞。',46,'全唐诗/poet.tang.49000.json','["天欲曉，宮漏穿花聲繚繞。", "窗裏星光少。", "冷露寒侵帳額，殘月光沈樹杪。", "夢斷錦帷空悄悄，彊起愁眉小。"]'),
('84e8ed71-3da9-4874-bfce-c1744891a7bf','春光好 一','和凝','唐','唐诗','tang','','[]','紗窗暖，畫屏閑，嚲雲鬟。',51,'全唐诗/poet.tang.49000.json','["紗窗暖，畫屏閑，嚲雲鬟。", "睡起四肢無力，半春[間]。", "玉指翦裁羅勝，金盤點綴酥山。", "窺宋深心無限事，小眉彎。"]'),
('ee21d5e4-ed5b-40b3-91e5-357a82ac0e8b','春光好 二','和凝','唐','唐诗','tang','','[]','蘋葉輭，杏花明，畫船輕。',50,'全唐诗/poet.tang.49000.json','["蘋葉輭，杏花明，畫船輕。", "雙浴鴛鴦出綠汀，櫂歌聲。", "春水無風無浪，春天半雨半晴。", "紅粉相隨南浦晚，幾含情。"]'),
('e5ed0458-7ef4-43e8-8a71-18b0467e5e3c','采桑子','和凝','唐','唐诗','tang','','[]','蝤蠐領上訶梨子，繡帶雙垂。',52,'全唐诗/poet.tang.49000.json','["蝤蠐領上訶梨子，繡帶雙垂。", "椒戶閑時，競學摴蒲賭荔支。", "叢頭鞋子紅編細，帬窣金絲。", "無事嚬眉，春思翻教阿母疑。"]'),
('bdda441f-5b0d-4c10-ac51-47c64c5dd054','菩薩蠻','和凝','唐','唐诗','tang','','["\u6885\u82b1", "\u76f8\u601d"]','越梅半拆輕寒裏，冰清澹薄籠藍水。',52,'全唐诗/poet.tang.49000.json','["越梅半拆輕寒裏，冰清澹薄籠藍水。", "暖覺杏梢紅，遊絲狂惹風。", "閑階莎徑碧，遠夢猶堪惜。", "離恨又迎春，相思難重陳。"]'),
('6e962606-ad47-4a2e-9add-4ab9fa17ccc6','喜遷鶯','和凝','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u5a49\u7ea6"]','曉月墜，宿雲披，銀燭錦屏帷。',57,'全唐诗/poet.tang.49000.json','["曉月墜，宿雲披，銀燭錦屏帷。", "建章鐘動玉繩低，宮漏出花遲。", "春態淺，來雙燕，紅日漸長一線。", "嚴妝欲罷轉黃鸝，飛上萬年枝。"]'),
('68375bc2-e60f-4100-a9a6-8f6821db9166','山花子 一','和凝','唐','唐诗','tang','','[]','鶯錦蟬縠馥麝臍，輕裾花草曉煙迷。',56,'全唐诗/poet.tang.49000.json','["鶯錦蟬縠馥麝臍，輕裾花草曉煙迷。", "鸂鶒戰金紅掌墜，翠雲低。", "星靨笑偎霞臉畔，蹙金開襜襯銀泥。", "春思半和芳草嫩，碧萋萋。"]'),
('c9a9c780-c60a-437b-a389-ad20caa5bbf6','山花子 二','和凝','唐','唐诗','tang','','[]','銀字笙寒調正長，水文簟冷畫屏涼。',56,'全唐诗/poet.tang.49000.json','["銀字笙寒調正長，水文簟冷畫屏涼。", "玉腕重，金扼臂，淡梳妝。", "幾度試香纖手暖，一回嘗酒絳脣光。", "佯弄紅絲繩拂子，打檀郎。"]'),
('a28e6364-2ce9-49ff-83a8-32d9b8a91a18','臨江仙 一','和凝','唐','唐诗','tang','','[]','海棠香老春江晚，小樓霧縠空濛。',62,'全唐诗/poet.tang.49000.json','["海棠香老春江晚，小樓霧縠空濛。", "翠鬟初出繡簾中，麝煙鸞佩惹蘋風。", "碾玉釵搖鸂鶒戰，雪肌雲鬢將融。", "含情遙指碧波東，越王臺殿蓼花紅。"]'),
('d49c5ec6-48dc-4cca-a3c0-9f8258f70730','臨江仙 二','和凝','唐','唐诗','tang','','[]','披袍窣地紅宮錦，鶯語時轉輕音。',62,'全唐诗/poet.tang.49000.json','["披袍窣地紅宮錦，鶯語時轉輕音。", "碧羅冠子穩犀簪，鳳凰雙颭步搖金。", "肌骨細勻紅玉輭，臉波微送春心。", "嬌羞不肯入鴛衾，蘭膏光裏兩情深。"]'),
('52995028-b821-402a-adaf-8b1b3ce1ef94','小重山 一','和凝','唐','唐诗','tang','','[]','春入神京萬木芳，禁林鶯語滑，蝶飛狂。',70,'全唐诗/poet.tang.49000.json','["春入神京萬木芳，禁林鶯語滑，蝶飛狂。", "曉花擎露妒啼妝，紅日永，風和百花香。", "煙鎖柳絲長，御溝澄碧水，轉池塘。", "時時微雨洗風光，天衢遠，到處引笙篁。"]'),
('a02d6854-dca7-416b-af5d-ddd4630a2883','小重山 二','和凝','唐','唐诗','tang','','[]','正是神京爛熳時，羣仙初折得，郄詵枝。',70,'全唐诗/poet.tang.49000.json','["正是神京爛熳時，羣仙初折得，郄詵枝。", "烏犀白紵最相宜，精神出，御陌袖鞭垂。", "柳色展愁眉，管弦分響亮，探花期。", "光陰占斷曲江池，新牓上，名姓徹丹墀。"]'),
('1c341415-124a-473a-bf08-6e4e871db200','麥秀兩岐','和凝','唐','唐诗','tang','','[]','涼簟鋪斑竹，鴛枕竝紅玉。',78,'全唐诗/poet.tang.49000.json','["涼簟鋪斑竹，鴛枕竝紅玉。", "臉蓮紅，眉柳綠。", "胸雪宜新浴，淡黃衫子裁春縠，異香芬馥。", "羞道交回燭，未慣雙雙宿。", "樹連枝，魚比目。", "掌上腰如束，嬌嬈不爭人拳跼，黛眉微蹙。"]'),
('e8d90016-b70a-4791-81b0-2b6528d52cb9','生查子 一','牛希濟','唐','唐诗','tang','','["\u79bb\u522b", "\u601d\u5ff5", "\u5199\u666f", "\u5a49\u7ea6"]','春山煙欲收，天澹星稀小。',50,'全唐诗/poet.tang.49000.json','["春山煙欲收，天澹星稀小。", "殘月臉邊明，別淚臨清曉。", "語已多，情未了，回首猶重道。", "記得綠羅帬，處處憐芳草。"]'),
('e23e028c-9a1b-4fcc-9c3f-fa806f7e87f3','生查子 二','牛希濟','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e50\u5e9c", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u6708\u4eae", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u7231\u60c5"]','新月曲如眉，未有團圞意。',48,'全唐诗/poet.tang.49000.json','["新月曲如眉，未有團圞意。", "紅豆不堪看，滿眼相思淚。", "終日劈桃穰，人在心兒裏。", "兩朵隔牆花，早晚成連理。"]'),
('b9e5a6da-df41-48d4-9225-2c3720f15181','中興樂','牛希濟','唐','唐诗','tang','','[]','池塘暖碧浸晴暉，濛濛柳絮輕飛。',51,'全唐诗/poet.tang.49000.json','["池塘暖碧浸晴暉，濛濛柳絮輕飛。", "紅蘂凋來，醉夢還稀。", "春雲空有雁歸，珠簾垂。", "東風寂寞，恨郎拋擲，淚濕羅衣。"]'),
('e31ea600-61d9-48b9-9b23-d1b3b0bf5447','酒泉子','牛希濟','唐','唐诗','tang','','[]','枕轉簟涼，清曉遠鐘殘夢。',50,'全唐诗/poet.tang.49000.json','["枕轉簟涼，清曉遠鐘殘夢。", "月光斜，簾影動，舊爐香。", "夢中說盡相思事，纖手勻雙淚。", "去年書，今日意，斷人腸。"]'),
('594587c3-2101-43ef-baa4-9e9e048fbb11','謁金門','牛希濟','唐','唐诗','tang','','["\u6000\u4eba", "\u79cb\u5929", "\u53d9\u68a6"]','秋已暮，重疊關山岐路。',53,'全唐诗/poet.tang.49000.json','["秋已暮，重疊關山岐路。", "嘶馬搖鞭何處去，曉禽霜滿樹。", "夢斷禁城鐘鼓，淚滴枕檀無數。", "一點凝紅和薄霧，翠蛾愁不語。"]'),
('13589363-8328-469b-a799-ba5250baf1f1','臨江仙 一','牛希濟','唐','唐诗','tang','','["\u5a49\u7ea6\u8bcd", "\u548f\u53e4", "\u6292\u6000", "\u5a49\u7ea6"]','峭碧參差十二峰，冷煙寒樹重重。',68,'全唐诗/poet.tang.49000.json','["峭碧參差十二峰，冷煙寒樹重重。", "瑤姬宮殿是仙蹤。", "金爐珠帳，香靄晝偏濃。", "一自楚王驚夢斷，人間無路相逢。", "至今雲雨帶愁容。", "月斜江上，征櫂動晨鐘。"]'),
('2b76cf17-b038-455e-a931-bd668fef471f','臨江仙 二','牛希濟','唐','唐诗','tang','','[]','謝家仙觀寄雲岑，嵒蘿拂地成陰。',57,'全唐诗/poet.tang.49000.json','["謝家仙觀寄雲岑，嵒蘿拂地成陰。", "洞房不閉白雲深。", "當時丹竈，一粒化黃金。", "石壁霞衣猶半挂，松風長似鳴琴。", "時聞唳鶴起前林。"]'),
('1267ce90-a270-493f-9b56-a6a340b935a8','臨江仙 三','牛希濟','唐','唐诗','tang','','[]','渭闕宮城秦樹凋，玉樓獨上無憀。',68,'全唐诗/poet.tang.49000.json','["渭闕宮城秦樹凋，玉樓獨上無憀。", "含情不語自吹簫。", "調清和恨，天路逐風飄。", "何事乘龍人忽降，似知深意相招。", "三清攜手路非遙。", "世間屏障，彩筆畫嬌饒。"]'),
('421ca5c8-1abc-461b-b01a-fe0d06cef23b','臨江仙 四','牛希濟','唐','唐诗','tang','','[]','江繞黃陵春廟閑，嬌鶯獨語關關。',68,'全唐诗/poet.tang.49000.json','["江繞黃陵春廟閑，嬌鶯獨語關關。", "滿庭重疊綠苔斑。", "陰雲無事，四散自歸山。", "簫鼓聲稀香燼冷，月娥斂盡彎環。", "風流皆道勝人間。", "須知狂客，判死爲紅顏。"]'),
('67e14c79-031e-4199-a2ac-6b5956cf2bfc','臨江仙 五','牛希濟','唐','唐诗','tang','','[]','素洛春光瀲灩平，千重媚臉初生。',68,'全唐诗/poet.tang.49000.json','["素洛春光瀲灩平，千重媚臉初生。", "凌波羅韈勢輕輕。", "煙籠日照，珠翠半分明。", "風引寶衣疑欲舞，鸞回鳳翥堪驚。", "也知心許恐無成。", "陳王辭賦，千載有聲名。"]'),
('e404a94c-8a33-4c12-84a9-caded0197d9b','臨江仙 六','牛希濟','唐','唐诗','tang','','["\u5199\u4eba", "\u795e\u8bdd", "\u5199\u4eba\u8bd7"]','柳帶搖風漢水濱，平蕪兩岸爭勻。',68,'全唐诗/poet.tang.49000.json','["柳帶搖風漢水濱，平蕪兩岸爭勻。", "鴛鴦對浴浪痕新。", "弄珠遊女，微笑自含春。", "輕步暗移蟬鬢動，羅帬風惹輕塵。", "水精宮殿豈無因。", "空勞纖手，解佩贈情人。"]'),
('076480bc-f883-4161-93cd-c38b5583d723','臨江仙 七','牛希濟','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u548f\u7269\u8bd7", "\u6292\u6000", "\u548f\u7269", "\u5199\u666f"]','洞庭波浪颭晴天，君山一點凝煙。',68,'全唐诗/poet.tang.49000.json','["洞庭波浪颭晴天，君山一點凝煙。", "此中真境屬神仙。", "玉樓珠殿，相映月輪邊。", "萬里平湖秋色冷，星辰垂影參然。", "橘林霜重更紅鮮。", "羅浮山下，有路暗相連。"]'),
('fcc0a539-f1a3-4ef2-9486-e89290b403fe','相見歡','薛昭藴','唐','唐诗','tang','','[]','羅襦繡袂香紅，畫堂中。',45,'全唐诗/poet.tang.49000.json','["羅襦繡袂香紅，畫堂中。", "細草平沙蕃馬，小屏風。", "卷羅幕，凭妝閣，思無窮。", "暮雨輕煙魂斷，隔簾櫳。"]'),
('2dfc7812-6035-4f08-b7f0-cb0766dbf81e','醉公子','薛昭藴','唐','唐诗','tang','','[]','慢綰青絲髮，光砑吳綾韈。',48,'全唐诗/poet.tang.49000.json','["慢綰青絲髮，光砑吳綾韈。", "牀上小熏籠，韶州新退紅。", "叵耐無端處，捻得從頭汙。", "惱得眼慵開，問人閑事來。"]'),
('8e761530-d6b4-4fe9-8a62-7bb08c1fa71d','女冠子 一','薛昭藴','唐','唐诗','tang','','[]','求仙去也，翠鈿金箆盡捨，入嵒巒。',50,'全唐诗/poet.tang.49000.json','["求仙去也，翠鈿金箆盡捨，入嵒巒。", "霧卷黃羅帔，雲雕白玉冠。", "野煙溪洞冷，林月石橋寒。", "靜夜松風下，禮天壇。"]'),
('b5f87fbb-0585-4eff-b3b2-c945728d165b','女冠子 二','薛昭藴','唐','唐诗','tang','','[]','雲羅霧縠，新授明威法籙，降真函。',50,'全唐诗/poet.tang.49000.json','["雲羅霧縠，新授明威法籙，降真函。", "髻綰青絲髮，冠抽碧玉篸。", "往來雲過五，去住島經三。", "正遇劉郎使，啓瑤緘。"]'),
('ca8bbf7b-047d-4871-8cca-025c0d278b50','浣溪沙 一','薛昭藴','唐','唐诗','tang','','["\u5199\u96e8", "\u5973\u5b50", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u96e8", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','紅蓼渡頭秋正雨，印沙鷗跡自成行，整鬟飄袖野風香。',48,'全唐诗/poet.tang.49000.json','["紅蓼渡頭秋正雨，印沙鷗跡自成行，整鬟飄袖野風香。", "不語含嚬深浦裏，幾回愁煞櫂船郎，燕歸帆盡水茫茫。"]'),
('2bc749ab-ea09-45e7-b886-821be059e82f','浣溪沙 二','薛昭藴','唐','唐诗','tang','','[]','鈿匣菱花錦帶垂，靜臨蘭檻卸頭時，約鬟低珥算歸期。',48,'全唐诗/poet.tang.49000.json','["鈿匣菱花錦帶垂，靜臨蘭檻卸頭時，約鬟低珥算歸期。", "花茂草青湘渚闊，夢餘空有漏依依，二年終日損芳菲。"]'),
('cb2eec04-7a68-486d-b59e-5943f7292793','浣溪沙 三','薛昭藴','唐','唐诗','tang','','["\u79bb\u522b", "\u5a49\u7ea6", "\u76f8\u601d"]','粉上依稀有淚痕，郡庭花落欲黃昏，遠情深恨與誰論。',48,'全唐诗/poet.tang.49000.json','["粉上依稀有淚痕，郡庭花落欲黃昏，遠情深恨與誰論。", "記得去年寒食日，延秋門外卓金輪，日斜人散暗銷魂。"]'),
('5e86d8df-d39f-4bd2-9d63-58f31877ab6f','浣溪沙 四','薛昭藴','唐','唐诗','tang','','["\u79bb\u522b", "\u996e\u9152"]','握手河橋柳似金，蜂鬚輕惹百花心，蕙風蘭思寄清琴。',48,'全唐诗/poet.tang.49000.json','["握手河橋柳似金，蜂鬚輕惹百花心，蕙風蘭思寄清琴。", "意滿便同春水滿，情深還似酒杯深，楚煙湘月兩沈沈。"]'),
('32c5b2a1-a1fa-47b3-808b-bfa415ef3979','浣溪沙 五','薛昭藴','唐','唐诗','tang','','[]','簾外三間出寺牆，滿街垂柳綠陰長，嫩紅輕翠間濃妝。',48,'全唐诗/poet.tang.49000.json','["簾外三間出寺牆，滿街垂柳綠陰長，嫩紅輕翠間濃妝。", "瞥地見時猶可可，却來閑處暗思量，如今情事隔仙鄉。"]'),
('fab31a88-a7d3-45c5-a597-34d42134c515','浣溪沙 六','薛昭藴','唐','唐诗','tang','','[]','江館清秋纜客船，故人相送夜開筵，麝煙蘭燄簇花鈿。',48,'全唐诗/poet.tang.49000.json','["江館清秋纜客船，故人相送夜開筵，麝煙蘭燄簇花鈿。", "正是斷魂迷楚雨，不堪離恨咽湘弦，月高霜白水連天。"]'),
('c21cfb3c-b2d5-4781-ac34-0a779955a4e8','浣溪沙 七','薛昭藴','唐','唐诗','tang','','["\u5199\u4eba", "\u548f\u53f2", "\u4f24\u6000", "\u5199\u4eba\u8bd7"]','傾國傾城恨有餘，幾多紅淚泣姑蘇，倚風凝睇雪肌膚。',48,'全唐诗/poet.tang.49000.json','["傾國傾城恨有餘，幾多紅淚泣姑蘇，倚風凝睇雪肌膚。", "吳主山河空落日，越王宮殿半平蕪，藕花菱蔓滿平湖。"]'),
('e5c8662d-85ff-445e-a5bf-d1cc71fd855f','浣溪沙 八','薛昭藴','唐','唐诗','tang','','[]','越女淘金春水上，步搖雲鬢佩鳴璫，渚風江草又清香。',48,'全唐诗/poet.tang.49000.json','["越女淘金春水上，步搖雲鬢佩鳴璫，渚風江草又清香。", "不爲遠山凝翠黛，只應含恨向斜陽，碧桃花謝憶劉郎。"]'),
('44f24073-d2c5-488f-a529-ba5978011574','謁金門','薛昭藴','唐','唐诗','tang','','[]','春滿院，疊損羅衣金線。',53,'全唐诗/poet.tang.49000.json','["春滿院，疊損羅衣金線。", "睡覺水精簾未卷，簾前雙語燕。", "斜掩金鋪一扇，滿地落花千片。", "早是相思腸欲斷，忍教頻夢見。"]'),
('540ef26b-17d4-4863-aa24-2a86ef84abb3','喜遷鶯 一','薛昭藴','唐','唐诗','tang','','[]','殘蟾落，曉鐘鳴，羽化覺身輕。',57,'全唐诗/poet.tang.49000.json','["殘蟾落，曉鐘鳴，羽化覺身輕。", "乍無春睡有餘酲，杏苑雪初晴。", "紫陌長，襟袖冷，不是人間風景。", "回看塵土似前生，休羨谷中鸎。"]'),
('e1f2599d-24b0-4835-8004-2cfa3af15afc','喜遷鶯 二','薛昭藴','唐','唐诗','tang','','[]','金門曉，玉京春，駿馬驟輕塵。',57,'全唐诗/poet.tang.49000.json','["金門曉，玉京春，駿馬驟輕塵。", "樺煙深處白衫新，認得化龍身。", "九陌喧，千戶啓，滿袖桂香風細。", "杏園歡宴曲江濱，自此占芳辰。"]'),
('5b976215-2fc2-4a5e-b513-94b30f55fa8f','喜遷鶯 三','薛昭藴','唐','唐诗','tang','','["\u6e05\u660e\u8282", "\u5199\u4eba", "\u8e0f\u9752"]','清明節，雨晴天，得意正當年。',57,'全唐诗/poet.tang.49000.json','["清明節，雨晴天，得意正當年。", "馬驕泥輭錦連乾，香袖半籠鞭。", "花色融，人競賞，盡是繡鞍朱鞅。", "日斜無計更留連，歸路草和煙。"]'),
('ece4cd01-14fc-47d7-9c4b-064387e04548','小重山 一','薛昭藴','唐','唐诗','tang','','[]','春到長門春草青，玉階華露滴，月朧明。',70,'全唐诗/poet.tang.49000.json','["春到長門春草青，玉階華露滴，月朧明。", "東風吹斷紫簫聲，宮漏促，簾外曉啼鸎。", "愁極夢難成，紅妝流宿淚，不勝情。", "手挼裙帶遶花行，思君切，羅幌暗塵生。"]'),
('bd69bddb-b408-403a-aae5-6f933b556eba','小重山 二','薛昭藴','唐','唐诗','tang','','["\u79cb\u5929", "\u8ffd\u5fc6", "\u540c\u60c5"]','秋到長門秋草黃，畫梁雙燕去，出宮牆。',70,'全唐诗/poet.tang.49000.json','["秋到長門秋草黃，畫梁雙燕去，出宮牆。", "玉簫無復理霓裳，金蟬墜，鸞鏡掩休妝。", "憶昔在昭陽，舞衣紅綬帶，繡鴛鴦。", "至今猶惹御爐香，魂夢斷，愁聽漏更長。"]'),
('621866df-16cc-4e00-9fc3-6e138972cd4d','離別難','薛昭藴','唐','唐诗','tang','','[]','寶馬曉鞴雕鞍，羅幃乍別情難。',107,'全唐诗/poet.tang.49000.json','["寶馬曉鞴雕鞍，羅幃乍別情難。", "那堪春景媚，送君千萬里。", "半妝珠翠落，露華寒。", "紅蠟燭，青絲曲，偏能鉤引淚闌干。", "良夜促，香塵綠，魂欲迷，檀眉半歛愁低。", "未別心先咽，欲語情難說。", "出芳草，路東西，搖袖立。", "春風急，櫻花楊柳雨淒淒。"]'),
('cd776d2c-d60f-4d40-819f-0bf2305e889b','荷葉杯 一','顧敻','唐','唐诗','tang','','[]','春盡小庭花落，寂寞，凭檻歛雙眉。',32,'全唐诗/poet.tang.49000.json','["春盡小庭花落，寂寞，凭檻歛雙眉。", "忍教成病憶佳期，知摩知，知摩知。"]'),
('c99f8073-f953-4830-8b7c-4a376737b59c','荷葉杯 二','顧敻','唐','唐诗','tang','','[]','歌發誰家筵上，寥亮，別恨正悠悠。',32,'全唐诗/poet.tang.49000.json','["歌發誰家筵上，寥亮，別恨正悠悠。", "蘭釭背帳月當樓，愁摩愁，愁摩愁。"]'),
('1add64d4-d58f-4234-9237-eddb78f2c41b','荷葉杯 三','顧敻','唐','唐诗','tang','','[]','弱柳好花盡拆，晴陌，陌上少年郎。',32,'全唐诗/poet.tang.49000.json','["弱柳好花盡拆，晴陌，陌上少年郎。", "滿身蘭麝撲人香，狂摩狂，狂摩狂。"]'),
('40f51c32-1ac1-4946-9379-5d597d22e641','荷葉杯 四','顧敻','唐','唐诗','tang','','[]','記得那時相見，膽戰，鬢亂四肢柔。',32,'全唐诗/poet.tang.49000.json','["記得那時相見，膽戰，鬢亂四肢柔。", "泥人無語不擡頭，羞摩羞，羞摩羞。"]'),
('4c3ae759-2e64-44eb-89be-c9b42e5ec753','荷葉杯 五','顧敻','唐','唐诗','tang','','[]','夜久歌聲怨咽，殘月，菊冷露微微。',32,'全唐诗/poet.tang.49000.json','["夜久歌聲怨咽，殘月，菊冷露微微。", "看看濕透縷金衣，歸摩歸，歸摩歸。"]'),
('3431cd28-c1d0-4ea5-968c-a75a50d1fbb1','荷葉杯 六','顧敻','唐','唐诗','tang','','[]','我憶君詩最苦，知否，字字盡關心。',32,'全唐诗/poet.tang.49000.json','["我憶君詩最苦，知否，字字盡關心。", "紅牋寫寄表情深，吟摩吟，吟摩吟。"]'),
('64d1a1fc-ca20-47d8-abc5-818b233bee5f','荷葉杯 七','顧敻','唐','唐诗','tang','','[]','金鴨香濃鴛被，枕膩，小髻簇花鈿。',32,'全唐诗/poet.tang.49000.json','["金鴨香濃鴛被，枕膩，小髻簇花鈿。", "腰如細柳臉如蓮，憐摩憐，憐摩憐。"]'),
('802f822e-0cd2-4b90-b26a-2130afb13fcb','荷葉杯 八','顧敻','唐','唐诗','tang','','[]','曲砌蝶飛煙暖，春半，花發柳垂條。',32,'全唐诗/poet.tang.49000.json','["曲砌蝶飛煙暖，春半，花發柳垂條。", "花如雙臉柳如腰，嬌摩嬌，嬌摩嬌。"]'),
('df3d76ce-a335-4aa0-9519-2b248388d447','荷葉杯 九','顧敻','唐','唐诗','tang','','[]','一去又乖期信，春盡，滿院長莓苔。',32,'全唐诗/poet.tang.49000.json','["一去又乖期信，春盡，滿院長莓苔。", "手挼裙帶獨裴回，來摩來，來摩來。"]'),
('36a4ffca-0fe5-49cc-86af-37546d863eb3','甘州子 一','顧敻','唐','唐诗','tang','','[]','一爐龍麝錦帷傍，屏掩映，燭熒煌。',40,'全唐诗/poet.tang.49000.json','["一爐龍麝錦帷傍，屏掩映，燭熒煌。", "禁樓刁斗喜初長，羅薦繡鴛鴦。", "山枕上，私語口脂香。"]'),
('cac16ab8-5677-4025-8913-909c51a08233','甘州子 二','顧敻','唐','唐诗','tang','','[]','每逢清夜與良晨，多悵望，足傷神。',40,'全唐诗/poet.tang.49000.json','["每逢清夜與良晨，多悵望，足傷神。", "雲迷水隔意中人，寂寞繡羅茵。", "山枕上，幾點淚痕新。"]'),
('870f9154-d5cf-4f4b-95e1-9ec1cd93c035','甘州子 三','顧敻','唐','唐诗','tang','','[]','曾如劉阮訪仙蹤，深洞客，此時逢。',40,'全唐诗/poet.tang.49000.json','["曾如劉阮訪仙蹤，深洞客，此時逢。", "綺筵散後繡衾同，款曲見韶容。", "山枕上，長是怯晨鐘。"]'),
('3a1fa62b-3b65-44e6-a82a-f404ce3c71d7','甘州子 四','顧敻','唐','唐诗','tang','','[]','露桃花裏小樓深，持玉盞，聽瑤琴。',40,'全唐诗/poet.tang.49000.json','["露桃花裏小樓深，持玉盞，聽瑤琴。", "醉歸青瑣入鴛衾，月色照衣襟。", "山枕上，翠鈿鎮眉心。"]'),
('c9dda86c-9f52-41d5-b3c2-770b64504ec0','甘州子 五','顧敻','唐','唐诗','tang','','[]','紅爐深夜醉調笙，敲拍處，玉纖輕。',40,'全唐诗/poet.tang.49000.json','["紅爐深夜醉調笙，敲拍處，玉纖輕。", "小屏古畫岸低平，煙月滿閑庭。", "山枕上，燈背臉波橫。"]'),
('049cb1bf-f38e-43d3-9822-ba3ef690d210','遐方怨','顧敻','唐','唐诗','tang','','[]','簾影細，簟文平。',72,'全唐诗/poet.tang.49000.json','["簾影細，簟文平。", "象紗籠玉指，縷金羅扇輕。", "嫩紅雙臉似花明，兩條眉黛遠山橫。", "鳳簫歇，鏡塵生。", "遼塞音書絕，夢魂長暗驚。", "玉郎經歲負娉婷，教人爭不恨無情。"]'),
('8f5f3f92-b322-4196-834e-9a7e3ae52144','訴衷情 一','顧敻','唐','唐诗','tang','','[]','香滅簾垂春漏永，整鴛衾。',42,'全唐诗/poet.tang.49000.json','["香滅簾垂春漏永，整鴛衾。", "羅帶重，雙鳳，縷黃金。", "窗外月光臨，沈沈。", "斷腸無處尋，負春心。"]'),
('72a704aa-0451-4ec5-99f3-9f7947e78348','訴衷情 二','顧敻','唐','唐诗','tang','','["\u601d\u5ff5", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u7231\u60c5", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5973\u5b50", "\u5a49\u7ea6"]','永夜拋人何處去，絕來音。',47,'全唐诗/poet.tang.49000.json','["永夜拋人何處去，絕來音。", "香閣掩，眉歛，月將沈。", "爭忍不相尋，怨孤衾。", "換我心，爲你心，始知相憶深。"]'),
('dc74db08-9576-4606-9792-ba41a18f5656','楊柳枝','顧敻','唐','唐诗','tang','','["\u6000\u4eba", "\u6292\u60c5", "\u5b64\u5bc2", "\u601d\u5ff5"]','秋夜香閨思寂寥，漏迢迢。',48,'全唐诗/poet.tang.49000.json','["秋夜香閨思寂寥，漏迢迢。", "鴛幃羅幌麝煙銷，燭光搖。", "正憶玉郎遊蕩去，無尋處。", "更聞簾外雨瀟瀟，滴芭蕉。"]'),
('ff663360-0acf-43c4-aa4d-b8c76ad192f8','醉公子 一','顧敻','唐','唐诗','tang','','["\u79cb\u5929", "\u5a49\u7ea6", "\u5199\u666f", "\u76f8\u601d"]','漠漠秋雲澹，紅藕香侵檻。',48,'全唐诗/poet.tang.49000.json','["漠漠秋雲澹，紅藕香侵檻。", "枕倚小山屏，金鋪向晚扃。", "睡起橫波慢，獨望情何限。", "衰柳數聲蟬，魂銷似去年。"]'),
('3e4696b9-336e-487b-90c3-794a5b394f48','醉公子 二','顧敻','唐','唐诗','tang','','["\u56de\u5fc6", "\u9001\u522b", "\u5199\u666f", "\u5973\u5b50", "\u4f24\u6000"]','岸柳垂金線，雨晴鸎百轉。',48,'全唐诗/poet.tang.49000.json','["岸柳垂金線，雨晴鸎百轉。", "家住綠楊邊，往來多少年。", "馬嘶芳草遠，高樓簾半卷。", "歛袖翠蛾攢，相逢爾許難。"]'),
('613e493c-3f2b-4d3b-89e1-d1405c0d668c','酒泉子 一','顧敻','唐','唐诗','tang','','["\u601d\u5ff5", "\u95fa\u6028", "\u5199\u666f"]','楊柳舞風，輕惹春煙殘雨。',51,'全唐诗/poet.tang.49000.json','["楊柳舞風，輕惹春煙殘雨。", "杏花愁，鸎正語，畫樓東。", "錦屏寂寞思無窮，還是不知消息。", "鏡塵生，珠淚滴，損儀容。"]'),
('b6ca68af-4fb5-46df-aa7b-6a2bfcbb0eed','酒泉子 二','顧敻','唐','唐诗','tang','','[]','羅帶縷金，蘭麝煙凝魂斷。',50,'全唐诗/poet.tang.49000.json','["羅帶縷金，蘭麝煙凝魂斷。", "畫屏欹，雲鬢亂，恨難任。", "幾回垂淚滴鴛衾，薄情何處去？", "月臨窗，花滿樹，信沈沈。"]'),
('4c831077-1110-48a0-9a47-9a3ace3db7eb','酒泉子 三','顧敻','唐','唐诗','tang','','[]','小檻日斜，風度綠窗人悄悄，翠幃閑掩舞雙鸞，舊香寒。',51,'全唐诗/poet.tang.49000.json','["小檻日斜，風度綠窗人悄悄，翠幃閑掩舞雙鸞，舊香寒。", "別來情緒轉難判，韶顏看却老，依稀粉上有啼痕，暗銷魂。"]'),
('7f1ba8f5-3d46-48a6-aeb5-2041526c8226','酒泉子 四','顧敻','唐','唐诗','tang','','["\u5b64\u72ec", "\u5973\u5b50", "\u95fa\u6028", "\u611f\u4f24"]','黛薄紅深，約掠綠鬟雲膩。',52,'全唐诗/poet.tang.49000.json','["黛薄紅深，約掠綠鬟雲膩。", "小鴛鴦，金翡翠，稱人心。", "錦鱗無處傳幽意，海燕蘭堂春又去。", "隔年書，千點淚，恨難任。"]'),
('b2b50c8c-4a3c-4558-83ac-45f9c02dfea8','酒泉子 五','顧敻','唐','唐诗','tang','','[]','掩却菱花，收拾翠鈿休上面，金蟲玉燕鎖香匳，恨厭厭。',51,'全唐诗/poet.tang.49000.json','["掩却菱花，收拾翠鈿休上面，金蟲玉燕鎖香匳，恨厭厭。", "雲鬟半墜嬾重篸，淚侵山枕濕，銀燈背帳夢方酣，鴈飛南。"]'),
('6d96547e-54d0-425c-ab06-828fb8c5d7c1','酒泉子 六','顧敻','唐','唐诗','tang','','["\u5987\u5973", "\u95fa\u6028", "\u6c34"]','水碧風清，入檻細香紅藕膩，謝娘歛翠恨無涯，小屏斜。',51,'全唐诗/poet.tang.49000.json','["水碧風清，入檻細香紅藕膩，謝娘歛翠恨無涯，小屏斜。", "堪憎蕩子不還家，謾留羅帶結，帳深枕膩炷沈煙，負當年。"]'),
('45729378-54a0-466a-ace5-32f10d80b6b4','酒泉子 七','顧敻','唐','唐诗','tang','','[]','黛怨紅羞，掩映畫堂春欲暮，殘花微雨隔青樓，思悠悠。',53,'全唐诗/poet.tang.49000.json','["黛怨紅羞，掩映畫堂春欲暮，殘花微雨隔青樓，思悠悠。", "芳菲時節看將度，寂寞無人還獨語。", "畫羅襦，香粉汙，不勝愁。"]'),
('3c04d0a2-2e11-4502-9488-60801566f9e2','浣溪沙 一','顧敻','唐','唐诗','tang','','[]','春色迷人恨正賒，可堪蕩子不還家，細風輕露著梨花。',48,'全唐诗/poet.tang.49000.json','["春色迷人恨正賒，可堪蕩子不還家，細風輕露著梨花。", "簾外有情雙燕颺，檻前無力綠楊斜，小屏狂夢極天涯。"]'),
('99835811-9071-4470-b901-4b134495a9ae','浣溪沙 二','顧敻','唐','唐诗','tang','','[]','紅藕香寒翠渚平，月籠虛閣夜蛩清，塞鴻驚夢兩牽情。',48,'全唐诗/poet.tang.49000.json','["紅藕香寒翠渚平，月籠虛閣夜蛩清，塞鴻驚夢兩牽情。", "寶帳玉爐殘麝冷，羅衣金縷暗塵生，小窗孤燭淚縱橫。"]'),
('0521438c-f57a-46fe-a246-175006f5949f','浣溪沙 三','顧敻','唐','唐诗','tang','','["\u95fa\u6028", "\u5987\u5973", "\u79cb\u601d"]','荷芰風輕簾幕香，繡衣鸂鶒泳回塘，小屏閑掩舊瀟湘。',48,'全唐诗/poet.tang.49000.json','["荷芰風輕簾幕香，繡衣鸂鶒泳回塘，小屏閑掩舊瀟湘。", "恨入空幃鸞影獨，淚凝雙臉渚蓮光，薄情年少悔思量。"]'),
('28919d53-623b-4b5f-b7cd-8e3472b25b3b','浣溪沙 四','顧敻','唐','唐诗','tang','','[]','惆悵經年別謝娘，月窗花院好風光，此時相望最情傷。',48,'全唐诗/poet.tang.49000.json','["惆悵經年別謝娘，月窗花院好風光，此時相望最情傷。", "青鳥不來傳錦字，瑤姬何處鎖蘭房，忍教魂夢兩茫茫。"]'),
('03b8f0fd-4940-4f6d-aea8-7a5793efecb8','浣溪沙 五','顧敻','唐','唐诗','tang','','[]','庭菊飄黃玉露濃，冷莎偎砌隱鳴蛩，何期良夜得相逢。',48,'全唐诗/poet.tang.49000.json','["庭菊飄黃玉露濃，冷莎偎砌隱鳴蛩，何期良夜得相逢。", "背帳風搖紅蠟滴，惹香煖夢繡衾重，覺來枕上怯晨鐘。"]'),
('d5cb5a45-acbb-4294-ba9b-861e7cc19686','浣溪沙 六','顧敻','唐','唐诗','tang','','["\u5b64\u72ec", "\u95fa\u6028", "\u5199\u666f"]','雲澹風高葉亂飛，小庭寒雨綠苔微，深閨人靜掩屏帷。',48,'全唐诗/poet.tang.49000.json','["雲澹風高葉亂飛，小庭寒雨綠苔微，深閨人靜掩屏帷。", "粉黛暗愁金帶枕，鴛鴦空繞畫羅衣，那堪孤負不思歸。"]'),
('1873c0c1-faea-4424-b1c7-4ae7d795ee68','浣溪沙 七','顧敻','唐','唐诗','tang','','[]','鴈響遙天玉漏清，小紗窗外月朧明，翠幃金鴨炷香平。',48,'全唐诗/poet.tang.49000.json','["鴈響遙天玉漏清，小紗窗外月朧明，翠幃金鴨炷香平。", "何處不歸音信斷，良宵空使夢魂驚，簟涼枕冷不勝情。"]'),
('3d33243a-07c2-4629-ac0d-12d902e2d65b','浣溪沙 八','顧敻','唐','唐诗','tang','','["\u601d\u5ff5", "\u79cb\u5929"]','露白蟾明又到秋，佳期幽會兩悠悠，夢牽情役幾時休。',48,'全唐诗/poet.tang.49000.json','["露白蟾明又到秋，佳期幽會兩悠悠，夢牽情役幾時休。", "記得泥人微歛黛，無言斜倚小書樓，暗思前事不勝愁。"]'),
('76f19d19-5cd8-40b0-8365-2473346fc488','更漏子','顧敻','唐','唐诗','tang','','[]','舊歡娛，新悵望，擁鼻含嚬樓上。',58,'全唐诗/poet.tang.49000.json','["舊歡娛，新悵望，擁鼻含嚬樓上。", "濃柳翠，晚霞微，江鷗接翼飛。", "簾半卷，屏斜掩，遠岫參差迷眼。", "歌滿耳，酒盈尊，前非不要論。"]'),
('df8d896d-f1fa-41bd-86ff-bd9ed1bf2d92','應天長','顧敻','唐','唐诗','tang','','[]','瑟瑟羅裙金線縷，輕透鵝黃香畫袴。',58,'全唐诗/poet.tang.49000.json','["瑟瑟羅裙金線縷，輕透鵝黃香畫袴。", "垂交帶，盤鸚鵡，嫋嫋翠翹移玉步。", "背人勻檀注，慢轉嬌波偷覷。", "歛黛春情暗許，倚屏慵不語。"]'),
('3a663e75-3efb-4699-87cc-0d8195888d63','漁歌子','顧敻','唐','唐诗','tang','','[]','曉風清，幽沼綠，倚闌凝望珍禽浴。',62,'全唐诗/poet.tang.49000.json','["曉風清，幽沼綠，倚闌凝望珍禽浴。", "畫簾垂，翠屏曲，滿袖荷香馥郁。", "好攄懷，堪寓目，身閑心靜平生足。", "酒杯深，光影促，名利無心較逐。"]'),
('c5ab8295-95f0-4c11-815f-85e362c91023','河傳 一','顧敻','唐','唐诗','tang','','[]','燕颺，晴景。',68,'全唐诗/poet.tang.49000.json','["燕颺，晴景。", "小窗屏暖，鴛鴦交頸。", "菱花掩却翠鬟欹，慵整，海棠簾外影。", "繡幃香斷金鸂鶒，無消息。", "心事空相憶，倚東風。", "春正濃，愁紅，淚痕衣上重。"]'),
('d93f07d0-9d04-4b51-8897-d3c0c53598fa','河傳 二','顧敻','唐','唐诗','tang','','[]','曲檻，春晚。',68,'全唐诗/poet.tang.49000.json','["曲檻，春晚。", "碧流紋細，綠楊絲輭。", "露華鮮，杏枝繁，鸎轉，野蕪平似翦。", "直是人間到天上，堪遊賞。", "醉眼疑屏障，對池塘。", "惜韶光，斷腸，爲花須盡狂。"]'),
('9b56f91d-cd8a-450d-bf8a-eba82df464c9','河傳 三','顧敻','唐','唐诗','tang','','[]','櫂舉，舟去。',68,'全唐诗/poet.tang.49000.json','["櫂舉，舟去。", "波光渺渺，不知何處。", "岸花汀草共依依，雨微，鷓鴣相逐飛。", "天涯離恨江聲咽，啼猿切。", "此意向誰說，倚蘭橈。", "獨無憀，魂銷，小爐香欲焦。"]'),
('4fcfcb95-6258-4002-9dc3-74c0e99efb2c','木蘭花 一','顧敻','唐','唐诗','tang','','[]','月照玉樓春漏促，颯颯風搖庭砌竹。',64,'全唐诗/poet.tang.49000.json','["月照玉樓春漏促，颯颯風搖庭砌竹。", "夢驚鴛被覺來時，何處管弦聲斷續。", "惆悵少年遊冶去，枕上兩蛾攢細綠。", "曉鶯簾外語花枝，背帳猶殘紅蠟燭。"]'),
('1fddd4bd-ea76-4833-879a-a1e34866b050','木蘭花 二','顧敻','唐','唐诗','tang','','[]','柳映玉樓春日晚，雨細風輕煙草輭。',64,'全唐诗/poet.tang.49000.json','["柳映玉樓春日晚，雨細風輕煙草輭。", "畫堂鸚鵡語雕籠，金粉小屏猶半掩。", "香滅繡幃人寂寂，倚檻無言愁思遠。", "恨郎何處縱疎狂，長使含啼眉不展。"]'),
('61dbe539-7ecb-47bf-b5ff-405b3f234aa2','木蘭花 三','顧敻','唐','唐诗','tang','','[]','月皎露華窗影細，風送菊香黏繡袂。',64,'全唐诗/poet.tang.49000.json','["月皎露華窗影細，風送菊香黏繡袂。", "博山爐冷水沈微，惆悵金閨終日閉。", "嬾展羅衾垂玉筯，羞對菱花篸寶髻。", "良宵好事枉教休，無計那他狂耍壻。"]'),
('6a44c134-659e-4de2-a6f3-104a0df64693','木蘭花 四','顧敻','唐','唐诗','tang','','["\u5987\u5973", "\u6625\u6101", "\u6c34", "\u76f8\u601d"]','拂水雙飛來去燕，曲檻小屏山六扇。',64,'全唐诗/poet.tang.49000.json','["拂水雙飛來去燕，曲檻小屏山六扇。", "春愁凝思結眉心，綠綺嬾調紅錦薦。", "話別情多聲欲戰，玉筯痕留紅粉面。", "鎮長獨立到黃昏，却怕良宵頻夢見。"]'),
('8a4f0e21-34f5-4e8e-85aa-6010fa5b0ad9','虞美人 一','顧敻','唐','唐诗','tang','','[]','曉鶯啼破相思夢，簾卷金泥鳳。',68,'全唐诗/poet.tang.49000.json','["曉鶯啼破相思夢，簾卷金泥鳳。", "宿妝猶在酒初醒，翠翹慵整倚雲屏，轉娉婷。", "香檀細畫侵桃臉，羅袂輕輕歛。", "佳期堪恨再難尋，綠蕪滿院柳成陰，負春心。"]'),
('7175e3f2-5b3c-4f18-b6a0-9f2f1dffafe4','虞美人 二','顧敻','唐','唐诗','tang','','["\u5973\u5b50", "\u95fa\u6028", "\u5199\u666f"]','觸簾風送景陽鐘，鴛被繡花重。',68,'全唐诗/poet.tang.49000.json','["觸簾風送景陽鐘，鴛被繡花重。", "曉幃初卷冷煙濃，翠勻粉黛好儀容，思嬌慵。", "起來無語理朝妝，寶匣鏡凝光。", "綠荷相倚滿池塘，露清枕簟藕花香，恨悠揚。"]'),
('433d2d68-8d02-4fc5-a676-ba87f0e4c8c4','虞美人 三','顧敻','唐','唐诗','tang','','[]','翠屏閑掩垂珠箔，絲雨籠池閣。',68,'全唐诗/poet.tang.49000.json','["翠屏閑掩垂珠箔，絲雨籠池閣。", "露黏紅藕咽清香，謝娘嬌極不成狂，罷朝妝。", "小金鸂鶒沈煙細，膩枕堆雲髻。", "淺眉微歛注檀輕，舊歡時有夢魂驚，悔多情。"]'),
('a7d4c10c-978d-4caf-8a52-bf48b0a87b9f','虞美人 四','顧敻','唐','唐诗','tang','','[]','碧梧桐映紗窗晚，花謝鶯聲嬾。',68,'全唐诗/poet.tang.49000.json','["碧梧桐映紗窗晚，花謝鶯聲嬾。", "小屏屈曲掩青山，翠幃香粉玉爐寒，兩蛾攢。", "顛狂年少輕離別，孤負春時節。", "畫羅紅袂有啼痕，魂銷無語倚閨門，欲黃昏。"]'),
('9209b807-2c7a-4df3-ba38-51a4f66e506a','虞美人 五','顧敻','唐','唐诗','tang','','[]','深閨春色勞思想，恨共春蕪長。',68,'全唐诗/poet.tang.49000.json','["深閨春色勞思想，恨共春蕪長。", "黃鸝嬌轉泥芳妍，杏枝如畫倚輕煙，鎖窗前。", "凭闌愁立雙蛾細，柳影斜搖砌。", "玉郎還是不還家，教人魂夢逐楊花，繞天涯。"]'),
('37479f94-c7da-46bd-af24-cfc94db6a2e4','虞美人 六','顧敻','唐','唐诗','tang','','[]','少年豔質勝瓊英，早晚別三清。',68,'全唐诗/poet.tang.49000.json','["少年豔質勝瓊英，早晚別三清。", "蓮冠穩篸鈿箆橫，飄飄羅袖碧雲輕，畫難成。", "遲遲少轉腰身嫋，翠靨眉心小。", "醮壇風急杏枝香，此時恨不駕鸞皇，訪劉郎。"]'),
('58152f9a-1a8c-487f-a1fb-2b7179e82604','臨江仙 一','顧敻','唐','唐诗','tang','','[]','碧染長空池似鏡，倚樓閑望凝情。',72,'全唐诗/poet.tang.49000.json','["碧染長空池似鏡，倚樓閑望凝情。", "滿衣紅藕細香清。", "象牀珍簟，山障掩，玉琴橫。", "暗想昔時歡笑事，如今贏得愁生。", "博山爐煖澹煙輕。", "蟬吟人靜，殘日傍，小窗明。"]'),
('2f3340e4-e053-4ec3-8e3f-21e3adae893b','臨江仙 二','顧敻','唐','唐诗','tang','','[]','幽閨小檻春光晚，柳濃花澹鶯稀。',68,'全唐诗/poet.tang.49000.json','["幽閨小檻春光晚，柳濃花澹鶯稀。", "舊歡思想尚依依。", "翠嚬紅歛，終日損芳菲。", "何事狂夫音信斷，不如梁燕猶歸。", "畫堂深處麝煙微。", "屏虛枕冷，風細雨霏霏。"]'),
('5d9a9bf0-5df5-4f36-b20d-58fae6822d6b','臨江仙 三','顧敻','唐','唐诗','tang','','["\u611f\u4f24", "\u95fa\u6028"]','月色穿簾風入竹，倚屏雙黛愁時。',68,'全唐诗/poet.tang.49000.json','["月色穿簾風入竹，倚屏雙黛愁時。", "砌花含露兩三枝。", "如啼恨臉，魂斷損容儀。", "香燼暗銷金鴨冷，可堪孤負前期。", "繡襦不整鬢鬟攲。", "幾多惆悵，情緒在天涯。"]'),
('eec24bad-a2ac-4d35-892d-ad7f3311656f','獻衷心','顧敻','唐','唐诗','tang','','[]','繡鴛鴦帳暖，畫孔雀屏欹。',87,'全唐诗/poet.tang.49000.json','["繡鴛鴦帳暖，畫孔雀屏欹。", "人悄悄，月明時。", "想昔年歡笑，恨今日分離。", "銀釭背，銅漏永，阻佳期。", "小爐煙細，虛閣簾垂。", "幾多心事，暗地思惟。", "被嬌娥牽役，魂夢如癡。", "金閨裏，山枕上，始應知。"]'),
('7b339f77-31f9-438c-b15a-711c5e2f16d9','女冠子 一','鹿虔扆','唐','唐诗','tang','','[]','鳳樓琪樹，惆悵劉郎一去，正春深。',50,'全唐诗/poet.tang.49000.json','["鳳樓琪樹，惆悵劉郎一去，正春深。", "洞裏愁空結，人間信莫尋。", "竹疎齋殿迥，松密醮壇陰。", "倚雲低首望，可知心。"]'),
('41ea050a-6f30-4219-bf8d-f3fa4f5bdd45','女冠子 二','鹿虔扆','唐','唐诗','tang','','[]','步虛壇上，絳節霓旌相向，引真仙。',50,'全唐诗/poet.tang.49000.json','["步虛壇上，絳節霓旌相向，引真仙。", "玉佩搖蟾影，金爐嫋麝煙。", "露濃霜簡濕，風緊羽衣偏。", "欲留難得住，却歸天。"]'),
('7d9749e5-d85f-4530-a9aa-7f2b11e0e82a','思越人','鹿虔扆','唐','唐诗','tang','','[]','翠屏欹，銀燭背，漏殘清夜迢迢。',60,'全唐诗/poet.tang.49000.json','["翠屏欹，銀燭背，漏殘清夜迢迢。", "雙帶繡窠盤錦薦，淚侵花暗香銷。", "珊瑚枕膩鴉鬟亂，玉纖慵整雲散。", "苦是適來新夢見，離腸爭不千斷。"]'),
('631b54fc-9c65-4c8f-a0a8-20f8d37a2ecc','虞美人','鹿虔扆','唐','唐诗','tang','','[]','卷荷香澹浮煙渚，綠嫩擎新雨。',68,'全唐诗/poet.tang.49000.json','["卷荷香澹浮煙渚，綠嫩擎新雨。", "瑣窗疎透曉風清，象牀珍簟冷光輕，水文平。", "九疑黛色屏斜掩，枕上眉心歛。", "不堪相望病將成，鈿昏檀粉淚縱橫，不勝情。"]'),
('4e78f122-3f5c-49ac-a2ed-9c4252a6aace','臨江仙 一','鹿虔扆','唐','唐诗','tang','','["\u7231\u56fd"]','金鎖重門荒苑靜，綺窗愁對秋空。',68,'全唐诗/poet.tang.49000.json','["金鎖重門荒苑靜，綺窗愁對秋空。", "翠華一去寂無蹤。", "玉樓歌吹，聲斷已隨風。", "煙月不知人事改，夜闌還照深宮。", "藕花相向野塘中。", "暗傷亡國，清露泣香紅。"]'),
('b810c924-5ff4-4c34-a47a-ace77ea15df0','臨江仙 二','鹿虔扆','唐','唐诗','tang','','[]','無賴曉鶯驚夢斷，起來殘酒初醒。',68,'全唐诗/poet.tang.49000.json','["無賴曉鶯驚夢斷，起來殘酒初醒。", "映窗絲柳嫋煙青。", "翠簾慵卷，約砌杏花零。", "一自玉郎遊冶去，蓮凋月慘儀形。", "暮天微雨灑閑庭。", "手挼裙帶，無語倚雲屏。"]'),
('deccec6b-00f8-41d8-9811-4ab1b67bdc74','訴衷情 一','魏承班','唐','唐诗','tang','','[]','高歌宴罷月初盈，詩情引恨情。',50,'全唐诗/poet.tang.49000.json','["高歌宴罷月初盈，詩情引恨情。", "煙露冷，水流輕，思想夢難成。", "羅帳嫋香平，恨頻生。", "思君無計睡還醒，隔層城。"]'),
('7e90e32e-a815-421f-bfd9-cd98c4005cfe','訴衷情 二','魏承班','唐','唐诗','tang','','[]','春深花簇小樓臺，風飄錦繡開。',50,'全唐诗/poet.tang.49000.json','["春深花簇小樓臺，風飄錦繡開。", "新睡覺，步香階，山枕印紅顋。", "鬢亂墜金釵，語檀偎。", "臨行執手重重屬，幾千回。"]'),
('96ee4309-df9c-4dc7-af11-9b61ae5678c8','訴衷情 三','魏承班','唐','唐诗','tang','','[]','銀漢雲情玉漏長，蛩聲悄畫堂。',50,'全唐诗/poet.tang.49000.json','["銀漢雲情玉漏長，蛩聲悄畫堂。", "筠簟冷，碧窗涼，紅蠟淚飄香。", "皓月瀉寒光，割人腸。", "那堪獨自步池塘，對鴛鴦。"]'),
('6a65762f-839e-4d77-96a3-c8d1fea01c20','訴衷情 四','魏承班','唐','唐诗','tang','','[]','金風輕透碧窗紗，銀釭燄影斜。',50,'全唐诗/poet.tang.49000.json','["金風輕透碧窗紗，銀釭燄影斜。", "欹枕臥，恨何賒，山掩小屏霞。", "雲雨別吳娃，想容華。", "夢成幾度遶天涯，到君家。"]'),
('1488d95e-42f0-42a9-80eb-4891aa911537','訴衷情 五','魏承班','唐','唐诗','tang','','[]','春情滿眼臉紅消，嬌妒索人饒。',50,'全唐诗/poet.tang.49000.json','["春情滿眼臉紅消，嬌妒索人饒。", "星靨小，玉璫搖，幾共醉春朝。", "別後憶纖腰，夢魂勞。", "如今風葉又蕭蕭，恨迢迢。"]'),
('49ee94cd-9eb1-4fbb-a654-aaaba6707384','生查子 一','魏承班','唐','唐诗','tang','','["\u5a49\u7ea6\u8bcd", "\u5b64\u72ec", "\u5973\u5b50", "\u5a49\u7ea6"]','煙雨晚晴天，零落花無語。',48,'全唐诗/poet.tang.49000.json','["煙雨晚晴天，零落花無語。", "難話此時心，梁燕雙來去。", "琴韻對薰風，有恨和情撫。", "腸斷斷弦頻，淚滴黃金縷。"]'),
('cb48dd5f-2935-4b5a-aee2-e06ca1beb37c','生查子 二','魏承班','唐','唐诗','tang','','[]','寂寞畫堂空，深夜垂羅幕。',48,'全唐诗/poet.tang.49000.json','["寂寞畫堂空，深夜垂羅幕。", "燈暗錦屏欹，月冷珠簾薄。", "愁恨夢難成，何處貪歡樂。", "看看又春來，還是長蕭索。"]'),
('33ec4301-e7e4-4722-be6e-5493e8b520f9','生查子 三','魏承班','唐','唐诗','tang','','[]','離別又經年，獨對芳菲景。',50,'全唐诗/poet.tang.49000.json','["離別又經年，獨對芳菲景。", "嫁得薄情夫，長抱相思病。", "花紅柳綠間晴空，蝶舞雙雙影。", "羞看繡羅衣，爲有金鸞竝。"]'),
('f4b8184b-df25-46c3-b3ac-ee7cb88577f9','菩薩蠻 一','魏承班','唐','唐诗','tang','','[]','羅裾薄薄秋波染，眉間畫得山兩點。',52,'全唐诗/poet.tang.49000.json','["羅裾薄薄秋波染，眉間畫得山兩點。", "相見綺筵時，深情暗共知。", "翠翹雲鬢動，歛態彈金鳳。", "宴罷入蘭房，邀人解佩璫。"]'),
('7aae508b-b086-4443-bddc-53bbacb8c94c','菩薩蠻 二','魏承班','唐','唐诗','tang','','[]','羅衣隱約金泥畫，玳筵一曲當秋夜。',54,'全唐诗/poet.tang.49000.json','["羅衣隱約金泥畫，玳筵一曲當秋夜。", "聲顫覷人嬌，[雲]鬟嫋翠翹。", "酒醺紅玉輭，眉翠秋山遠。", "繡幌麝煙沈，誰人知兩心。"]'),
('a4438aee-f218-40fc-babf-fd4d11e12a98','菩薩蠻 三','魏承班','唐','唐诗','tang','','[]','玉容光照菱花影，沈沈臉上秋波冷。',52,'全唐诗/poet.tang.49000.json','["玉容光照菱花影，沈沈臉上秋波冷。", "白雪一聲新，雕梁起暗塵。", "寶釵搖翡翠，香惹芙蓉醉。", "攜手入鴛衾，誰人知此心。"]'),
('97b6ee9e-3e1a-41f4-b978-f26808ef46ac','漁歌子','魏承班','唐','唐诗','tang','','["\u79bb\u522b", "\u5987\u5973"]','柳如眉，雲似髮，鮫綃霧縠籠香雪。',62,'全唐诗/poet.tang.49000.json','["柳如眉，雲似髮，鮫綃霧縠籠香雪。", "夢魂驚，鐘漏歇，窗外曉鶯殘月。", "幾多情，無處說，落花飛絮清明節。", "少年郎，容易別，一去音書斷絕。"]'),
('3a33b96d-d322-465c-8221-949e7386bea7','滿宮花 一','魏承班','唐','唐诗','tang','','[]','雪霏霏，風凜凜。',60,'全唐诗/poet.tang.49000.json','["雪霏霏，風凜凜。", "玉郎何處狂飲，醉時想得縱風流，羅帳香幃鴛寢。", "春朝秋夜思君甚，愁見繡屏孤枕。", "少年何事負初心，淚滴縷金雙袵。"]'),
('acdc2c06-2f64-4b7c-818b-5fb211927587','滿宮花 二','魏承班','唐','唐诗','tang','','[]','寒夜長，更漏永。',60,'全唐诗/poet.tang.49000.json','["寒夜長，更漏永。", "愁見透簾月影，王孫何處不歸來，應在倡樓酩酊。", "金鴨無香羅帳冷，羞更雙鸞交頸。", "夢中幾度見兒夫，不忍駡伊薄倖。"]'),
('93000ffd-2e21-416c-adf9-86d3ec51cb54','謁金門 一','魏承班','唐','唐诗','tang','','[]','煙水闊，人值清明時節。',53,'全唐诗/poet.tang.49000.json','["煙水闊，人值清明時節。", "雨細花零鶯語切，愁腸千萬結。", "鴈去音徽斷絕，有恨欲憑誰說。", "無事傷心猶不徹，春時容易別。"]'),
('07f3ca39-30b0-488e-9e8b-cd454c7ebbd1','謁金門 二','魏承班','唐','唐诗','tang','','[]','春欲半，堆砌落花千片。',53,'全唐诗/poet.tang.49000.json','["春欲半，堆砌落花千片。", "早是潘郎長不見，忍聽雙語燕。", "飛絮晴空颺遠，風送誰家弦管。", "愁倚畫屏凡事嬾，淚霑金縷線。"]'),
('6643378c-dd0f-4597-9a46-f407ca75a574','謁金門 三','魏承班','唐','唐诗','tang','','[]','長思憶，思憶佳辰輕擲。',53,'全唐诗/poet.tang.49000.json','["長思憶，思憶佳辰輕擲。", "霜月透簾澄夜色，小屏山凝碧。", "恨恨君何太極，記得嬌嬈無力。", "獨坐思量愁似織，斷腸煙水隔。"]'),
('cd98291d-64a8-44f4-b6aa-cf1af22e40eb','木蘭花','魏承班','唐','唐诗','tang','','[]','小芙蓉，香旖旎，碧玉堂深清似水。',64,'全唐诗/poet.tang.49000.json','["小芙蓉，香旖旎，碧玉堂深清似水。", "閉寶匣，掩金鋪，倚屏拖袖愁如醉。", "遲遲好景煙花媚，曲渚鴛鴦眠錦翅。", "凝然愁望靜相思，一雙笑靨嚬香蘂。"]'),
('562317fd-861c-4d45-b792-9836b1164e89','玉樓春 一','魏承班','唐','唐诗','tang','','["\u5bf9\u6708", "\u6625\u5929", "\u6000\u4eba", "\u95fa\u6028", "\u5a49\u7ea6"]','寂寂畫堂梁上燕，高卷翠簾橫數扇。',64,'全唐诗/poet.tang.49000.json','["寂寂畫堂梁上燕，高卷翠簾橫數扇。", "一庭春色惱人來，滿地落花紅幾片。", "愁倚錦屏低雪面，淚滴繡羅金縷線。", "好天涼月盡傷心，爲是玉郎長不見。"]'),
('f39f195d-09e1-4e67-b30d-6191162cdf9a','玉樓春 二','魏承班','唐','唐诗','tang','','[]','輕歛翠蛾呈皓齒，鶯轉一枝花影裏。',64,'全唐诗/poet.tang.49000.json','["輕歛翠蛾呈皓齒，鶯轉一枝花影裏。", "聲聲清迥遏行雲，寂寂畫梁塵暗起。", "玉斝滿斟情未已，促坐王孫公子醉。", "春風筵上貫珠勻，豔色韶顏嬌旖旎。"]'),
('63f5c3ae-a990-4fe5-be7f-164cc8011b33','黃鍾樂','魏承班','唐','唐诗','tang','','[]','池塘煙暖草萋萋，惆悵閑宵含恨。',74,'全唐诗/poet.tang.49000.json','["池塘煙暖草萋萋，惆悵閑宵含恨。", "愁坐思堪迷，遙想玉人情事遠，音容渾似隔桃溪。", "偏記同歡秋月低，簾外論心花畔。", "和醉暗相攜，何事春來君不見，夢魂長在錦江西。"]'),
('18eef17d-1f32-4682-9438-19a6e46db5d3','江城子','尹鶚','唐','唐诗','tang','','[]','帬拖碧，步飄香，纖腰束素長。',45,'全唐诗/poet.tang.49000.json','["帬拖碧，步飄香，纖腰束素長。", "鬢雲光，拂面瓏璁，膩玉碎凝妝。", "寶柱秦箏彈向晚，弦促雁，更思量。"]'),
('827aac15-b44e-4db1-a265-4c9607e3fdf9','何滿子','尹鶚','唐','唐诗','tang','','[]','雲雨常陪勝會，笙歌慣逐閑遊。',85,'全唐诗/poet.tang.49000.json','["雲雨常陪勝會，笙歌慣逐閑遊。", "錦里風光應占，玉鞭金勒驊騮。", "戴月潛穿深曲，和香醉脫輕裘。", "方喜正同鴛帳，又言將往皇州。", "每憶良宵公子伴，夢魂長挂紅樓。", "欲表傷離情味，丁香結在心頭。"]'),
('2786042e-1d15-4250-8589-afc625324854','醉公子','尹鶚','唐','唐诗','tang','','[]','暮煙籠蘚砌，戟門猶未閉。',48,'全唐诗/poet.tang.49000.json','["暮煙籠蘚砌，戟門猶未閉。", "盡日醉尋春，歸來月滿身。", "離鞍偎繡袂，墜巾花亂綴。", "何處惱佳人，檀痕衣上新。"]'),
('8522f620-042d-49ba-90ae-85f66484752f','女冠子','尹鶚','唐','唐诗','tang','','[]','雙成伴侶，去去不知何處，有佳期。',50,'全唐诗/poet.tang.49000.json','["雙成伴侶，去去不知何處，有佳期。", "霞帔金絲薄，花冠玉葉危。", "嬾乘丹鳳子，學跨小龍兒。", "叵耐天風緊，挫腰肢。"]'),
('0d204429-cef6-48da-830e-1387a3da29b9','菩薩蠻 一','尹鶚','唐','唐诗','tang','','[]','隴雲暗合秋天白，俯窗獨坐窺煙陌。',52,'全唐诗/poet.tang.49000.json','["隴雲暗合秋天白，俯窗獨坐窺煙陌。", "樓際角重吹，黃昏方醉歸。", "荒唐難共語，明日還應去。", "上馬出門時，金鞭莫與伊。"]'),
('08a31151-6a4a-4fd3-a7cd-ffd0ba7cfdfc','菩薩蠻 二','尹鶚','唐','唐诗','tang','','[]','嗚嗚曉角調如語，畫樓三會喧雷鼓。',52,'全唐诗/poet.tang.49000.json','["嗚嗚曉角調如語，畫樓三會喧雷鼓。", "枕上夢方殘，月光鋪水寒。", "蛾眉應歛翠，咫尺同千里。", "宿酒未全消，滿懷離恨饒。"]'),
('07afe4a4-b78c-446a-91cb-c70043879ea8','菩薩蠻 三','尹鶚','唐','唐诗','tang','','[]','錦茵閑襯丁香枕，銀釭燼落猶慵寢。',52,'全唐诗/poet.tang.49000.json','["錦茵閑襯丁香枕，銀釭燼落猶慵寢。", "顒坐遍紅爐，誰知情緒孤。", "少年狂蕩慣，花曲長牽絆。", "去便不歸來，空教駿馬回。"]'),
('ed875b3e-f772-4ea2-a040-a2f9dc2a8aaa','杏園芳','尹鶚','唐','唐诗','tang','','[]','嚴妝嫩臉花明，教人見了關情。',53,'全唐诗/poet.tang.49000.json','["嚴妝嫩臉花明，教人見了關情。", "含羞舉步越羅輕，稱娉婷。", "終朝咫尺窺香閣，迢遙似隔層城。", "何時休遣夢相縈，入雲屏。"]'),
('8a5e0894-ee35-4835-8ba1-e6569f6dba48','清平樂 一','尹鶚','唐','唐诗','tang','','[]','偎紅歛翠，盡日思閑事。',54,'全唐诗/poet.tang.49000.json','["偎紅歛翠，盡日思閑事。", "髻滑鳳皇釵欲墜，雨打梨花滿地。", "繡衣獨倚闌干，玉容似怯春寒。", "應待少年公子，鴛幃深處同歡。"]'),
('a82ed652-75c6-45c1-a0d3-844f37ab3ffd','清平樂 二','尹鶚','唐','唐诗','tang','','[]','芳年妙妓，淡拂鉛華翠。',54,'全唐诗/poet.tang.49000.json','["芳年妙妓，淡拂鉛華翠。", "輕笑自然生百媚，爭那尊前人意。", "酒傾琥珀杯時，更堪能唱新詞。", "賺得王孫狂處，斷腸一搦腰肢。"]'),
('4ac63601-68b4-49bf-94f3-d0151da7303b','滿宮花','尹鶚','唐','唐诗','tang','','["\u5a49\u7ea6\u8bcd", "\u6292\u6000", "\u5199\u666f", "\u5a49\u7ea6"]','月沈沈，人悄悄，一炷後庭香嫋。',60,'全唐诗/poet.tang.49000.json','["月沈沈，人悄悄，一炷後庭香嫋。", "風流帝子不歸來，滿地禁花慵掃。", "離恨多，相見少，何處醉迷三島。", "漏清宮樹子規啼，愁鎖碧窗春曉。"]'),
('20d65124-64ea-4169-a025-9e3994466c13','臨江仙 一','尹鶚','唐','唐诗','tang','','["\u601d\u5ff5", "\u5bd3\u4eba", "\u8377\u82b1", "\u7537\u5b50"]','一番荷芰生池沼，檻前風送馨香。',68,'全唐诗/poet.tang.49000.json','["一番荷芰生池沼，檻前風送馨香。", "昔年於此伴蕭娘。", "相偎佇立，牽惹敘衷腸。", "時逞笑容無限態，還如菡萏爭芳。", "別來虛遣思悠颺。", "慵窺往事，金鎖小蘭房。"]'),
('77082434-76ea-40ee-8379-171b09d1e12b','臨江仙 二','尹鶚','唐','唐诗','tang','','["\u5a49\u7ea6", "\u611f\u4f24", "\u95fa\u6028"]','深秋寒夜銀河靜，月明深院中庭。',70,'全唐诗/poet.tang.49000.json','["深秋寒夜銀河靜，月明深院中庭。", "西窗幽夢等閑成。", "逡巡覺後，特地恨難平。", "紅燭半條殘焰短，[依]稀暗背銀屏。", "枕前何事最傷情。", "梧桐葉上，點點露珠零。"]'),
('3f52f0ed-26fc-4194-bff7-f4aa1d632255','撥櫂子 一','尹鶚','唐','唐诗','tang','','["\u601d\u5ff5", "\u5b64\u72ec", "\u5199\u666f"]','風切切，深秋月。',72,'全唐诗/poet.tang.49000.json','["風切切，深秋月。", "十朵芙蓉繁豔歇，小檻細腰無力。", "空贏得，目斷魂飛何處說。", "寸心恰似丁香結，看看瘦盡胸前雪。", "偏挂恨，少年拋擲。", "羞覩見，繡被堆紅閑不徹。"]'),
('8df17e20-db30-4af9-80cb-0ce7056d2b2a','撥櫂子 二','尹鶚','唐','唐诗','tang','','[]','丹臉膩，雙靨媚。',74,'全唐诗/poet.tang.49000.json','["丹臉膩，雙靨媚。", "冠子縷金裝翡翠，將一朵，瓊花堪比。", "窠窠繡，鸞鳳衣裳香窣地。", "銀臺蠟燭滴紅淚，醁酒勸人教半醉。", "簾幕外，月華如水。", "特地向，寶帳顛狂不肯睡。"]'),
('0a03b4eb-b0ea-4720-a192-ab61ac1be495','秋夜月','尹鶚','唐','唐诗','tang','','[]','三秋佳節，罥晴空，凝碎露，茱萸千結。',106,'全唐诗/poet.tang.49000.json','["三秋佳節，罥晴空，凝碎露，茱萸千結。", "菊蘂和煙輕撚，酒浮金屑。", "徵雲雨，調絲竹，此時難輟。", "歡極，一片豔歌聲揭。", "黃昏慵別，炷沈煙，熏繡被，翠帷同歇。", "醉竝鴛鴦雙枕，煖偎春雪。", "語丁寧，情委曲，論心正切。", "夜深，窗透數條斜月。"]'),
('00ec1eb0-934a-4cdc-899c-03d4d4ecf2e0','金浮圖','尹鶚','唐','唐诗','tang','','[]','繁華地，王孫富貴。',115,'全唐诗/poet.tang.49000.json','["繁華地，王孫富貴。", "玳瑁筵開，下朝無事。", "壓紅茵，鳳舞黃金翅。", "玉立纖腰，一片揭天歌吹。", "滿目綺羅珠翠，和風淡蕩，偷散沈檀氣。", "堪判醉，韶光正媚。", "折盡牡丹，豔迷人意。", "金張許史應難比，貪戀歡娛，不覺金烏墜。", "還惜會難別易，金船更勸，勒住花驄轡。"]'),
('43b26bff-11ff-4e3e-af16-2dab4773e1a5','定西番','毛熙震','唐','唐诗','tang','','["\u6000\u4eba", "\u5a49\u7ea6\u8bcd", "\u5199\u666f", "\u5a49\u7ea6"]','蒼翠濃陰滿院，鶯對語。',43,'全唐诗/poet.tang.49000.json','["蒼翠濃陰滿院，鶯對語。", "蝶交飛，戲薔薇。", "斜日倚闌風好，餘香出繡衣。", "未得玉郎消息，幾時歸。"]'),
('25eaed0e-c778-453d-9bf1-c4aa567549a0','何滿子 一','毛熙震','唐','唐诗','tang','','[]','寂寞芳菲暗度，歲華如箭堪驚。',86,'全唐诗/poet.tang.49000.json','["寂寞芳菲暗度，歲華如箭堪驚。", "緬想舊歡多少事，轉添春思難平。", "曲檻絲垂金柳，小窗弦斷銀箏。", "深院空聞燕語，滿園閑落花輕。", "一片相思休不得，忍教長日愁生。", "誰見夕陽孤夢，覺來無限傷情。"]'),
('61f4f62d-de38-4dcf-b52c-8bd4e627d5d4','何滿子 二','毛熙震','唐','唐诗','tang','','[]','無語殘妝澹薄，含羞嚲袂輕盈。',86,'全唐诗/poet.tang.49000.json','["無語殘妝澹薄，含羞嚲袂輕盈。", "幾度香閨眠過曉，綺窗疎日微明。", "雲母帳中偷惜，水精枕上初驚。", "笑靨嫩疑花拆，愁眉翠歛山橫。", "相望只教添悵恨，整鬟時見纖瓊。", "獨倚朱扉閑立，誰知別有深情。"]'),
('3e04a599-362c-4639-8bef-1d401fd6fc9d','女冠子 一','毛熙震','唐','唐诗','tang','','[]','碧桃紅杏，遲日媚籠光影，綵霞深。',50,'全唐诗/poet.tang.49000.json','["碧桃紅杏，遲日媚籠光影，綵霞深。", "香暖熏鶯語，風清引鶴音。", "翠鬟冠玉葉，霓袖捧瑤琴。", "應共吹簫侶，暗相尋。"]'),
('b30dcc07-35be-4966-a86c-d31195dbdfe0','女冠子 二','毛熙震','唐','唐诗','tang','','[]','修蛾慢臉，不語檀心一點，小山妝。',52,'全唐诗/poet.tang.49000.json','["修蛾慢臉，不語檀心一點，小山妝。", "蟬鬢低含綠，羅衣澹拂黃。", "[悶]來深院裏，閑步落花傍。", "纖手輕輕整，玉爐香。"]'),
('13ee9f89-3b5b-4d7f-b953-deb35d7c450a','酒泉子 一','毛熙震','唐','唐诗','tang','','[]','閑臥繡幃，慵想萬般情寵。',50,'全唐诗/poet.tang.49000.json','["閑臥繡幃，慵想萬般情寵。", "錦檀偏，翹股重，翠雲欹。", "暮天屏上春山碧，映香煙霧隔。", "蕙蘭心，魂夢役，歛蛾眉。"]'),
('c81a630e-1170-4c2d-8465-92dc4fc8dce8','酒泉子 二','毛熙震','唐','唐诗','tang','','[]','鈿匣舞鸞，隱映豔紅修碧。',50,'全唐诗/poet.tang.49000.json','["鈿匣舞鸞，隱映豔紅修碧。", "月梳斜，雲鬢膩，粉香寒。", "曉花微斂輕呵展，嫋釵金燕輭。", "日初升，簾半卷，對妝殘。"]'),
('14833f3b-b55c-4775-aeb4-fcd75682f670','浣溪沙 一','毛熙震','唐','唐诗','tang','','[]','春暮黃鶯下砌前，水精簾影露珠懸，綺霞低映晚晴天。',48,'全唐诗/poet.tang.49000.json','["春暮黃鶯下砌前，水精簾影露珠懸，綺霞低映晚晴天。", "弱柳萬條垂翠帶，殘紅滿地碎香鈿，蕙風飄蕩散輕煙。"]'),
('74ecb65d-59ce-4430-8a1d-c86cbaf26090','浣溪沙 二','毛熙震','唐','唐诗','tang','','["\u6292\u60c5", "\u5b64\u72ec", "\u5973\u5b50", "\u5199\u666f"]','花榭香紅煙景迷，滿庭芳草綠萋萋，金鋪閑掩繡簾底。',48,'全唐诗/poet.tang.49000.json','["花榭香紅煙景迷，滿庭芳草綠萋萋，金鋪閑掩繡簾底。", "紫燕一雙嬌語碎，翠屏十二晚峰齊，夢魂消散醉空閨。"]'),
('074e7c8a-b265-4cfa-b30f-b454f25c2bf8','浣溪沙 三','毛熙震','唐','唐诗','tang','','[]','晚起紅房醉欲消，綠鬟雲散嫋金翹，雪香花語不勝嬌。',48,'全唐诗/poet.tang.49000.json','["晚起紅房醉欲消，綠鬟雲散嫋金翹，雪香花語不勝嬌。", "好是向人柔弱處，玉纖時急繡帬腰，春心牽惹轉無憀。"]'),
('e5f2cd0e-baf3-4626-9d78-d9c1a1bd498e','浣溪沙 四','毛熙震','唐','唐诗','tang','','[]','一隻橫釵墜髻叢，靜眠珍簟起來慵，繡羅紅嫩抹蘇胸。',48,'全唐诗/poet.tang.49000.json','["一隻橫釵墜髻叢，靜眠珍簟起來慵，繡羅紅嫩抹蘇胸。", "羞歛細蛾魂暗斷，因迷無語思猶濃，小屏香靄碧山重。"]'),
('02e138c3-b25e-4ccb-aa4b-44cf1756bb7a','浣溪沙 五','毛熙震','唐','唐诗','tang','','[]','雲薄羅帬綬帶長，滿身新裛瑞龍香，翠鈿斜映豔梅妝。',48,'全唐诗/poet.tang.49000.json','["雲薄羅帬綬帶長，滿身新裛瑞龍香，翠鈿斜映豔梅妝。", "佯不覷人空婉約，笑和嬌語太猖狂，忍教牽恨暗形相。"]'),
('c1a59f93-1bc1-460d-a86c-096272ddfa80','浣溪沙 六','毛熙震','唐','唐诗','tang','','[]','碧玉冠輕嫋燕釵，捧心無語步香階，緩移弓底繡羅鞋。',48,'全唐诗/poet.tang.49000.json','["碧玉冠輕嫋燕釵，捧心無語步香階，緩移弓底繡羅鞋。", "暗想歡娛何計好，豈堪期約有時乖，日高深院正忘懷。"]'),
('521f2b2b-2754-4315-aa76-a5da687b89a1','浣溪沙 七','毛熙震','唐','唐诗','tang','','[]','半醉凝情臥繡茵，睡容無力卸羅裙，玉籠鸚鵡厭聽聞。',48,'全唐诗/poet.tang.49000.json','["半醉凝情臥繡茵，睡容無力卸羅裙，玉籠鸚鵡厭聽聞。", "慵整落釵金翡翠，象梳欹鬢月生雲，錦屏綃幌麝煙薰。"]'),
('3c05d14b-972f-4b48-8cc5-2a071587c4dd','後庭花 一','毛熙震','唐','唐诗','tang','','[]','鶯啼燕語芳菲節，瑞庭花發。',52,'全唐诗/poet.tang.49000.json','["鶯啼燕語芳菲節，瑞庭花發。", "昔時歡宴歌聲揭，管弦清越。", "自從陵谷追遊歇，畫梁塵黦。", "傷心一片如珪月，閑鎖宮闕。"]'),
('c6c34993-0955-4407-ae8c-bf79131007af','後庭花 二','毛熙震','唐','唐诗','tang','','[]','輕盈舞伎含芳豔，競妝新臉。',52,'全唐诗/poet.tang.49000.json','["輕盈舞伎含芳豔，競妝新臉。", "步搖珠翠修蛾歛，膩鬟雲染。", "歌聲慢發開檀點，繡衫斜掩。", "時將纖手勻紅臉，笑拈金靨。"]'),
('5b458676-96bb-49f9-806b-6a9b61cb1818','後庭花 三','毛熙震','唐','唐诗','tang','','[]','越羅小袖新香蒨，薄籠金釧。',52,'全唐诗/poet.tang.49000.json','["越羅小袖新香蒨，薄籠金釧。", "倚闌無語搖輕扇，半遮勻面。", "春殘日暖鶯嬌嬾，滿庭花片。", "爭不教人長相見，畫堂深院。"]'),
('28d902c2-bef1-4273-8727-f52edd667c76','菩薩蠻 一','毛熙震','唐','唐诗','tang','','["\u601d\u5ff5", "\u5199\u666f"]','梨花滿院飄香雪，高樓夜靜風箏咽。',52,'全唐诗/poet.tang.49000.json','["梨花滿院飄香雪，高樓夜靜風箏咽。", "斜月照簾帷，憶君和夢稀。", "小窗燈影背，燕語驚愁態。", "屏掩斷香飛，行雲山外歸。"]'),
('d2270beb-0b01-438f-8e8d-ce49d97cb728','菩薩蠻 二','毛熙震','唐','唐诗','tang','','[]','繡簾高軸臨塘看，雨翻荷芰真珠散。',52,'全唐诗/poet.tang.49000.json','["繡簾高軸臨塘看，雨翻荷芰真珠散。", "殘暑晚初涼，輕風渡水香。", "無憀悲往事，爭那牽情思。", "光影暗相催，等閑秋又來。"]'),
('06888732-a419-46c9-9010-e054fa27a722','菩薩蠻 三','毛熙震','唐','唐诗','tang','','[]','天含殘碧融春色，五陵薄倖無消息。',52,'全唐诗/poet.tang.49000.json','["天含殘碧融春色，五陵薄倖無消息。", "盡日掩朱門，離愁暗斷魂。", "鶯啼芳樹暖，燕拂回塘滿。", "寂寞對屏山，相思醉夢間。"]'),
('b113a314-0f4c-4922-bf7a-64234edb7645','清平樂','毛熙震','唐','唐诗','tang','','["\u6625\u5929", "\u95fa\u6028", "\u5199\u666f", "\u5a49\u7ea6"]','春光欲暮，寂寞閑庭戶。',54,'全唐诗/poet.tang.49000.json','["春光欲暮，寂寞閑庭戶。", "粉蝶雙雙穿檻舞，簾卷晚天疎雨。", "含愁獨倚閨幃，玉爐煙斷香微。", "正是銷魂時節，東風滿院花飛。"]'),
('9a979cef-4c14-4bc8-96db-92f84e5473c3','更漏子 一','毛熙震','唐','唐诗','tang','','[]','秋色清，河影淡，深戶燭寒光暗。',58,'全唐诗/poet.tang.49000.json','["秋色清，河影淡，深戶燭寒光暗。", "綃幌碧，錦衾紅，博山香炷融。", "更漏咽，蛩鳴切，滿院霜華如雪。", "新月上，薄雲收，映簾懸玉鉤。"]'),
('bd6d6f59-7f30-4cc7-8d8c-1a3852437cb7','更漏子 二','毛熙震','唐','唐诗','tang','','[]','煙月寒，秋夜靜，漏轉金壺初永。',58,'全唐诗/poet.tang.49000.json','["煙月寒，秋夜靜，漏轉金壺初永。", "羅幕下，繡屏空，燈花結碎紅。", "人悄悄，愁無了，思夢不成難曉。", "長憶得，與郎期，竊香私語時。"]'),
('5d3e961f-91f2-4264-b9d9-172a7d80a088','南歌子 一','毛熙震','唐','唐诗','tang','','[]','遠山愁黛碧，橫波慢臉明，膩香紅玉茜羅輕。',62,'全唐诗/poet.tang.49000.json','["遠山愁黛碧，橫波慢臉明，膩香紅玉茜羅輕。", "深院晚堂人靜，理銀箏。", "鬢動行雲影，帬遮點屐聲，嬌羞愛問曲中名。", "楊柳杏花時節，幾多情。"]'),
('d7a63117-7262-4bb7-a4de-a0c4504164d6','南歌子 二','毛熙震','唐','唐诗','tang','','[]','惹恨還添恨，牽腸即斷腸，凝情不語一枝芳。',62,'全唐诗/poet.tang.49000.json','["惹恨還添恨，牽腸即斷腸，凝情不語一枝芳。", "獨映畫簾閑立，繡衣香。", "暗想爲雲女，應憐傅粉郎，晚來輕步出閨房。", "髻慢釵橫無力，縱猖狂。"]'),
('1a7144a7-76ee-49c2-b587-3042bce414e2','木蘭花','毛熙震','唐','唐诗','tang','','[]','掩朱扉，鉤翠箔，滿院鶯聲春寂寞。',64,'全唐诗/poet.tang.49000.json','["掩朱扉，鉤翠箔，滿院鶯聲春寂寞。", "勻粉淚，恨檀郎，一去不歸花又落。", "對斜暉，臨小閣，前事豈堪重想著。", "金帶冷，畫屏幽，寶帳慵熏蘭麝薄。"]'),
('e104e918-cc16-4d78-b0f9-3a6e9a3d4403','小重山','毛熙震','唐','唐诗','tang','','[]','梁燕雙飛畫閣前，寂寥多少恨，嬾孤眠。',70,'全唐诗/poet.tang.49000.json','["梁燕雙飛畫閣前，寂寥多少恨，嬾孤眠。", "曉來閑處想君憐，紅羅帳，金鴨冷沈煙。", "誰信損嬋娟，倚屏啼玉筯，溼香鈿。", "四支無力上鞦韆，羣花謝，愁對豔陽天。"]'),
('b3be1a26-d648-40b0-8c9e-d670c1728362','臨江仙 一','毛熙震','唐','唐诗','tang','','[]','南齊天子寵嬋娟，六宮羅綺三千，潘妃嬌豔獨芳妍。',68,'全唐诗/poet.tang.49000.json','["南齊天子寵嬋娟，六宮羅綺三千，潘妃嬌豔獨芳妍。", "椒房蘭洞，雲雨降神仙。", "縱態迷歡心不足，風流可惜當年，纖腰婉約步金蓮。", "妖君傾國，猶自至今傳。"]'),
('f37302d0-d50a-491b-9d4f-7fca8f0314d0','臨江仙 二','毛熙震','唐','唐诗','tang','','[]','幽閨欲曙聞鶯轉，紅窗月影微明，好風頻謝落花聲。',57,'全唐诗/poet.tang.49000.json','["幽閨欲曙聞鶯轉，紅窗月影微明，好風頻謝落花聲。", "隔幃殘燭，猶照綺屏箏。", "繡被錦茵眠玉煖，炷香斜嫋煙輕，淡蛾羞斂不勝情。"]'),
('b5c29920-5e23-4486-a9c6-8cea077c9846','漁父 一','李珣','唐','唐诗','tang','','[]','水接衡門十里餘，信船歸去臥看書。',32,'全唐诗/poet.tang.49000.json','["水接衡門十里餘，信船歸去臥看書。", "輕爵祿，慕玄虛，莫道漁人只爲魚。"]'),
('e05ab9fb-54ad-479f-b789-b63c3ba86238','漁父 二','李珣','唐','唐诗','tang','','[]','避世垂綸不記年，官高爭得似君閑。',32,'全唐诗/poet.tang.49000.json','["避世垂綸不記年，官高爭得似君閑。", "傾白酒，對青山，笑指柴門待月還。"]'),
('532ec4a3-c152-4b35-ba8b-6c4a68a58b2e','漁父 三','李珣','唐','唐诗','tang','','[]','櫂警鷗飛水濺袍，影隨潭面柳垂縚。',32,'全唐诗/poet.tang.49000.json','["櫂警鷗飛水濺袍，影隨潭面柳垂縚。", "終日醉，絕塵勞，曾見錢塘八月濤。"]'),
('5d18821e-9ec6-435a-87a8-9e1a5594ff0e','南鄉子 一','李珣','唐','唐诗','tang','','[]','煙漠漠，雨淒淒，岸花零落鷓鴣啼。',36,'全唐诗/poet.tang.49000.json','["煙漠漠，雨淒淒，岸花零落鷓鴣啼。", "遠客扁舟臨野渡，思鄉處，潮退水平春色暮。"]'),
('fd56e488-9962-4ad2-b620-5ff1c50213dc','南鄉子 二','李珣','唐','唐诗','tang','','[]','蘭橈舉，水文開，競攜藤籠采蓮來。',36,'全唐诗/poet.tang.49000.json','["蘭橈舉，水文開，競攜藤籠采蓮來。", "回塘深處遙相見，邀同宴，淥酒一巵紅上面。"]'),
('d7a5d641-0eb8-4c04-9c8b-3f4af53f9c42','南鄉子 三','李珣','唐','唐诗','tang','','[]','歸路近，扣舷歌，采真珠處水風多。',36,'全唐诗/poet.tang.49000.json','["歸路近，扣舷歌，采真珠處水風多。", "曲岸小橋山月過，煙深鎖，豆蔻花垂千萬朵。"]'),
('96948b9f-faf5-4c7c-b965-b3c325efb564','南鄉子 四','李珣','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5c11\u5973", "\u5a49\u7ea6", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','乘綵舫，過蓮塘，櫂歌驚起睡鴛鴦。',36,'全唐诗/poet.tang.49000.json','["乘綵舫，過蓮塘，櫂歌驚起睡鴛鴦。", "帶香遊女偎伴笑，爭窈窕，競折團荷遮晚照。"]'),
('247d70ab-539b-4859-83d5-dccbfbf85835','南鄉子 五','李珣','唐','唐诗','tang','','[]','傾綠蟻，泛紅螺，閑邀女伴簇笙歌。',36,'全唐诗/poet.tang.49000.json','["傾綠蟻，泛紅螺，閑邀女伴簇笙歌。", "避暑信船輕浪裏，閑游戲，夾岸荔支紅蘸水。"]'),
('476685f9-2788-4387-8bbb-376064101d82','南鄉子 六','李珣','唐','唐诗','tang','','[]','雲帶雨，浪迎風，釣翁回櫂碧灣中。',36,'全唐诗/poet.tang.49000.json','["雲帶雨，浪迎風，釣翁回櫂碧灣中。", "春酒香熟鱸魚美，誰同醉，纜却扁舟篷底睡。"]'),
('65de0b89-c4a1-4167-8fbc-7489e550da5a','南鄉子 七','李珣','唐','唐诗','tang','','[]','沙月靜，水煙輕，芰荷香裏夜船行。',36,'全唐诗/poet.tang.49000.json','["沙月靜，水煙輕，芰荷香裏夜船行。", "綠鬟紅臉誰家女，遙相顧，緩唱櫂歌極浦去。"]'),
('26aa81b9-8ed8-4306-970d-4b9eb629448c','南鄉子 八','李珣','唐','唐诗','tang','','[]','漁市散，渡船稀，越南雲樹望中微。',36,'全唐诗/poet.tang.49000.json','["漁市散，渡船稀，越南雲樹望中微。", "行客待潮天欲暮，送春浦，愁聽猩猩啼瘴雨。"]'),
('9b8c14ec-8b91-4437-8035-7ac20ff04852','南鄉子 九','李珣','唐','唐诗','tang','','[]','攏雲髻，背犀梳，焦紅衫映綠羅裾。',36,'全唐诗/poet.tang.49000.json','["攏雲髻，背犀梳，焦紅衫映綠羅裾。", "越王臺下春風暖，花盈岸，遊賞每邀鄰女伴。"]'),
('98dc7da7-3563-4bb9-994a-ae937a4f81e3','南鄉子 十','李珣','唐','唐诗','tang','','["\u5c11\u5973", "\u5199\u4eba", "\u7231\u60c5"]','相見處，晚晴天，刺桐花下越臺前。',36,'全唐诗/poet.tang.49000.json','["相見處，晚晴天，刺桐花下越臺前。", "暗裏回眸深屬意，遺雙翠，騎象背人先過水。"]'),
('0f9c9a82-fe2f-45cc-9a5f-f204b397c6e1','南鄉子 十一','李珣','唐','唐诗','tang','','[]','攜籠去，采菱歸，碧波風起雨霏霏。',36,'全唐诗/poet.tang.49000.json','["攜籠去，采菱歸，碧波風起雨霏霏。", "趁岸小船齊櫂急，羅衣溼，出向桄榔樹下立。"]'),
('9b86ce6b-1f21-48ba-aadb-10d3750bb2a7','南鄉子 十二','李珣','唐','唐诗','tang','','[]','雲髻重，葛衣輕，見人微笑亦多情。',36,'全唐诗/poet.tang.49000.json','["雲髻重，葛衣輕，見人微笑亦多情。", "拾翠采珠能幾許，來還去，爭及村居織機女。"]'),
('de87596f-5622-42bd-b13b-278ac97f32fb','南鄉子 十三','李珣','唐','唐诗','tang','','[]','登畫舸，泛清波，采蓮時唱采蓮歌。',36,'全唐诗/poet.tang.49000.json','["登畫舸，泛清波，采蓮時唱采蓮歌。", "攔櫂聲齊羅袖斂，池光颭，驚起沙鷗八九點。"]'),
('f4bab55c-8ede-4bc0-965d-5db75de2553e','南鄉子 十四','李珣','唐','唐诗','tang','','[]','雙髻墜，小眉彎，笑隨女伴下春山。',36,'全唐诗/poet.tang.49000.json','["雙髻墜，小眉彎，笑隨女伴下春山。", "玉纖遙指花深處，爭回顧，孔雀雙雙迎日舞。"]'),
('f839416d-477f-4954-a99a-707f7a16a86e','南鄉子 十五','李珣','唐','唐诗','tang','','[]','紅豆蔻，紫玫瑰，謝娘家接越王臺。',36,'全唐诗/poet.tang.49000.json','["紅豆蔻，紫玫瑰，謝娘家接越王臺。", "一曲鄉歌齊撫掌，堪遊賞，酒酌螺杯流水上。"]'),
('653b43b1-1eb4-4749-9e01-a7cc83799d9d','南鄉子 十六','李珣','唐','唐诗','tang','','["\u6c5f\u5357", "\u5c71", "\u751f\u6d3b", "\u4eba\u6c11", "\u5199\u666f"]','山果熟，水花香，家家風景有池塘。',36,'全唐诗/poet.tang.49000.json','["山果熟，水花香，家家風景有池塘。", "木蘭舟上珠簾卷，歌聲遠，椰子酒傾鸚鵡醆。"]'),
('e11a80ed-d673-4c77-a2a7-912849e5e855','南鄉子 十七','李珣','唐','唐诗','tang','','[]','新月上，遠煙開，慣隨潮水采珠來。',36,'全唐诗/poet.tang.49000.json','["新月上，遠煙開，慣隨潮水采珠來。", "櫂穿花過歸溪口，酤春酒，小艇纜牽垂岸柳。"]'),
('f687c986-6b25-4042-acee-36025c48d160','西溪子 一','李珣','唐','唐诗','tang','','[]','金縷翠鈿浮動，妝罷小窗圓夢。',43,'全唐诗/poet.tang.49000.json','["金縷翠鈿浮動，妝罷小窗圓夢。", "日高時，春已老，人來到，滿地落花慵埽。", "無語倚屏風，泣殘紅。"]'),
('06b7b22c-e7ac-482c-96ce-85c41fbe1ff1','西溪子 二','李珣','唐','唐诗','tang','','[]','馬上見時如夢，認得臉波相送。',43,'全唐诗/poet.tang.49000.json','["馬上見時如夢，認得臉波相送。", "柳堤長，無限意，夕陽裏，醉把金鞭欲墜。", "歸去想嬌嬈，暗魂銷。"]'),
('05558777-b488-490e-b423-20a2ad1d6a20','女冠子 一','李珣','唐','唐诗','tang','','[]','星高月午，丹桂青松深處，醮壇開。',50,'全唐诗/poet.tang.49000.json','["星高月午，丹桂青松深處，醮壇開。", "金磬敲清露，珠幢立翠苔。", "步虛聲縹緲，相像思徘徊。", "曉天歸去路，指蓬萊。"]'),
('c1cd81e5-ee89-4384-90d2-fa4faf276a88','女冠子 二','李珣','唐','唐诗','tang','','["\u5c71", "\u6292\u60c5", "\u9053\u58eb", "\u5199\u4eba"]','春山夜靜，愁聞洞天疎磬，玉堂虛。',50,'全唐诗/poet.tang.49000.json','["春山夜靜，愁聞洞天疎磬，玉堂虛。", "細霧垂珠佩，輕煙曳翠裾。", "對花情脈脈，望月步徐徐。", "劉阮今何處，絕來書。"]'),
('682f88eb-c0f1-4c23-a18c-84d5d217a398','中興樂','李珣','唐','唐诗','tang','','[]','後庭寂寂日初長，翩翩蝶舞紅芳。',102,'全唐诗/poet.tang.49000.json','["後庭寂寂日初長，翩翩蝶舞紅芳。", "繡簾垂地，金鴨無香，誰知春思如狂，憶蕭郎。", "等閑一去，程遙信斷，五嶺三湘。", "休開鸞鏡學宮妝，可能更理笙簧。", "倚屏凝睇，淚落成行，手尋裙帶鴛鴦，暗思量。", "忍孤前約，教人花貌，虛老風光。"]'),
('4529676f-c5c5-464b-8734-1dc6638757ee','酒泉子 一','李珣','唐','唐诗','tang','','[]','寂寞青樓，風觸繡簾珠碎撼。',53,'全唐诗/poet.tang.49000.json','["寂寞青樓，風觸繡簾珠碎撼。", "月朦朧，花暗澹，鎖春愁。", "尋思往事依稀夢，淚臉露桃紅色重。", "鬢欹蟬，釵墜鳳，思悠悠。"]'),
('12273877-96ff-42b1-ae4f-349d5e49dbfb','酒泉子 二','李珣','唐','唐诗','tang','','["\u79bb\u522b", "\u6101\u601d"]','雨漬花零，紅散香凋池兩岸。',53,'全唐诗/poet.tang.49000.json','["雨漬花零，紅散香凋池兩岸。", "別情遙，春歌斷，掩銀屏。", "孤帆早晚離三楚，閑理鈿箏愁幾許。", "曲中情，弦上語，不堪聽。"]'),
('4e066325-85d3-49cf-96c9-228e6c6a47c9','酒泉子 三','李珣','唐','唐诗','tang','','[]','秋雨連綿，聲散敗荷叢裏。',52,'全唐诗/poet.tang.49000.json','["秋雨連綿，聲散敗荷叢裏。", "那堪深夜枕前聽，酒初醒。", "牽愁惹思更無停，燭暗香凝天欲曙。", "細和煙，冷和雨，透簾旌。"]'),
('9f7f5df0-8477-4726-8448-3986817f63e4','酒泉子 四','李珣','唐','唐诗','tang','','[]','秋月嬋娟，皎潔碧紗窗外。',51,'全唐诗/poet.tang.49000.json','["秋月嬋娟，皎潔碧紗窗外。", "照花穿竹冷沈沈，印池心。", "凝露滴，砌蛩吟。", "驚覺謝娘殘夢，夜深斜傍枕前來，影徘徊。"]'),
('8aa82c90-03b7-4b5a-8064-f77aee7a58ab','浣溪沙 一','李珣','唐','唐诗','tang','','[]','入夏偏宜澹薄妝，越羅衣褪鬱金黃，翠鈿檀注助容光。',48,'全唐诗/poet.tang.49000.json','["入夏偏宜澹薄妝，越羅衣褪鬱金黃，翠鈿檀注助容光。", "相見無言還有恨，幾回判却又思量，月窗香徑夢悠颺。"]'),
('339b46be-397b-424b-bc67-89621f4d725b','浣溪沙 二','李珣','唐','唐诗','tang','','[]','晚出閑庭看海棠，風流學得內家妝，小釵橫戴一枝芳。',48,'全唐诗/poet.tang.49000.json','["晚出閑庭看海棠，風流學得內家妝，小釵橫戴一枝芳。", "鏤玉梳斜雲鬢膩，縷金衣透雪肌香，暗思何事立殘陽。"]'),
('3f0e607d-0b39-453f-abd3-01c879b2ef2c','浣溪沙 三','李珣','唐','唐诗','tang','','[]','訪舊傷離欲斷魂，無因重見玉樓人，六街微雨鏤香塵。',48,'全唐诗/poet.tang.49000.json','["訪舊傷離欲斷魂，無因重見玉樓人，六街微雨鏤香塵。", "早爲不逢巫峽夢，那堪虛度錦江春，遇花傾酒莫辭頻。"]'),
('5de8125a-0bb5-4239-b032-697f5ab0f2ce','浣溪沙 四','李珣','唐','唐诗','tang','','[]','紅藕花香到檻頻，可堪閑憶似花人，舊歡如夢絕音塵。',24,'全唐诗/poet.tang.49000.json','["紅藕花香到檻頻，可堪閑憶似花人，舊歡如夢絕音塵。"]'),
('60065c15-5bd2-4f72-a21e-7af33e65d0ac','巫山一段雲 一','李珣','唐','唐诗','tang','','[]','有客經巫峽，停橈向水湄。',52,'全唐诗/poet.tang.49000.json','["有客經巫峽，停橈向水湄。", "楚王曾此夢瑤姬，一夢杳無期。", "塵暗珠簾卷，香銷翠幄垂。", "西風回首不勝悲，暮雨灑空祠。"]'),
('708d1fc4-07c9-4615-bf78-a59b5603af99','巫山一段雲 二','李珣','唐','唐诗','tang','','["\u5a49\u7ea6", "\u5c71\u6c34", "\u6000\u5ff5", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u884c\u821f", "\u5bfa\u5e99"]','古廟依青嶂，行宮枕碧流。',52,'全唐诗/poet.tang.49000.json','["古廟依青嶂，行宮枕碧流。", "水聲山色鎖妝樓，往事思悠悠。", "雲雨朝還暮，煙花春復秋。", "啼猨何必近孤舟，行客自多愁。"]'),
('bcdb0c46-805f-4264-9b42-ba659edf64e7','菩薩蠻 一','李珣','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50", "\u5199\u666f"]','回塘風起波文細，刺桐花裏門斜閉。',52,'全唐诗/poet.tang.49000.json','["回塘風起波文細，刺桐花裏門斜閉。", "殘日照平蕪，雙雙飛鷓鴣。", "征帆何處客，相見還相隔。", "不語欲魂銷，望中煙水遙。"]'),
('9c6f7fce-1ae7-4a25-949c-fd27c7f019a1','菩薩蠻 二','李珣','唐','唐诗','tang','','[]','等閑將度三春景，簾垂碧砌參差影。',52,'全唐诗/poet.tang.49000.json','["等閑將度三春景，簾垂碧砌參差影。", "曲檻日初斜，杜鵑啼落花。", "恨君容易處，又話瀟湘去。", "凝思倚屏山，淚流紅臉斑。"]'),
('e312a3be-340e-4d75-b926-bba030ab95a9','菩薩蠻 三','李珣','唐','唐诗','tang','','[]','隔簾微雨雙飛燕，砌花零落紅深淺。',52,'全唐诗/poet.tang.49000.json','["隔簾微雨雙飛燕，砌花零落紅深淺。", "捻得寶箏調，心隨征櫂遙。", "楚天雲外路，動便經年去。", "香斷畫屏深，舊歡何處尋。"]'),
('0b3b95c3-6eba-44c4-a37f-f0906161c3e8','漁歌子 一','李珣','唐','唐诗','tang','','[]','楚山青，湘水淥，春風澹蕩看不足。',62,'全唐诗/poet.tang.49000.json','["楚山青，湘水淥，春風澹蕩看不足。", "草芊芊，花簇簇，漁艇櫂歌相續。", "信浮沈，無管束，釣回乘月歸灣曲。", "酒盈尊，雲滿屋，不見人間榮辱。"]'),
('40b6a670-b8dd-438a-b85c-5a52186366b7','漁歌子 二','李珣','唐','唐诗','tang','','["\u79cb\u5929", "\u5f52\u9690", "\u5199\u666f"]','荻花秋，瀟湘夜，橘洲佳景如屏畫。',62,'全唐诗/poet.tang.49000.json','["荻花秋，瀟湘夜，橘洲佳景如屏畫。", "碧煙中，明月下，小艇垂綸初罷。", "水爲鄉，蓬作舍，魚羹稻飯常飡也。", "酒盈杯，書滿架，名利不將心挂。"]'),
('bf6109d8-9474-4ff4-92be-42d62b58b17e','漁歌子 三','李珣','唐','唐诗','tang','','[]','柳垂絲，花滿樹，鶯啼楚岸春天暮。',62,'全唐诗/poet.tang.49000.json','["柳垂絲，花滿樹，鶯啼楚岸春天暮。", "櫂輕舟，出深浦，緩唱漁郎歸去。", "罷垂綸，還酌醑，孤村遙指雲遮處。", "下長汀，臨深渡，驚起一行沙鷺。"]'),
('0c8b98eb-208d-486d-9206-16b43b967cc9','漁歌子 四','李珣','唐','唐诗','tang','','[]','九疑山，三湘水，蘆花時節秋風起。',62,'全唐诗/poet.tang.49000.json','["九疑山，三湘水，蘆花時節秋風起。", "水雲間，山月裏，櫂月穿雲遊戲。", "鼓清琴，傾淥蟻，扁舟自得逍遙志。", "任東西，無定止，不議人間醒醉。"]'),
('3c2c9656-63aa-487f-a075-7c80cc54d7b0','望遠行 一','李珣','唐','唐诗','tang','','[]','春日遲遲思寂寥，行客關山路遙。',62,'全唐诗/poet.tang.49000.json','["春日遲遲思寂寥，行客關山路遙。", "瓊窗時聽語鶯嬌，柳絲牽恨一條條。", "休暈繡，罷吹簫，貌逐殘花暗凋。", "同心猶結舊帬腰，忍孤風月度良宵。"]'),
('06ec58fc-8048-460b-ba02-543697d557a9','望遠行 二','李珣','唐','唐诗','tang','','[]','露滴幽庭落葉時，愁聚蕭娘柳眉。',62,'全唐诗/poet.tang.49000.json','["露滴幽庭落葉時，愁聚蕭娘柳眉。", "玉郎一去負佳期，水雲迢遰雁書遲。", "屏半掩，枕斜欹，蠟淚無言對垂。", "吟蛩斷續漏頻移，入窗明月鑒空幃。"]'),
('26b558f2-256b-4b8b-9daf-21579a7c29e3','河傳 一','李珣','唐','唐诗','tang','','[]','去去，何處。',68,'全唐诗/poet.tang.49000.json','["去去，何處。", "迢迢巴楚，山水相連。", "朝雲暮雨，依舊十二峰前，猨聲到客船。", "愁腸豈異丁香結，因離別，故國音書絕。", "想佳人花下，對明月春風，恨應同。"]'),
('c9a2cf3a-3835-467d-b376-7ee46b21c4a3','河傳 二','李珣','唐','唐诗','tang','','[]','春暮，微雨。',68,'全唐诗/poet.tang.49000.json','["春暮，微雨。", "送君南浦，愁斂雙蛾。", "落花深處，啼鳥似逐離歌，粉檀珠淚和。", "臨流更把同心結，情哽咽，後會何時節。", "不堪回首相望，已隔汀洲，櫓聲幽。"]'),
('5ad82ed6-247b-4c36-87c9-c83f429a8525','虞美人','李珣','唐','唐诗','tang','','[]','金籠鶯報天將曙，驚起分飛處。',68,'全唐诗/poet.tang.49000.json','["金籠鶯報天將曙，驚起分飛處。", "夜來潛與玉郎期，多情不覺酒醒遲，失歸期。", "映花避月遙相送，膩髻偏垂鳳。", "却回嬌步入香閨，倚屏無語撚雲箆，翠眉低。"]'),
('eea807a5-0933-4cb7-a740-7f7a5db89247','臨江仙 一','李珣','唐','唐诗','tang','','[]','簾卷池心小閣虛，暫涼閑步徐徐。',68,'全唐诗/poet.tang.49000.json','["簾卷池心小閣虛，暫涼閑步徐徐。", "芰荷經雨半凋疎，拂堤垂柳，蟬噪夕陽餘。", "不語低鬟幽思遠，玉釵斜墜雙魚。", "幾回偷看寄來書，離情別恨，相隔欲何如。"]'),
('e89b6389-cff0-4db9-9870-5e8b067171b9','臨江仙 二','李珣','唐','唐诗','tang','','[]','鶯報簾前暖日紅，玉爐殘麝猶濃。',70,'全唐诗/poet.tang.49000.json','["鶯報簾前暖日紅，玉爐殘麝猶濃。", "起來閨思尚疎慵，[別]愁春夢，誰解此情悰。", "彊整嬌姿臨寶鏡，小池一朵芙蓉。", "舊歡無處再尋蹤，更堪回顧，屏畫九疑峰。"]'),
('61fff933-a0ed-4164-83d1-27f8e87d93fd','定風波 一','李珣','唐','唐诗','tang','','[]','志在煙霞慕隱淪，功成歸看五湖春。',73,'全唐诗/poet.tang.49000.json','["志在煙霞慕隱淪，功成歸看五湖春。", "一葉舟中吟復醉，雲水，此時方認自由身。", "花島爲鄰鷗作侶，深處，經年不見市朝人。", "已得希夷微妙旨，潛喜，荷衣蕙帶絕纖塵。"]'),
('d71f3418-6ebc-42d2-9534-b02f44eba2fa','定風波 二','李珣','唐','唐诗','tang','','[]','十載逍遙物外居，白雲流水似相於。',73,'全唐诗/poet.tang.49000.json','["十載逍遙物外居，白雲流水似相於。", "乘興有時攜短櫂，江島，誰知求道不求魚。", "到處等閑邀鶴伴，春岸，野花香氣撲琴書。", "更飲一杯紅霞酒，回首，半鉤新月貼清虛。"]'),
('09c15b2c-a7c9-44a0-98bf-8991313da30f','定風波 三','李珣','唐','唐诗','tang','','[]','又見辭巢燕子歸，阮郎何事絕音徽。',73,'全唐诗/poet.tang.49000.json','["又見辭巢燕子歸，阮郎何事絕音徽。", "簾外西風黃葉落，池閣，隱莎蛩叫雨霏霏。", "愁坐算程千萬里，頻跂，等閑經歲兩相違。", "聽鵲憑龜無定處，不知，淚痕流在畫羅衣。"]'),
('58fced0b-0d5b-424e-902f-ccdad55da9a3','定風波 四','李珣','唐','唐诗','tang','','[]','雁過秋空夜未央，隔窗煙月鎖蓮塘。',73,'全唐诗/poet.tang.49000.json','["雁過秋空夜未央，隔窗煙月鎖蓮塘。", "往事豈堪容易想，惆悵，故人迢遰在瀟湘。", "縱有回文重疊意，誰寄，解鬟臨鏡泣殘妝。", "沈水香消金鴨冷，愁永，候蟲聲接杵聲長。"]'),
('f9390a40-6928-4136-bc48-bd8ca51cd85e','定風波 五','李珣','唐','唐诗','tang','','[]','簾外煙和月滿庭，此時閑坐若爲情。',73,'全唐诗/poet.tang.49000.json','["簾外煙和月滿庭，此時閑坐若爲情。", "小閣擁爐殘酒醒，愁聽，寒風葉落一聲聲。", "惟恨玉人芳信阻，雲雨，屏帷寂寞夢難成。", "斗轉更闌心杳杳，將曉，銀釭斜照綺琴橫。"]'),
('df76abfb-56ef-4ff3-9585-c50515835af0','南歌子','歐陽炯','唐','唐诗','tang','','[]','錦帳銀燈影，紗窗玉漏聲，迢迢永夜夢難成。',31,'全唐诗/poet.tang.49000.json','["錦帳銀燈影，紗窗玉漏聲，迢迢永夜夢難成。", "愁對小庭秋色，月空明。"]'),
('92c51161-e4a9-4d04-83b4-5772d6199098','漁父 一','歐陽炯','唐','唐诗','tang','','[]','擺脫塵機上釣船，免教榮辱有流年。',32,'全唐诗/poet.tang.49000.json','["擺脫塵機上釣船，免教榮辱有流年。", "無繫絆，沒愁煎，須信船中有散仙。"]'),
('3c3c3e5a-cb3e-4b9e-a14a-746dfb0f25c2','漁父 二','歐陽炯','唐','唐诗','tang','','[]','風浩寒溪照膽明，小君山上玉蟾生。',32,'全唐诗/poet.tang.49000.json','["風浩寒溪照膽明，小君山上玉蟾生。", "荷露墜，翠煙輕，撥剌游魚幾箇驚。"]'),
('672dc390-62c6-4784-bc85-1b8fe1435764','巫山一段雲 一','歐陽炯','唐','唐诗','tang','','[]','絳闕登真子，飄飄御綵鸞。',52,'全唐诗/poet.tang.49000.json','["絳闕登真子，飄飄御綵鸞。", "碧虛風雨佩光寒，斂袂下雲端。", "月帳朝霞薄，星冠玉蘂攢。", "遠遊蓬島降人間，特地拜龍顏。"]'),
('8996ca1f-d51f-40b8-adf7-74ac77bcbccb','巫山一段雲 二','歐陽炯','唐','唐诗','tang','','["\u76f8\u601d", "\u95fa\u6028"]','春去秋來也，愁心似醉醺。',54,'全唐诗/poet.tang.49000.json','["春去秋來也，愁心似醉醺。", "去時邀約早回輪，及去又何曾。", "歌扇花光[黦]，衣珠滴淚新。", "恨身飜不作車塵，萬里得隨君。"]'),
('15718a00-e714-4b68-a9bb-93df519d9e65','春光好 一','歐陽炯','唐','唐诗','tang','','[]','天初暖，日初長，好春光。',50,'全唐诗/poet.tang.49000.json','["天初暖，日初長，好春光。", "萬彙此時皆得意，競芬芳。", "筍迸苔錢嫩綠，花偎雪塢濃香。", "誰把金絲裁翦却，挂斜陽。"]'),
('a0f8186b-3b47-419b-a667-eb64560d35c2','春光好 二','歐陽炯','唐','唐诗','tang','','["\u6625\u5929", "\u82b1", "\u5199\u82b1", "\u996e\u9152"]','花滴露，柳搖煙，豔陽天。',50,'全唐诗/poet.tang.49000.json','["花滴露，柳搖煙，豔陽天。", "雨霽山櫻紅欲爛，谷鶯遷。", "飲處交飛玉斝，遊時倒把金鞭。", "風颭九衢榆葉動，簇青錢。"]'),
('84f98e5a-9d57-43a5-b710-402fa43ab185','春光好 三','歐陽炯','唐','唐诗','tang','','[]','胸鋪雪，臉分蓮，理繁弦。',50,'全唐诗/poet.tang.49000.json','["胸鋪雪，臉分蓮，理繁弦。", "纖指飛飜金鳳語，轉嬋娟。", "嘈囋如敲玉佩，清泠似滴香泉。", "曲罷問郎名箇甚，想夫憐。"]'),
('86059a04-da7c-4e09-bda4-ae91d1c13444','春光好 四','歐陽炯','唐','唐诗','tang','','[]','磧香散，渚冰融，暖空濛。',50,'全唐诗/poet.tang.49000.json','["磧香散，渚冰融，暖空濛。", "飛絮悠揚徧虛空，惹輕風。", "柳眼煙來點綠，花心日與妝紅。", "黃雀錦鸞相對舞，近簾櫳。"]'),
('6cf291e8-6059-4a47-87f2-d9ed7073c158','春光好 五','歐陽炯','唐','唐诗','tang','','[]','雞樹綠，鳳池清，滿神京。',50,'全唐诗/poet.tang.49000.json','["雞樹綠，鳳池清，滿神京。", "玉兔宮前金牓出，列仙名。", "疊雪羅袍接武，團花駿馬嬌行。", "開宴錦江遊爛熳，柳煙輕。"]'),
('5530c224-4953-4abd-9202-4192c0ebdce5','春光好 六','歐陽炯','唐','唐诗','tang','','[]','芳叢繡，綠筵張，兩心狂。',50,'全唐诗/poet.tang.49000.json','["芳叢繡，綠筵張，兩心狂。", "空遣橫波傳意緒，對笙簧。", "雖似安仁擲果，未聞韓壽分香。", "流水桃花情不已，待劉郎。"]'),
('e1dd11a0-4e85-41f4-995e-ef02726fb21e','春光好 七','歐陽炯','唐','唐诗','tang','','[]','垂繡幔，掩雲屏，思盈盈。',50,'全唐诗/poet.tang.49000.json','["垂繡幔，掩雲屏，思盈盈。", "雙枕珊瑚無限情，翠釵橫。", "幾見纖纖動處，時聞款款嬌聲。", "却出錦屏妝面了，理秦箏。"]'),
('13950046-d1b9-4be8-95e6-59d28af94fbb','春光好 八','歐陽炯','唐','唐诗','tang','','[]','金轡響，玉鞭長，映垂楊。',50,'全唐诗/poet.tang.49000.json','["金轡響，玉鞭長，映垂楊。", "堤上采花筵上醉，滿衣香。", "無處不攜弦管，直應占斷春光。", "年少王孫何處好，競尋芳。"]'),
('83f12566-c8ba-4ff0-8fe3-ae8f362b212b','春光好 九','歐陽炯','唐','唐诗','tang','','[]','蘋葉嫩，杏花明，畫船輕。',50,'全唐诗/poet.tang.49000.json','["蘋葉嫩，杏花明，畫船輕。", "雙浴鴛鴦出綠汀，櫂歌聲。", "春水無風無浪，春來半雨半晴。", "紅粉相隨南浦晚，莫辭行。"]'),
('1e2fd147-05b2-4754-a59a-a1112c5b816d','西江月 一','歐陽炯','唐','唐诗','tang','','["\u957f\u6c5f"]','月映長江秋水，分明冷浸星河。',58,'全唐诗/poet.tang.49000.json','["月映長江秋水，分明冷浸星河。", "淺沙汀上白雲多，雪散幾叢蘆葦。", "扁舟倒影寒潭，煙光遠罩輕波。", "笛聲何處響漁歌，兩岸蘋香暗起。"]'),
('5f41c26f-df32-4ba8-b928-73d6cd0a07ca','西江月 二','歐陽炯','唐','唐诗','tang','','[]','水上鴛鴦比翼，巧將繡作羅衣。',58,'全唐诗/poet.tang.49000.json','["水上鴛鴦比翼，巧將繡作羅衣。", "鏡中重畫遠山眉，春睡起來無力。", "細雀穩簪雲髻，含羞時想佳期。", "臉邊紅豔對花枝，猶占鳳樓春色。"]'),
('05b73306-fde3-4a3c-9de3-570db2ca3dfe','赤棗子 一','歐陽炯','唐','唐诗','tang','','[]','夜悄悄，燭熒熒，金爐香盡酒初醒。',32,'全唐诗/poet.tang.49000.json','["夜悄悄，燭熒熒，金爐香盡酒初醒。", "春睡起來回雪面，含羞不語倚雲屏。"]'),
('68b0f21c-5c27-4e0f-955f-dc4117dc2d37','赤棗子 二','歐陽炯','唐','唐诗','tang','','[]','蓮臉薄，柳眉長，等閑無事莫思量。',32,'全唐诗/poet.tang.49000.json','["蓮臉薄，柳眉長，等閑無事莫思量。", "每一見時明月夜，損人情思斷人腸。"]'),
('e8a9b382-5e4c-466e-9cc3-32947ed44546','女冠子 一','歐陽炯','唐','唐诗','tang','','[]','薄妝桃臉，滿面縱橫花靨，豔情多。',52,'全唐诗/poet.tang.49000.json','["薄妝桃臉，滿面縱橫花靨，豔情多。", "綬帶盤金縷，輕帬透碧羅。", "含羞眉[乍]斂，微語笑相和。", "不會頻偷眼，意如何。"]'),
('da72420f-2ac0-47ef-bc07-86610e4ae40d','女冠子 二','歐陽炯','唐','唐诗','tang','','[]','秋宵秋月，一朵荷花初發，照前池。',50,'全唐诗/poet.tang.49000.json','["秋宵秋月，一朵荷花初發，照前池。", "搖曳熏香夜，嬋娟對鏡時。", "蘂中千點淚，心裏萬條絲。", "恰似輕盈女，好風姿。"]'),
('b2afa154-9d9a-4994-a5d0-6a77f8c8c406','更漏子 一','歐陽炯','唐','唐诗','tang','','[]','玉闌干，金甃井，月照碧梧桐影。',57,'全唐诗/poet.tang.49000.json','["玉闌干，金甃井，月照碧梧桐影。", "獨自箇，立多時，露華濃溼衣。", "一向，凝情望，待得不成模樣。", "雖叵耐，又尋思，爭生嗔得伊。"]'),
('6df05905-1771-4876-a9cb-d129dd450824','更漏子 二','歐陽炯','唐','唐诗','tang','','["\u5bab\u5ef7", "\u6c34", "\u6000\u53e4"]','三十六宮秋夜永，露華點滴高梧。',58,'全唐诗/poet.tang.49000.json','["三十六宮秋夜永，露華點滴高梧。", "丁丁玉漏咽銅壺，明月上金鋪。", "紅線毯，博山爐，香風暗觸流蘇。", "羊車一去長青蕪，鏡塵鸞綵孤。"]'),
('65c75c13-83ff-4e40-bb42-5b6a71f6acc4','定風波','歐陽炯','唐','唐诗','tang','','["\u601d\u5ff5", "\u95fa\u60c5", "\u6101\u7eea", "\u6292\u60c5"]','暖日閑窗映碧紗，小池春水浸晴霞。',73,'全唐诗/poet.tang.49000.json','["暖日閑窗映碧紗，小池春水浸晴霞。", "數樹海棠紅欲盡，爭忍，玉閨深掩過年華。", "獨凭繡牀方寸亂，腸斷，淚珠穿破臉邊花。", "鄰舍女郎相借問，音信，教人羞道未還家。"]'),
('9c73389e-37e9-411e-9d7a-08219e6878ff','木蘭花 一','歐陽炯','唐','唐诗','tang','','[]','兒家夫婿心容易，身又不來書不寄。',64,'全唐诗/poet.tang.49000.json','["兒家夫婿心容易，身又不來書不寄。", "閑庭獨立鳥關關，爭忍拋奴深院裏。", "悶向綠紗窗下睡，睡又不成愁已至。", "今年却憶去年春，同在木蘭花下醉。"]'),
('f2556d24-ea0a-46ee-b42c-2448998f2a64','木蘭花 二','歐陽炯','唐','唐诗','tang','','[]','日照玉樓花似錦，樓上醉和春色寢。',64,'全唐诗/poet.tang.49000.json','["日照玉樓花似錦，樓上醉和春色寢。", "綠楊風送小鶯聲，殘夢不成離玉枕。", "堪愛晚來韶景甚，寶柱秦箏方再品。", "青蛾紅臉笑來迎，又向海棠花下飲。"]'),
('e550440c-6141-4505-9b16-0860c0b60ac5','木蘭花 三','歐陽炯','唐','唐诗','tang','','[]','春早玉樓煙雨夜，簾外櫻桃花半謝。',64,'全唐诗/poet.tang.49000.json','["春早玉樓煙雨夜，簾外櫻桃花半謝。", "錦屏香冷繡衾寒，怊悵憶君無計舍。", "侵曉鵲聲來砌下，鸞鏡殘妝紅粉罷。", "黛眉雙點不成描，留待玉郎歸日畫。"]'),
('f6f6c50b-e533-45da-8e33-99e1221b8012','清平樂','歐陽炯','唐','唐诗','tang','','[]','春來街砌，春雨如絲細。',54,'全唐诗/poet.tang.49000.json','["春來街砌，春雨如絲細。", "春地滿飄紅杏蔕，春燕舞隨風勢。", "春幡細縷春繒，春閨一點春燈。", "自是春心撩亂，非干春夢無憑。"]'),
('c79ce05e-b8bf-484d-ae74-db8b3f6e292b','菩薩蠻 一','歐陽炯','唐','唐诗','tang','','[]','曉來中酒和春睡，四支無力雲鬟墜。',52,'全唐诗/poet.tang.49000.json','["曉來中酒和春睡，四支無力雲鬟墜。", "斜臥臉波春，玉郎休惱人。", "日高猶未起，爲戀鴛鴦被。", "鸚鵡語金籠，道兒還是慵。"]'),
('bfb041e0-8247-4bf3-882e-ea753a0b7959','菩薩蠻 二','歐陽炯','唐','唐诗','tang','','[]','紅爐煖閣佳人睡，隔簾飛雪添寒氣。',52,'全唐诗/poet.tang.49000.json','["紅爐煖閣佳人睡，隔簾飛雪添寒氣。", "小院奏笙歌，香風簇綺羅。", "酒傾金醆滿，蘭燭重開宴。", "公子醉如泥，天街聞馬嘶。"]'),
('890b74b1-6cce-437f-a5de-54fd78763f66','菩薩蠻 三','歐陽炯','唐','唐诗','tang','','[]','翠眉雙臉新妝薄，幽閨斜卷青羅幕。',52,'全唐诗/poet.tang.49000.json','["翠眉雙臉新妝薄，幽閨斜卷青羅幕。", "寒食百花時，紅繁香滿枝。", "雙雙梁燕語，蝶舞相隨去。", "腸斷正思君，閑眠冷繡茵。"]'),
('62088d62-97db-4659-844e-ed744403c770','菩薩蠻 四','歐陽炯','唐','唐诗','tang','','[]','畫屏繡閣三秋雨，香脣膩臉偎人語。',52,'全唐诗/poet.tang.49000.json','["畫屏繡閣三秋雨，香脣膩臉偎人語。", "語罷欲天明，嬌多夢不成。", "曉街鐘鼓絕，嗔道如今別。", "特地氣長吁，倚屏彈淚珠。"]'),
('0b6be4e4-6d12-4fa3-a0ba-36c07052dbeb','浣溪沙 一','歐陽炯','唐','唐诗','tang','','[]','落絮殘鶯半日天，玉柔花醉只思眠，惹窗映竹滿爐煙。',48,'全唐诗/poet.tang.49000.json','["落絮殘鶯半日天，玉柔花醉只思眠，惹窗映竹滿爐煙。", "獨掩畫屏愁不語，斜欹瑤枕髻鬟偏，此時心在阿誰邊。"]'),
('941385dc-c3ae-4c48-8730-441ae643c1f6','浣溪沙 二','歐陽炯','唐','唐诗','tang','','[]','天碧羅衣拂地垂，美人初著更相宜，宛風如舞透香肌。',48,'全唐诗/poet.tang.49000.json','["天碧羅衣拂地垂，美人初著更相宜，宛風如舞透香肌。", "獨坐含嚬吹鳳竹，園中緩步折花枝，有情無力泥人時。"]'),
('75562549-d8ba-45b4-bdb3-6aca5f7eb1b0','浣溪沙 三','歐陽炯','唐','唐诗','tang','','["\u7231\u60c5", "\u91cd\u9022"]','相見休言有淚珠，酒闌重得敘歡娛，鳳屏鴛枕宿金鋪。',48,'全唐诗/poet.tang.49000.json','["相見休言有淚珠，酒闌重得敘歡娛，鳳屏鴛枕宿金鋪。", "蘭麝細香聞喘息，綺羅纖縷見肌膚，此時還恨薄情無。"]'),
('5aac88aa-cc66-4a26-82a3-2f3d495d533f','三字令','歐陽炯','唐','唐诗','tang','','[]','春欲盡，日遲遲。',64,'全唐诗/poet.tang.49000.json','["春欲盡，日遲遲。", "牡丹時，羅幌卷。", "翠簾垂，綵牋書。", "紅粉淚，兩心知。", "人不在，燕空歸。", "負佳期，香燼落。", "枕函欹，月分明。", "花澹薄，惹相思。"]'),
('cf8cd8b7-81fd-475d-a044-6065b65b42df','南鄉子 一','歐陽炯','唐','唐诗','tang','','[]','嫩草如煙，石榴花發海南天。',33,'全唐诗/poet.tang.49000.json','["嫩草如煙，石榴花發海南天。", "日暮江亭春影淥，鴛鴦浴，水遠山長看不足。"]'),
('70ca46ae-8fcd-4c00-9c54-6f9266cd5c77','南鄉子 二','歐陽炯','唐','唐诗','tang','','["\u5a49\u7ea6", "\u5c11\u5973", "\u5199\u4eba", "\u5199\u666f", "\u5199\u4eba\u8bd7"]','畫舸停橈，槿花籬外竹橫橋。',32,'全唐诗/poet.tang.49000.json','["畫舸停橈，槿花籬外竹橫橋。", "水上遊人沙上女，回顧，笑指芭蕉林裏住。"]'),
('9c29278c-31b8-4121-b1d4-da18ea188522','南鄉子 三','歐陽炯','唐','唐诗','tang','','[]','岸遠沙平，日斜歸路晚霞明。',32,'全唐诗/poet.tang.49000.json','["岸遠沙平，日斜歸路晚霞明。", "孔雀自憐金翠尾，臨水，認得行人驚不起。"]'),
('5cdf73a6-417d-41d6-8f96-0a1434687d81','南鄉子 四','歐陽炯','唐','唐诗','tang','','[]','洞口誰家，木蘭船繫木蘭花。',33,'全唐诗/poet.tang.49000.json','["洞口誰家，木蘭船繫木蘭花。", "紅袖女郎相引去，遊南浦，笑倚春風相對語。"]'),
('739ca26b-6d49-42c6-aca3-7be479e32257','南鄉子 五','歐陽炯','唐','唐诗','tang','','[]','二八花鈿，胸前如雪臉如蓮。',35,'全唐诗/poet.tang.49000.json','["二八花鈿，胸前如雪臉如蓮。", "耳墜金[鐶]穿瑟瑟，霞衣窄，笑倚江頭招遠客。"]'),
('6d1841f3-11e9-4a0f-b414-84b145d75e19','南鄉子 六','歐陽炯','唐','唐诗','tang','','["\u5a49\u7ea6\u8bcd", "\u5357\u65b9", "\u5199\u666f", "\u5a49\u7ea6"]','路入南中，桄榔葉暗蓼花紅。',33,'全唐诗/poet.tang.49000.json','["路入南中，桄榔葉暗蓼花紅。", "兩岸人家微雨後，收紅豆，樹底纖纖擡素手。"]'),
('35f6e378-6ed2-45c3-8b80-0f67f8ba78af','南鄉子 七','歐陽炯','唐','唐诗','tang','','[]','袖斂鮫綃，采香深洞笑相邀。',33,'全唐诗/poet.tang.49000.json','["袖斂鮫綃，采香深洞笑相邀。", "藤杖枝頭蘆酒滴，鋪葵席，豆蔻花間趖晚日。"]'),
('d156335f-3eff-4fc5-b842-d6d5b540c922','南鄉子 八','歐陽炯','唐','唐诗','tang','','[]','翡翠鵁鶄，白蘋香裏小沙汀。',33,'全唐诗/poet.tang.49000.json','["翡翠鵁鶄，白蘋香裏小沙汀。", "島上陰陰秋雨色，蘆花撲，數隻漁船何處宿。"]'),
('ab114324-8ee1-4048-816d-998ffabde86b','獻衷心','歐陽炯','唐','唐诗','tang','','["\u76f8\u601d", "\u95fa\u6028", "\u5199\u666f"]','見好花顏色，爭笑東風。',81,'全唐诗/poet.tang.49000.json','["見好花顏色，爭笑東風。", "雙臉上，晚妝同。", "閉小樓深閣，春景重重。", "三五夜，偏有恨，月明中。", "情未已，信曾通，滿衣猶自染檀紅。", "恨不如雙燕，飛舞簾櫳。", "春欲暮，殘絮盡，柳條空。"]'),
('6b0a0e32-2f69-4857-a165-1d56eec60ef0','賀明朝 一','歐陽炯','唐','唐诗','tang','','["\u7231\u60c5", "\u8ffd\u5fc6", "\u7537\u5b50", "\u6000\u5ff5"]','憶昔花間初識面，紅袖半遮妝臉。',72,'全唐诗/poet.tang.49000.json','["憶昔花間初識面，紅袖半遮妝臉。", "輕轉石榴帬帶，故將纖纖玉指，偷撚雙鳳金線。", "碧梧桐鎖深深院，誰料得兩情，何日教繾綣？", "羨春來雙燕，飛到玉樓，朝暮相見。"]'),
('2b0e29a0-9353-449f-a69d-d42adde3c960','賀明朝 二','歐陽炯','唐','唐诗','tang','','["\u601d\u5ff5", "\u8ffd\u5fc6", "\u5973\u5b50"]','憶昔花間相見後，只憑纖手，暗拋紅豆。',76,'全唐诗/poet.tang.49000.json','["憶昔花間相見後，只憑纖手，暗拋紅豆。", "人前不解，巧傳心事，別來依舊，孤負春晝。", "碧羅衣上蹙金繡，覩對對鴛鴦，空裛淚痕透。", "想韶顏非久，終是爲伊，只[恁]偷瘦。"]'),
('587d77cd-4aea-480f-9386-bad8e98c43f5','江城子','歐陽炯','唐','唐诗','tang','','["\u5a49\u7ea6\u8bcd", "\u5199\u666f", "\u6000\u53e4", "\u5a49\u7ea6"]','晚日金陵岸草平，落霞明，水無情。',44,'全唐诗/poet.tang.49000.json','["晚日金陵岸草平，落霞明，水無情。", "六代繁華，暗逐逝波聲。", "空有姑蘇臺上月，如西子鏡，照江城。"]'),
('cd884a84-e2d3-4c90-b009-4751733509b2','鳳樓春','歐陽炯','唐','唐诗','tang','','[]','鳳髻綠雲叢，深掩房櫳。',94,'全唐诗/poet.tang.49000.json','["鳳髻綠雲叢，深掩房櫳。", "錦書通，夢中相見覺來慵。", "勻面淚，臉珠融。", "因想玉郎何處去，對淑景誰同。", "小樓中，春思無窮。", "倚闌凝望，闇牽愁緒，柳花飛起東風。", "斜日照簾，羅幌香冷粉屏空。", "海棠零落，鶯語殘紅。"]'),
('d1803c1f-74f3-43aa-884c-233a546b7348','生查子','歐陽彬','唐','唐诗','tang','','[]','竟日畫堂歡，入夜重開宴。',48,'全唐诗/poet.tang.49000.json','["竟日畫堂歡，入夜重開宴。", "翦燭蠟煙香，促席花光顫。", "待得月華來，滿院如鋪練。", "門外簇驊騮，直待更深散。"]'),
('c572aa02-22cd-4b18-895d-8d43cd3c3b75','虞美人 一','閻選','唐','唐诗','tang','','[]','粉融紅膩蓮房綻，臉動雙波慢。',68,'全唐诗/poet.tang.49000.json','["粉融紅膩蓮房綻，臉動雙波慢。", "小魚銜玉鬢釵橫，石榴裙染象紗輕，轉娉婷。", "偷期錦浪荷深處，一夢雲兼雨。", "臂留檀印齒痕香，深秋不寐漏初長，儘思量。"]'),
('8902ac96-c29f-4b61-a845-adc79820d012','虞美人 二','閻選','唐','唐诗','tang','','[]','楚腰蠐領團香玉，鬢疊深深綠。',68,'全唐诗/poet.tang.49000.json','["楚腰蠐領團香玉，鬢疊深深綠。", "月蛾星眼笑微頻，柳夭桃豔不勝春，晚妝勻。", "水紋簟映青紗帳，霧罩秋波上。", "一枝嬌臥醉芙蓉，良宵不得與君同，恨忡忡。"]'),
('8a66e343-6aa0-448c-8e6c-5bf2cc885e8c','臨江仙 一','閻選','唐','唐诗','tang','','["\u601d\u5ff5", "\u5199\u666f", "\u8377\u82b1"]','雨停荷芰逗濃香，岸邊蟬噪垂楊。',68,'全唐诗/poet.tang.49000.json','["雨停荷芰逗濃香，岸邊蟬噪垂楊。", "物華空有舊池塘，不逢仙子，何處夢襄王。", "珍簟對欹鴛枕冷，此來塵暗淒涼。", "欲憑危檻恨偏長，藕花珠綴，猶似汗凝妝。"]'),
('743b4178-4586-4ae5-a489-fc5c0a46ad16','臨江仙 二','閻選','唐','唐诗','tang','','[]','十二高峰天外寒，竹梢輕拂仙壇。',68,'全唐诗/poet.tang.49000.json','["十二高峰天外寒，竹梢輕拂仙壇。", "寶衣行雨在雲端，畫簾深殿，香霧冷風殘。", "欲問楚王何處去，翠屏猶掩金鸞。", "猨啼明月照空灘，孤舟行客，驚夢亦艱難。"]'),
('d92adcb3-734c-45bc-944c-a1a819cc9129','浣溪沙','閻選','唐','唐诗','tang','','[]','寂寞流蘇冷繡茵，倚屏山枕惹香塵，小庭花露泣濃春。',48,'全唐诗/poet.tang.49000.json','["寂寞流蘇冷繡茵，倚屏山枕惹香塵，小庭花露泣濃春。", "劉阮信非仙洞客，嫦娥終是月中人，此生無路訪東鄰。"]'),
('31845bea-cac9-4019-9aaf-78353e309f44','八拍蠻 一','閻選','唐','唐诗','tang','','["\u5973\u5b50", "\u95fa\u6028", "\u5199\u666f"]','雲鎖嫩黃煙柳細，風吹紅蔕雪梅殘。',32,'全唐诗/poet.tang.49000.json','["雲鎖嫩黃煙柳細，風吹紅蔕雪梅殘。", "光影不勝閨閣恨，行行坐坐黛眉攢。"]'),
('5714d257-717e-4a98-a8aa-6da4306c4406','八拍蠻 二','閻選','唐','唐诗','tang','','[]','愁鎖黛眉煙易慘，淚飄紅臉粉難勻。',32,'全唐诗/poet.tang.49000.json','["愁鎖黛眉煙易慘，淚飄紅臉粉難勻。", "憔悴不知緣底事，遇人推道不宜春。"]'),
('1c49a658-3d33-45bc-9dd4-94368e83ccea','河傳','閻選','唐','唐诗','tang','','["\u5199\u96e8", "\u95fa\u6028", "\u6292\u60c5", "\u96e8"]','秋雨，秋雨。',66,'全唐诗/poet.tang.49000.json','["秋雨，秋雨。", "無晝無夜，滴滴霏霏。", "暗燈涼簟怨分離，妖姬不勝悲。", "西風稍急喧窗竹，停又續，膩臉懸雙玉。", "幾回邀約雁來時，違期，雁歸，人不歸。"]'),
('30935d92-e742-4a19-bc1a-8864899ec8f8','謁金門','閻選','唐','唐诗','tang','','[]','美人浴，碧沼蓮開芬馥。',53,'全唐诗/poet.tang.49000.json','["美人浴，碧沼蓮開芬馥。", "雙髻綰雲顏似玉，素娥輝淡綠。", "雅態芳姿閑淑，雪映鈿裝金斛。", "水濺青絲珠斷續，酥融香透肉。"]'),
('ecb6781b-0d4e-4572-a38f-745de09d1fde','定風波','閻選','唐','唐诗','tang','','["\u79cb\u5929", "\u611f\u4f24", "\u5199\u666f", "\u5a49\u7ea6"]','江水沈沈帆影過，游魚到晚透寒波。',73,'全唐诗/poet.tang.49000.json','["江水沈沈帆影過，游魚到晚透寒波。", "渡口雙雙飛白鳥，煙嫋，蘆花深處隱漁歌。", "扁舟短櫂歸蘭浦，人去，蕭蕭竹徑透青莎。", "深夜無風新雨歇，涼月，露迎珠顆入圓荷。"]'),
('6b69ffca-1b10-48e2-8b0d-b34c03c13d63','竹枝 一','孫光憲','唐','唐诗','tang','','[]','門前春水白蘋花，岸上無人小艇斜。',32,'全唐诗/poet.tang.49000.json','["門前春水白蘋花，岸上無人小艇斜。", "商女經過江欲暮，散拋殘食飼神鵶。"]'),
('3d6c1a07-33ca-4305-bd6d-e9ded88011d3','竹枝 二','孫光憲','唐','唐诗','tang','','[]','亂繩千結絆人深，越羅萬丈表長尋。',32,'全唐诗/poet.tang.49000.json','["亂繩千結絆人深，越羅萬丈表長尋。", "楊柳在身垂意緒，藕花落盡見蓮心。"]'),
('a2c357cb-9a9d-4322-bca0-f3203a9f7dee','浣溪沙 一','孫光憲','唐','唐诗','tang','','["\u601d\u5ff5", "\u5199\u666f", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u9001\u522b", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u60dc\u522b"]','蓼岸風多橘柚香，江邊一望楚天長，片帆煙際閃孤光。',48,'全唐诗/poet.tang.49000.json','["蓼岸風多橘柚香，江邊一望楚天長，片帆煙際閃孤光。", "目送征鴻飛杳杳，思隨流水去茫茫，蘭紅波碧憶瀟湘。"]'),
('6d2a7b2a-a1df-490c-8b7e-0d25064a83f3','浣溪沙 二','孫光憲','唐','唐诗','tang','','[]','桃杏風香簾幕閑，謝家門戶約花關，畫梁幽語燕初還。',48,'全唐诗/poet.tang.49000.json','["桃杏風香簾幕閑，謝家門戶約花關，畫梁幽語燕初還。", "繡閣數行題了壁，曉屏一枕酒醒山，却疑身是夢雲間。"]'),
('46f89c35-c0f4-4950-a354-493dda57ce5a','浣溪沙 三','孫光憲','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u5973\u5b50", "\u6292\u60c5", "\u82b1", "\u5199\u82b1"]','花漸凋疎不耐風，畫簾垂地晚堂空，墮階縈蘚舞愁紅。',48,'全唐诗/poet.tang.49000.json','["花漸凋疎不耐風，畫簾垂地晚堂空，墮階縈蘚舞愁紅。", "膩粉半黏金靨子，殘香猶煖繡薰籠，蕙心無處與人同。"]'),
('3d7b331b-d180-4f6e-a1b1-e611d94899d5','浣溪沙 四','孫光憲','唐','唐诗','tang','','[]','攬鏡無言淚欲流，凝情半日嬾梳頭，一庭疎雨溼春愁。',48,'全唐诗/poet.tang.49000.json','["攬鏡無言淚欲流，凝情半日嬾梳頭，一庭疎雨溼春愁。", "楊柳祗知傷怨別，杏花應信損嬌羞，淚霑魂斷軫離憂。"]'),
('11a2ee36-eca7-4461-b30d-9aff17862cba','浣溪沙 五','孫光憲','唐','唐诗','tang','','[]','半踏長裾宛約行，晚簾疎處見分明，此時堪恨昧平生。',50,'全唐诗/poet.tang.49000.json','["半踏長裾宛約行，晚簾疎處見分明，此時堪恨昧平生。", "早是[銷]魂殘燭影，更愁聞著品弦聲，杳無消息若爲情。"]'),
('728c2dea-54d0-46f5-975c-5468995294d6','浣溪沙 六','孫光憲','唐','唐诗','tang','','[]','蘭沐初休曲檻前，暖風遲日洗頭天，濕雲新斂未梳蟬。',48,'全唐诗/poet.tang.49000.json','["蘭沐初休曲檻前，暖風遲日洗頭天，濕雲新斂未梳蟬。", "翠袂半將遮粉臆，寶釵長欲墜香肩，此時模樣不禁憐。"]'),
('9ecfab6d-7c9c-454d-94c7-2047c688a4a8','浣溪沙 七','孫光憲','唐','唐诗','tang','','["\u95fa\u6028", "\u5199\u666f"]','風遞殘香出繡簾，團窠金鳳舞襜襜，落花微雨恨相兼。',48,'全唐诗/poet.tang.49000.json','["風遞殘香出繡簾，團窠金鳳舞襜襜，落花微雨恨相兼。", "何處去來狂太甚，空推宿酒睡無厭，爭教人不別猜嫌。"]'),
('4bc3956e-a90f-4921-becb-bc6ad5461589','浣溪沙 八','孫光憲','唐','唐诗','tang','','[]','輕打銀箏墜燕泥，斷絲高罥畫樓西，花冠閑上午牆啼。',48,'全唐诗/poet.tang.49000.json','["輕打銀箏墜燕泥，斷絲高罥畫樓西，花冠閑上午牆啼。", "粉籜半開新竹徑，紅苞盡落舊桃蹊，不堪終日閉深閨。"]'),
('377b6f08-190a-41af-880f-323d04a71ce1','浣溪沙 九','孫光憲','唐','唐诗','tang','','[]','烏帽斜欹倒佩魚，靜街偷步訪仙居，隔牆應認打門初。',48,'全唐诗/poet.tang.49000.json','["烏帽斜欹倒佩魚，靜街偷步訪仙居，隔牆應認打門初。", "將見客時微掩斂，得人憐處且生疎，低頭羞問壁邊書。"]'),
('5c3cdcc7-9a45-4d9a-af7f-e98337cea86c','浣溪沙 十','孫光憲','唐','唐诗','tang','','[]','風撼芳菲滿院香，四簾慵卷日初長，鬢雲垂枕嚮微鍠。',52,'全唐诗/poet.tang.49000.json','["風撼芳菲滿院香，四簾慵卷日初長，鬢雲垂枕嚮微鍠。", "春夢未成愁寂寂，佳期難會信茫茫。", "萬般心，千點淚，泣蘭堂。"]'),
('1af4e30b-2cac-4518-be26-f507b2561610','浣溪沙 十一','孫光憲','唐','唐诗','tang','','[]','碧玉衣裳白玉人，翠眉紅臉小腰身，瑞雲飛雨逐行雲。',48,'全唐诗/poet.tang.49000.json','["碧玉衣裳白玉人，翠眉紅臉小腰身，瑞雲飛雨逐行雲。", "除却弄珠兼解佩，便隨西子與東鄰，是誰容易比真真。"]'),
('96fa4159-84ef-4c2c-9716-97b82be0a404','浣溪沙 十二','孫光憲','唐','唐诗','tang','','[]','何事相逢不展眉，苦將情分惡猜疑，眼前行止想應知。',48,'全唐诗/poet.tang.49000.json','["何事相逢不展眉，苦將情分惡猜疑，眼前行止想應知。", "半恨半嗔回面處，和嬌和淚泥人時，萬般饒得爲憐伊。"]'),
('a7b007ab-302a-4908-ba5f-431a9d1dda54','浣溪沙 十三','孫光憲','唐','唐诗','tang','','[]','落絮飛花滿帝城，看看春盡又傷情，歲華頻度想堪驚。',48,'全唐诗/poet.tang.49000.json','["落絮飛花滿帝城，看看春盡又傷情，歲華頻度想堪驚。", "風月豈惟今日恨，煙霄終待此身榮，未甘虛老負平生。"]'),
('c3ab0e52-98aa-41ee-a6f7-d3433e3c2f6e','浣溪沙 十四','孫光憲','唐','唐诗','tang','','[]','靜想離愁暗淚零，欲棲雲雨計難成，少年多是薄情人。',24,'全唐诗/poet.tang.49000.json','["靜想離愁暗淚零，欲棲雲雨計難成，少年多是薄情人。"]'),
('be63ad1e-b608-4688-bf9d-38297c9d9c5a','浣溪沙 十五','孫光憲','唐','唐诗','tang','','[]','試問於誰分最多，便隨人意轉橫波，縷金衣上小雙鵝。',48,'全唐诗/poet.tang.49000.json','["試問於誰分最多，便隨人意轉橫波，縷金衣上小雙鵝。", "醉後愛稱嬌姐姐，夜來留得好哥哥，不知情事久長麽。"]'),
('713960ff-e843-4900-bfd4-2ee42e74449f','浣溪沙 十六','孫光憲','唐','唐诗','tang','','[]','葉墜空階折早秋，細煙輕霧鎖妝樓，寸心雙淚慘嬌羞。',48,'全唐诗/poet.tang.49000.json','["葉墜空階折早秋，細煙輕霧鎖妝樓，寸心雙淚慘嬌羞。", "風月但牽魂夢苦，歲華偏感別離愁，恨和相憶兩難酬。"]'),
('5cea9bf0-654f-4319-94a4-f3c9779c621a','浣溪沙 十七','孫光憲','唐','唐诗','tang','','[]','月淡風和畫閣深，露桃煙柳影相侵，斂眉凝緒夜沈沈。',24,'全唐诗/poet.tang.49000.json','["月淡風和畫閣深，露桃煙柳影相侵，斂眉凝緒夜沈沈。"]'),
('c77d5646-0a85-4320-824c-9cf083d80e92','浣溪沙 十八','孫光憲','唐','唐诗','tang','','[]','自入春來月夜稀，今宵蟾彩倍凝輝，強開襟抱出簾帷。',48,'全唐诗/poet.tang.49000.json','["自入春來月夜稀，今宵蟾彩倍凝輝，強開襟抱出簾帷。", "囓指暗思花下約，凭闌羞覩淚痕衣，薄情狂蕩幾時歸。"]'),
('b592eacf-3d4f-4592-aea1-1b4109ed33d1','浣溪沙 十九','孫光憲','唐','唐诗','tang','','[]','十五年來錦岸遊，未曾行處不風流，好花長與萬金酬。',48,'全唐诗/poet.tang.49000.json','["十五年來錦岸遊，未曾行處不風流，好花長與萬金酬。", "滿眼利名渾信運，一生狂蕩恐難休，且陪煙月醉紅樓。"]'),
('70749194-b1b9-4cac-a0eb-e27896d13d3b','河傳 一','孫光憲','唐','唐诗','tang','','[]','太平天子，等閑遊戲，疏河千里。',68,'全唐诗/poet.tang.49000.json','["太平天子，等閑遊戲，疏河千里。", "柳如絲，偎倚，綠波春水，長淮風不起。", "如花殿脚三千女，爭雲雨，何處留人住？", "錦帆風，煙際紅，燒空，魂迷大業中。"]'),
('b57b23b5-6394-4e55-974f-3113249193c6','河傳 二','孫光憲','唐','唐诗','tang','','[]','柳拖金縷，著煙籠霧，濛濛落絮。',66,'全唐诗/poet.tang.49000.json','["柳拖金縷，著煙籠霧，濛濛落絮。", "鳳皇舟上楚女，妙舞，雷喧波上鼓。", "龍爭虎戰分中土，人無主，桃葉江南渡。", "襞花牋，豔思牽，成篇，宮娥相與傳。"]'),
('2e713966-2aa8-4483-8ab0-f26fcffe5695','河傳 三','孫光憲','唐','唐诗','tang','','["\u5b64\u72ec", "\u5973\u5b50", "\u95fa\u6028"]','花落，煙薄，謝家池閣，寂寞春深。',68,'全唐诗/poet.tang.49000.json','["花落，煙薄，謝家池閣，寂寞春深。", "翠蛾輕斂意沈吟，霑襟，無人知此心。", "玉爐香斷霜灰冷，簾鋪影，梁燕歸紅杏。", "晚來天，空悄然，孤眠，枕檀雲髻偏。"]'),
('c4899fc8-c230-4553-83ac-152dfc1f269f','河傳 四','孫光憲','唐','唐诗','tang','','["\u5c11\u5973", "\u5199\u4eba", "\u7eaa\u6e38", "\u5199\u4eba\u8bd7"]','風颭，波斂，團荷閃閃，珠傾露點。',69,'全唐诗/poet.tang.49000.json','["風颭，波斂，團荷閃閃，珠傾露點。", "木蘭舟上，何處吳娃越豔，藕花紅照臉。", "大堤狂殺襄陽客，煙波隔，渺渺湖光白。", "身已歸，心不歸，斜暉，遠汀鸂鶒飛。"]'),
('19669525-bb28-4fae-8284-c377cf28dc13','菩薩鬘 一','孫光憲','唐','唐诗','tang','','["\u7231\u60c5", "\u6c34", "\u5199\u666f"]','月華如水籠香砌，金鐶碎撼門初閉。',52,'全唐诗/poet.tang.49000.json','["月華如水籠香砌，金鐶碎撼門初閉。", "寒影墮高簷，鉤垂一面簾。", "碧煙輕嫋嫋，紅戰燈花笑。", "即此是高唐，掩屏秋夢長。"]'),
('1787888d-1009-488a-9e88-4fff5686ae36','菩薩鬘 二','孫光憲','唐','唐诗','tang','','[]','花冠頻鼓牆頭翼，東方澹白連窗色。',52,'全唐诗/poet.tang.49000.json','["花冠頻鼓牆頭翼，東方澹白連窗色。", "門外早鶯聲，背樓殘月明。", "薄寒籠醉態，依舊鉛華在。", "握手送人歸，半拖金縷衣。"]'),
('8f160c40-ef41-4f75-980d-20cbb2205ff0','菩薩鬘 三','孫光憲','唐','唐诗','tang','','[]','小庭花落無人掃，疎香滿地東風老。',52,'全唐诗/poet.tang.49000.json','["小庭花落無人掃，疎香滿地東風老。", "春晚信沈沈，天涯何處尋。", "曉堂屏六扇，眉共湘山遠。", "爭奈別離心，近來尤不禁。"]'),
('6e196927-ec2a-4838-957c-2a0164c9b4e6','菩薩鬘 四','孫光憲','唐','唐诗','tang','','["\u5199\u4eba", "\u7231\u60c5"]','青嵒碧洞經朝雨，隔花相喚南溪去。',52,'全唐诗/poet.tang.49000.json','["青嵒碧洞經朝雨，隔花相喚南溪去。", "一隻木蘭船，波平遠浸天。", "扣船驚翡翠，嫩玉擡香臂。", "紅日欲沈西，煙中遙解觿。"]'),
('543e1b87-45c3-438f-bd58-ad49c2bae031','菩薩鬘 五','孫光憲','唐','唐诗','tang','','["\u5199\u82b1", "\u82b1", "\u5a49\u7ea6"]','木綿花映叢祠小，越禽聲裏春光曉。',52,'全唐诗/poet.tang.49000.json','["木綿花映叢祠小，越禽聲裏春光曉。", "銅鼓與蠻歌，南人祈賽多。", "客帆風正急，茜袖偎檣立。", "極浦幾回頭，煙波無限愁。"]'),
('394a5165-aece-4176-aa06-aa753527dc18','河瀆神 一','孫光憲','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u629a\u6614\u4f24\u4eca", "\u5bfa\u5e99", "\u548f\u7269\u8bd7", "\u6c34"]','汾水碧依依，黃雲落葉初飛。',57,'全唐诗/poet.tang.49000.json','["汾水碧依依，黃雲落葉初飛。", "翠娥一去不言歸，廟門空掩斜暉。", "四壁陰森排古畫，依舊瓊輪羽駕。", "小殿沈沈清夜，銀燈飄落香灺。"]'),
('e13d2a99-01ec-4a6b-b06d-2cad293f01c3','河瀆神 二','孫光憲','唐','唐诗','tang','','[]','江上草芊芊，春晚湘妃廟前。',57,'全唐诗/poet.tang.49000.json','["江上草芊芊，春晚湘妃廟前。", "一方卵色楚南天，數行斜雁聯翩。", "獨倚朱闌情不極，魂斷終朝相憶。", "兩槳不知消息，遠汀時起鸂鶒。"]'),
('3154487f-3653-40b0-ab2e-fe4d28b85749','虞美人 一','孫光憲','唐','唐诗','tang','','[]','紅窗寂寂無人語，暗淡棃花雨。',68,'全唐诗/poet.tang.49000.json','["紅窗寂寂無人語，暗淡棃花雨。", "繡羅紋地粉新描，博山香炷旋抽條，睡魂銷。", "天涯一去無消息，終日長相憶。", "教人相憶幾時休，不堪棖觸別離愁，淚還流。"]'),
('1db30835-283e-4f6c-bf37-73808a24d5d8','虞美人 二','孫光憲','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50"]','好風微揭簾旌起，金翼鸞相倚。',68,'全唐诗/poet.tang.49000.json','["好風微揭簾旌起，金翼鸞相倚。", "翠簷愁聽乳禽聲，此時春態暗關情，獨難平。", "畫堂流水空相翳，一穗香搖曳。", "教人無處寄相思，落花芳草過前期，沒人知。"]'),
('b5b0cba7-68e3-4fc2-833f-492609473aab','後庭花 一','孫光憲','唐','唐诗','tang','','[]','景陽鐘動宮鶯轉，露涼金殿。',55,'全唐诗/poet.tang.49000.json','["景陽鐘動宮鶯轉，露涼金殿。", "輕飆吹起瓊花綻，玉葉如剪。", "晚來高閣上，珠簾卷。", "見墜香千片，修蛾慢臉陪雕輦，後庭新宴。"]'),
('abc9365c-2851-4723-8853-976273a30ae8','後庭花 二','孫光憲','唐','唐诗','tang','','["\u6292\u60c5", "\u6000\u53e4", "\u4f24\u611f"]','石城依舊空江國，故宮春色。',55,'全唐诗/poet.tang.49000.json','["石城依舊空江國，故宮春色。", "七尺青絲芳草綠，絕世難得。", "玉英凋落盡，更何人識。", "野棠如織，只是教人添怨憶，悵望無極。"]'),
('9f4112b7-6c67-4481-954d-59fc039e7c03','生查子 一','孫光憲','唐','唐诗','tang','','[]','寂寞掩朱門，正是天將暮。',50,'全唐诗/poet.tang.49000.json','["寂寞掩朱門，正是天將暮。", "暗澹小庭中，滴滴梧桐雨。", "繡工夫，牽心緒，配盡鴛鴦縷。", "待得沒人時，偎倚論私語。"]'),
('afea507b-1980-45f5-9353-7d9f2eec8ee7','生查子 二','孫光憲','唐','唐诗','tang','','[]','暖日策花驄，嚲鞚垂楊陌。',50,'全唐诗/poet.tang.49000.json','["暖日策花驄，嚲鞚垂楊陌。", "芳草惹煙青，落絮隨風白。", "誰家繡轂動香塵，隱映神仙客。", "狂殺玉鞭郎，咫尺音容隔。"]'),
('0b99aa4b-0499-400d-92f3-5fdb88b91ae2','生查子 三','孫光憲','唐','唐诗','tang','','[]','金井墮高梧，玉殿籠斜月。',50,'全唐诗/poet.tang.49000.json','["金井墮高梧，玉殿籠斜月。", "永巷寂無人，斂態愁堪絕。", "玉爐寒，香燼滅，還似君恩歇。", "翠輦不歸來，幽恨將誰說。"]'),
('3d180a80-faee-4e11-a417-6e909785a5fd','生查子 四','孫光憲','唐','唐诗','tang','','[]','春病與春愁，何事年年有。',50,'全唐诗/poet.tang.49000.json','["春病與春愁，何事年年有。", "半爲枕前人，半爲花間酒。", "醉金尊，攜玉手，共作鴛鴦偶。", "倒載臥雲屏，雪面腰如柳。"]'),
('9c6c08c0-1ca4-491e-bad1-f5f63cd963ae','生查子 五','孫光憲','唐','唐诗','tang','','[]','爲惜美人嬌，長有如花笑。',50,'全唐诗/poet.tang.49000.json','["爲惜美人嬌，長有如花笑。", "半醉倚紅妝，轉語傳青鳥。", "眷方深，憐恰好，唯恐相逢少。", "似這一般情，肯信春光老。"]'),
('8395e94b-bc01-41ba-b91b-27c3eb57b3b5','生查子 六','孫光憲','唐','唐诗','tang','','[]','清曉牡丹芳，紅豔凝金蘂。',50,'全唐诗/poet.tang.49000.json','["清曉牡丹芳，紅豔凝金蘂。", "乍占錦江春，永認笙歌地。", "感人心，爲物瑞，爛熳煙花裏。", "戴上玉釵時，迥與凡花異。"]'),
('a0a2482f-4f3b-4c4a-a68f-2b207d9f37d8','生查子 七','孫光憲','唐','唐诗','tang','','["\u601d\u5ff5", "\u5199\u96e8", "\u96e8"]','密雨阻佳期，盡日凝然坐。',50,'全唐诗/poet.tang.49000.json','["密雨阻佳期，盡日凝然坐。", "簾外正淋漓，不覺愁如鎖。", "夢難裁，心欲破，淚逐簷聲墜。", "想得玉人情，也合思量我。"]'),
('50be5375-735b-4fcc-99d8-709a8d1e2205','臨江仙 一','孫光憲','唐','唐诗','tang','','[]','霜拍井梧乾葉墮，翠幃雕檻初寒。',68,'全唐诗/poet.tang.49000.json','["霜拍井梧乾葉墮，翠幃雕檻初寒。", "薄鉛殘黛稱花冠，含情無語，延佇倚闌干。", "杳杳征輪何處去，離愁別恨千般。", "不堪心緒正多端，鏡匳長掩，無意對孤鸞。"]'),
('8cbf927c-c896-4026-906d-41595be3d4a0','臨江仙 二','孫光憲','唐','唐诗','tang','','[]','暮雨淒淒深院閉，燈前凝坐初更。',68,'全唐诗/poet.tang.49000.json','["暮雨淒淒深院閉，燈前凝坐初更。", "玉釵低壓鬢雲橫，半垂羅幕，相映燭光明。", "終是有心投漢珮，低頭但理秦箏。", "燕雙鸞偶不勝情，只愁明發，將逐楚雲行。"]'),
('26f38187-7868-4643-9b20-94359f6d925d','酒泉子 一','孫光憲','唐','唐诗','tang','','["\u5a49\u7ea6", "\u5f81\u4eba", "\u601d\u4eb2", "\u8fb9\u585e"]','空磧無邊，萬里陽關道路。',50,'全唐诗/poet.tang.49000.json','["空磧無邊，萬里陽關道路。", "馬蕭蕭，人去去，隴雲愁。", "香貂舊製戎衣窄，胡霜千里白。", "綺羅心，魂夢隔，上高樓。"]'),
('7be7bd72-35f5-41e5-a91d-9a534b50d755','酒泉子 二','孫光憲','唐','唐诗','tang','','[]','曲檻小樓，正是鶯花二月。',50,'全唐诗/poet.tang.49000.json','["曲檻小樓，正是鶯花二月。", "思無憀，愁欲絕，鬱離襟。", "展屏空對瀟湘水，眼前千萬里。", "淚掩紅，眉斂翠，恨沈沈。"]'),
('421cd718-6070-4dd9-8f49-2f7a46914bad','酒泉子 三','孫光憲','唐','唐诗','tang','','[]','斂態窗前，嫋嫋雀釵拋頸。',50,'全唐诗/poet.tang.49000.json','["斂態窗前，嫋嫋雀釵拋頸。", "燕成雙，鸞對影，偶新知。", "玉纖澹拂眉山小，鏡中嗔共照。", "翠連娟，紅縹緲，早妝時。"]'),
('1cf5133f-4eb8-4d2a-8911-8860946158f8','清平樂 一','孫光憲','唐','唐诗','tang','','[]','愁腸欲斷，正是青春半。',54,'全唐诗/poet.tang.49000.json','["愁腸欲斷，正是青春半。", "連理分枝鸞失伴，又是一場離散。", "掩鏡無語眉低，思隨芳草淒淒。", "憑仗東風吹夢，與郎終日東西。"]'),
('d8d07768-5f4b-4498-91be-23d7221a33e4','清平樂 二','孫光憲','唐','唐诗','tang','','[]','等閑無語，春恨如何去。',54,'全唐诗/poet.tang.49000.json','["等閑無語，春恨如何去。", "終是疎狂留不住，花暗柳濃何處。", "盡日目斷魂飛，晚窗斜界殘暉。", "長恨朱門薄暮，繡鞍驄馬空歸。"]'),
('04f277e7-6a2b-4b30-8c85-ec5c936bda8e','更漏子 一','孫光憲','唐','唐诗','tang','','[]','聽寒更，聞遠雁，半夜蕭娘深院。',58,'全唐诗/poet.tang.49000.json','["聽寒更，聞遠雁，半夜蕭娘深院。", "扃繡戶，下珠簾，滿庭噴玉蟾。", "人語靜，香閨冷，紅幕半垂清影。", "雲雨態，蕙蘭心，此情江海深。"]'),
('f9c1d321-c92b-4dac-8e94-8abe4f63a4ef','更漏子 二','孫光憲','唐','唐诗','tang','','[]','今夜期，來日別，相對祗堪愁絕。',58,'全唐诗/poet.tang.49000.json','["今夜期，來日別，相對祗堪愁絕。", "偎粉面，撚瑤簪，無言淚滿襟。", "銀箭落，霜華薄，牆外曉雞咿喔。", "聽付屬，惡情悰，斷腸西復東。"]'),
('068220f3-50dd-4943-95ff-3d6f12850ca2','更漏子 三','孫光憲','唐','唐诗','tang','','[]','燭熒煌，香旖旎，閑放一堆鴛被。',58,'全唐诗/poet.tang.49000.json','["燭熒煌，香旖旎，閑放一堆鴛被。", "慵就寢，獨無憀，相思魂欲銷。", "不會得，這心力，判了依前還憶。", "空自怨，奈伊何，別來情更多。"]'),
('0153e0ff-5bfd-4804-9bf1-10ff1d30f0ef','更漏子 四','孫光憲','唐','唐诗','tang','','[]','掌中珠，心上氣，愛惜豈將容易。',58,'全唐诗/poet.tang.49000.json','["掌中珠，心上氣，愛惜豈將容易。", "花下月，枕前人，此生誰更親。", "交頸語，合歡身，便同比目金鱗。", "連繡枕，臥紅茵，霜天似暖春。"]'),
('6f4cc9d6-6106-4c8d-9a13-1fd2643a15a7','更漏子 五','孫光憲','唐','唐诗','tang','','["\u79cb\u5929", "\u60b2\u79cb"]','對秋深，離恨苦，數夜滿庭風雨。',58,'全唐诗/poet.tang.49000.json','["對秋深，離恨苦，數夜滿庭風雨。", "凝想坐，斂愁眉，孤心似有違。", "紅窗靜，畫簾垂，魂消地角天涯。", "和淚聽，斷腸窺，漏移燈暗時。"]'),
('213a3ad1-7539-4aa0-bc1a-900f001174b6','更漏子 六','孫光憲','唐','唐诗','tang','','[]','求君心，風韻別，渾似一團煙月。',58,'全唐诗/poet.tang.49000.json','["求君心，風韻別，渾似一團煙月。", "歌皓齒，舞紅籌，花時醉上樓。", "能婉媚，解嬌羞，王孫忍不攀留。", "惟我恨，未綢繆，相思魂夢愁。"]'),
('6d2b0906-839a-43b2-8d08-eefa9908c4c5','女冠子 一','孫光憲','唐','唐诗','tang','','[]','蕙風芝露，壇際殘香輕度，蘂珠宮。',50,'全唐诗/poet.tang.49000.json','["蕙風芝露，壇際殘香輕度，蘂珠宮。", "苔點分圓碧，桃花踐破紅。", "品流巫峽外，名籍紫微中。", "真侶墉城會，夢魂通。"]'),
('4f91609b-67ed-4649-b593-bed683fa0f83','女冠子 二','孫光憲','唐','唐诗','tang','','["\u9053\u58eb", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','淡花瘦玉，依約神仙妝束，佩瓊文。',50,'全唐诗/poet.tang.49000.json','["淡花瘦玉，依約神仙妝束，佩瓊文。", "瑞露通宵貯，幽香盡日焚。", "碧紗籠絳節，黃藕冠濃雲。", "勿以吹簫伴，不同羣。"]'),
('3e8e48e4-1836-4b6a-8667-63d9fa9cee60','風流子 一','孫光憲','唐','唐诗','tang','','["\u5a49\u7ea6", "\u5a49\u7ea6\u8bcd", "\u519c\u6751", "\u6c34\u4e61"]','茅舍槿籬溪曲，雞犬自南自北。',42,'全唐诗/poet.tang.49000.json','["茅舍槿籬溪曲，雞犬自南自北。", "菰葉長，水葓開，門外春波漲淥。", "聽織，聲促，軋軋鳴梭穿屋。"]'),
('811221b6-718f-47b8-ba41-c6b1794e98c7','風流子 二','孫光憲','唐','唐诗','tang','','[]','樓倚長衢欲暮，瞥見神仙伴侶。',42,'全唐诗/poet.tang.49000.json','["樓倚長衢欲暮，瞥見神仙伴侶。", "微傅粉，攏梳頭，隱映畫簾開處。", "無語，無緒，慢曳羅帬歸去。"]'),
('aafdfd6c-c5b7-4860-ba6f-47aeb1b0c8b0','風流子 三','孫光憲','唐','唐诗','tang','','[]','金絡玉銜嘶馬，繫向綠楊陰下。',42,'全唐诗/poet.tang.49000.json','["金絡玉銜嘶馬，繫向綠楊陰下。", "朱戶掩，繡簾垂，曲院水流花謝。", "歡罷，歸也，猶在九衢深夜。"]'),
('5de489a0-40a3-4b04-959c-8dfb24899a52','定西番 一','孫光憲','唐','唐诗','tang','','[]','雞祿山前遊騎，邊草白，朔天明，馬蹄輕。',43,'全唐诗/poet.tang.49000.json','["雞祿山前遊騎，邊草白，朔天明，馬蹄輕。", "鵲面弓離短韔，彎來月欲成，一隻鳴𩩉雲外，曉鴻驚。"]'),
('30d04a6f-e6d4-443a-b04d-49b68e65a885','定西番 二','孫光憲','唐','唐诗','tang','','[]','帝子枕前秋夜，霜幄冷，月華明，正三更。',43,'全唐诗/poet.tang.49000.json','["帝子枕前秋夜，霜幄冷，月華明，正三更。", "何處戍樓寒笛，夢殘聞一聲，遙想漢關萬里，淚縱橫。"]'),
('d5836f69-97cc-4787-9b99-ff8ccf6c0c91','何滿子','孫光憲','唐','唐诗','tang','','[]','冠劒不隨君去，江河還共恩深。',29,'全唐诗/poet.tang.49000.json','["冠劒不隨君去，江河還共恩深。", "歌袖半遮眉黛慘，淚珠旋滴衣襟。"]'),
('16a17e34-c361-4342-a02f-85d67b057fbc','玉胡蝶','孫光憲','唐','唐诗','tang','','[]','春欲盡，景仍長，滿園花正黃。',52,'全唐诗/poet.tang.49000.json','["春欲盡，景仍長，滿園花正黃。", "粉翅兩悠颺，翩翩過短牆。", "鮮飆暖，牽遊伴，飛去立殘芳。", "無語對蕭娘，舞衫沈麝香。"]'),
('e9ce51fb-b1fd-43d5-9c5f-d8dcb261a1ba','八拍蠻','孫光憲','唐','唐诗','tang','','[]','孔雀尾拖金線長，怕人飛起入丁香。',32,'全唐诗/poet.tang.49000.json','["孔雀尾拖金線長，怕人飛起入丁香。", "越女沙頭爭拾翠，相呼歸去背斜陽。"]'),
('c3829100-0c2b-4189-bc42-a38649662e09','思帝鄉','孫光憲','唐','唐诗','tang','','[]','如何，遣情情更多。',44,'全唐诗/poet.tang.49000.json','["如何，遣情情更多。", "永日水堂簾下，斂羞蛾。", "六幅羅帬窣地，微行曳碧波。", "看盡滿池疎雨，打團荷。"]'),
('63c46976-9c2b-4207-8951-aded0e39110a','上行杯 一','孫光憲','唐','唐诗','tang','','[]','草草離亭鞍馬，從遠道，此地分襟。',48,'全唐诗/poet.tang.49000.json','["草草離亭鞍馬，從遠道，此地分襟。", "燕宋秦吳千萬里，無辭一醉。", "野棠開，江草溼。", "佇立，霑泣，征騎駸駸。"]'),
('d70809f6-34dc-488f-9933-dbc70e9e5a67','上行杯 二','孫光憲','唐','唐诗','tang','','[]','離櫂逡巡欲動，臨極浦，故人相送。',49,'全唐诗/poet.tang.49000.json','["離櫂逡巡欲動，臨極浦，故人相送。", "去住心情知不共，金船滿捧。", "綺羅愁，絲管咽。", "回別，帆影滅，江浪如雪。"]'),
('8d50bcc4-6bfd-4f1e-b37f-c680fec2a4d3','謁金門','孫光憲','唐','唐诗','tang','','[]','留不得，留得也應無益。',54,'全唐诗/poet.tang.49000.json','["留不得，留得也應無益。", "白紵春衫如雪色，揚州初去日。", "輕別離，甘拋擲，江上滿帆風疾。", "却羨綵鴛三十六，孤鸞還一隻。"]'),
('d204a543-56dd-4738-ba3c-e96c01a361d8','思越人 一','孫光憲','唐','唐诗','tang','','[]','古臺平，芳草遠，館娃宮外春深。',60,'全唐诗/poet.tang.49000.json','["古臺平，芳草遠，館娃宮外春深。", "翠黛空留千載恨，教人何處相尋？", "綺羅無復當時事，露花點滴香淚。", "惆悵遙天橫淥水，鴛鴦對對飛起。"]'),
('626cd0d4-c1a1-434f-b3d1-a378d4842677','思越人 二','孫光憲','唐','唐诗','tang','','[]','渚蓮枯，宮樹老，長洲廢苑蕭條。',60,'全唐诗/poet.tang.49000.json','["渚蓮枯，宮樹老，長洲廢苑蕭條。", "想像玉人空處所，月明獨上溪橋。", "經春初敗秋風起，紅蘭綠蕙愁死。", "一片風流傷心地，魂銷目斷西子。"]'),
('27fb5def-5bc1-4bde-93b9-2f62411bf40c','望梅花','孫光憲','唐','唐诗','tang','','[]','數枝開與短牆平，見雪萼。',45,'全唐诗/poet.tang.49000.json','["數枝開與短牆平，見雪萼。", "紅跗相映，引起誰人邊塞情。", "簾外欲三更，吹斷離愁月正明，空聽隔江聲。"]'),
('6e0bd74f-e386-4a4b-9d14-f8235ccf0a87','漁歌子 一','孫光憲','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u65f7\u8fbe"]','草芊芊，波漾漾，湖邊草色連波漲。',62,'全唐诗/poet.tang.49000.json','["草芊芊，波漾漾，湖邊草色連波漲。", "沿蓼岸，泊楓汀，天際玉輪初上。", "扣舷歌，聯極望，槳聲伊軋知何向。", "黃鵠叫，白鷗眠，誰似儂家疎曠。"]'),
('108aa664-25b3-4400-baf7-cc05efdaf331','漁歌子 二','孫光憲','唐','唐诗','tang','','[]','泛流螢，明又滅，夜涼水冷東灣闊。',62,'全唐诗/poet.tang.49000.json','["泛流螢，明又滅，夜涼水冷東灣闊。", "風浩浩，笛寥寥，萬頃金波重疊。", "杜若洲，香郁烈，一聲宿雁霜時節。", "經霅水，過松江，盡屬儂家日月。"]'),
('32853d6d-60e8-4ff6-b4fd-860f9e3fbeac','定風波','孫光憲','唐','唐诗','tang','','[]','簾拂疎香斷碧絲，淚衫還滴繡黃鸝。',74,'全唐诗/poet.tang.49000.json','["簾拂疎香斷碧絲，淚衫還滴繡黃鸝。", "上國獻書人不在，凝黛，晚庭又是落紅時。", "春日自長心自促，翻覆，年來年去負前期。", "應是秦雲兼楚雨，留住，向花枝誇說月中枝。"]'),
('6173b152-6691-44c1-948a-cd22f5be77ef','南歌子 一','孫光憲','唐','唐诗','tang','','[]','豔冶青樓女，風流似楚真。',62,'全唐诗/poet.tang.49000.json','["豔冶青樓女，風流似楚真。", "驪珠美玉未爲珍，窈窕一枝芳柳，入腰身。", "舞袖頻回雪，歌聲幾動塵。", "慢凝秋水顧情人，祗緣傾國，著處覺生春。"]'),
('9fbe092f-1eda-4089-8c93-cd1ae2e4a04f','南歌子 二','孫光憲','唐','唐诗','tang','','[]','映月論心處，偎花見面時。',62,'全唐诗/poet.tang.49000.json','["映月論心處，偎花見面時。", "倚郎和袖撫香肌，遙指畫堂深院，許相期。", "解佩君非晚，虛襟我未遲。", "願如連理合歡枝，不似五陵狂蕩，薄情兒。"]'),
('79dc061a-9acf-4aa8-8d6d-88d5da46fdf5','應天長','孫光憲','唐','唐诗','tang','','[]','翠凝仙豔非凡有，窈窕年華方十九。',60,'全唐诗/poet.tang.49000.json','["翠凝仙豔非凡有，窈窕年華方十九。", "鬢如雲，腰似柳，妙對綺弦歌醁酒。", "醉瑤臺，攜玉手。", "共燕此宵相偶，魂斷晚窗分首，淚霑金縷袖。"]'),
('0b4a825d-13aa-49fc-8522-ebc5c09a07c8','遐方怨','孫光憲','唐','唐诗','tang','','[]','紅綬帶，錦香囊。',71,'全唐诗/poet.tang.49000.json','["紅綬帶，錦香囊。", "爲表花前意，慇懃贈玉郎。", "此時更役心腸，轉添秋夜夢魂狂。", "思豔質，想嬌妝。", "願早傳金盞，同歡臥醉鄉。", "任人猜妬惡猜防，到頭須使似鴛鴦。"]'),
('dcf02abb-8930-444a-84f5-fb04bfc519d4','浣溪沙 一','張泌','唐','唐诗','tang','','["\u9001\u522b", "\u54c0\u6101"]','鈿轂香車過柳堤，樺煙分處馬頻嘶，爲他沈醉不成泥。',48,'全唐诗/poet.tang.49000.json','["鈿轂香車過柳堤，樺煙分處馬頻嘶，爲他沈醉不成泥。", "花滿驛亭香露細，杜鵑聲斷玉蟾低，含情無語倚樓西。"]'),
('92ece33e-701c-4bbe-b2c5-551a4602574f','浣溪沙 二','張泌','唐','唐诗','tang','','[]','馬上凝情憶舊遊，照花淹竹小溪流，鈿箏羅幕玉搔頭。',48,'全唐诗/poet.tang.49000.json','["馬上凝情憶舊遊，照花淹竹小溪流，鈿箏羅幕玉搔頭。", "早是出門長帶月，可堪分袂又經秋，晚風斜日不勝愁。"]'),
('eb6be6b6-e651-426d-bdec-501e13d0ab0e','浣溪沙 三','張泌','唐','唐诗','tang','','["\u6000\u4eba", "\u5a49\u7ea6\u8bcd", "\u6708\u591c", "\u5a49\u7ea6"]','獨立寒堦望月華，露濃香泛小庭花，繡屏愁背一燈斜。',48,'全唐诗/poet.tang.49000.json','["獨立寒堦望月華，露濃香泛小庭花，繡屏愁背一燈斜。", "雲雨自從分散後，人間無路到仙家，但憑魂夢訪天涯。"]'),
('4a8a0efd-59e0-4ecb-942a-d43868b6afa1','浣溪沙 四','張泌','唐','唐诗','tang','','[]','依約殘眉理舊黃，翠鬟拋擲一簪長，暖風晴日罷朝妝。',48,'全唐诗/poet.tang.49000.json','["依約殘眉理舊黃，翠鬟拋擲一簪長，暖風晴日罷朝妝。", "閑折海棠看又撚，玉纖無力惹餘香，此情誰會倚斜陽。"]'),
('0eb0030b-6ac0-4f78-87e9-0ff25da32c21','浣溪沙 五','張泌','唐','唐诗','tang','','[]','翡翠屏開繡幄紅，謝娥無力曉妝慵，錦帷鴛被宿香濃。',48,'全唐诗/poet.tang.49000.json','["翡翠屏開繡幄紅，謝娥無力曉妝慵，錦帷鴛被宿香濃。", "微雨小庭春寂寞，燕飛鶯語隔簾櫳，杏花凝恨倚東風。"]'),
('e28fe108-7e4d-459f-9457-d1d44ecd39e5','浣溪沙 六','張泌','唐','唐诗','tang','','[]','花月香寒悄夜塵，綺筵幽會暗傷神，嬋娟依約畫屏人。',48,'全唐诗/poet.tang.49000.json','["花月香寒悄夜塵，綺筵幽會暗傷神，嬋娟依約畫屏人。", "人不見時還暫語，令纔拋後愛微嚬，越羅巴錦不勝春。"]'),
('871bf875-199f-45e3-8718-937d02523c0b','浣溪沙 七','張泌','唐','唐诗','tang','','[]','偏戴花冠白玉簪，睡容新起意沈吟，翠鈿金縷鎮眉心。',48,'全唐诗/poet.tang.49000.json','["偏戴花冠白玉簪，睡容新起意沈吟，翠鈿金縷鎮眉心。", "小檻日斜風悄悄，隔簾零落杏花陰，斷香輕碧鎖愁深。"]'),
('5330b8f1-c330-47db-9137-b28d256d3ccb','浣溪沙 八','張泌','唐','唐诗','tang','','[]','晚逐香車入鳳城，東風斜揭繡簾輕，慢回嬌眼笑盈盈。',48,'全唐诗/poet.tang.49000.json','["晚逐香車入鳳城，東風斜揭繡簾輕，慢回嬌眼笑盈盈。", "消息未通何計是，便須佯醉且隨行，依稀聞道太狂生。"]'),
('46fa3b83-9ff3-42c7-98cc-d57f8640fa75','浣溪沙 九','張泌','唐','唐诗','tang','','[]','小市東門欲雪天，衆中依約見神仙，蘂黃香畫貼金蟬。',48,'全唐诗/poet.tang.49000.json','["小市東門欲雪天，衆中依約見神仙，蘂黃香畫貼金蟬。", "飲散黃昏人草草，醉容無語立門前，馬嘶塵烘一街煙。"]'),
('f8cc214b-7903-4582-a8e1-c1a74964583c','臨江仙','張泌','唐','唐诗','tang','','[]','煙收湘渚秋江靜，蕉花露泣愁紅。',68,'全唐诗/poet.tang.49000.json','["煙收湘渚秋江靜，蕉花露泣愁紅。", "五雲雙鶴去無蹤，幾回魂斷，凝望向長空。", "翠竹暗留珠淚怨，閑調寶瑟波中。", "花鬟月鬢綠雲重，古祠深殿，香冷雨和風。"]'),
('9c2b8b63-6f4a-460c-8697-ef34807ee6e2','女冠子','張泌','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50"]','露花煙草，寂寞五雲三島。',50,'全唐诗/poet.tang.49000.json','["露花煙草，寂寞五雲三島。", "正春深，貌減潛銷玉，香殘尚惹襟。", "竹疎虛檻靜，松密醮壇陰。", "何事劉郎去，信沈沈。"]'),
('e6cc38b3-d87c-4f7e-93d2-32bd79ca23c4','河傳 一','張泌','唐','唐诗','tang','','[]','渺莽雲水，惆悵暮帆。',62,'全唐诗/poet.tang.49000.json','["渺莽雲水，惆悵暮帆。", "去程迢遞，夕陽芳草。", "千里萬里，雁聲無限起。", "夢魂悄斷煙波裏，心如醉。", "相見何處是，錦屏香冷無睡，被頭多少淚。"]'),
('0700d273-7bca-4217-a0ac-be79397a313e','河傳 二','張泌','唐','唐诗','tang','','[]','紅杏，交枝相映，密密濛濛。',63,'全唐诗/poet.tang.49000.json','["紅杏，交枝相映，密密濛濛。", "一庭濃豔倚東風，香融，透簾櫳。", "斜陽似共春光語，蝶爭舞，更引流鶯妒。", "魂銷千片玉罇前，神仙，瑤池醉暮天。"]'),
('bce17839-f467-40f8-ae7e-6db8cdc59b10','酒泉子 一','張泌','唐','唐诗','tang','','[]','春雨打窗，驚夢覺來天氣曉。',53,'全唐诗/poet.tang.49000.json','["春雨打窗，驚夢覺來天氣曉。", "畫堂深，紅燄小，背蘭缸。", "酒香噴鼻嬾開缸，惆悵更無人共醉。", "舊巢中，新燕子，語雙雙。"]'),
('93acbc91-2055-4b68-8388-424e8bf35442','酒泉子 二','張泌','唐','唐诗','tang','','[]','紫陌青門，三十六宮春色。',51,'全唐诗/poet.tang.49000.json','["紫陌青門，三十六宮春色。", "御溝輦路暗相通，杏園風。", "咸陽沽酒寶釵空，笑指未央歸去。", "插花走馬落殘紅，月明中。"]'),
('43f8f80c-5a3b-494a-8606-034df24c2b48','生查子','張泌','唐','唐诗','tang','','[]','相見稀，喜相見，相見還相遠。',52,'全唐诗/poet.tang.49000.json','["相見稀，喜相見，相見還相遠。", "檀畫荔支紅，金蔓蜻蜓輭。", "魚雁疎，芳信斷，花落庭陰晚。", "可惜玉肌膚，消瘦成慵嬾。"]'),
('9fac524e-2d9f-40cf-ad96-4a1fec13f629','思越人','張泌','唐','唐诗','tang','','[]','燕雙飛，鶯百轉，越波堤下長橋。',60,'全唐诗/poet.tang.49000.json','["燕雙飛，鶯百轉，越波堤下長橋。", "鬬鈿花筐金匣恰，舞衣羅薄纖腰。", "東風澹蕩慵無力，黛眉愁聚春碧。", "滿地落花無消息，月明腸斷空憶。"]'),
('3cc19b41-2742-4feb-8d80-ac1dfa1f63a4','滿宮花','張泌','唐','唐诗','tang','','["\u5199\u4eba", "\u540c\u60c5", "\u5199\u4eba\u8bd7"]','花正芳，樓似綺，寂寞上陽宮裏。',60,'全唐诗/poet.tang.49000.json','["花正芳，樓似綺，寂寞上陽宮裏。", "鈿籠金鎖睡鴛鴦，簾冷露華珠翠。", "嬌豔輕盈香雪膩，細雨黃鶯雙起。", "東風惆悵欲清明，公子橋邊沈醉。"]'),
('5596965e-8a0c-41d0-a8fb-c6704be9e67b','柳枝','張泌','唐','唐诗','tang','','[]','膩粉瓊妝透碧紗，雪休誇。',48,'全唐诗/poet.tang.49000.json','["膩粉瓊妝透碧紗，雪休誇。", "金鳳搔頭墜鬢斜，髮交加。", "倚著雲屏新睡覺，思夢笑。", "紅顋隱出枕函花，有些些。"]'),
('c90b7eae-c7ff-4f23-8a44-656fe09e0e1c','南歌子 一','張泌','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5", "\u5a49\u7ea6"]','柳色遮樓暗，桐花落砌香。',31,'全唐诗/poet.tang.49000.json','["柳色遮樓暗，桐花落砌香。", "畫堂開處遠風涼，高卷水精簾額，襯斜陽。"]'),
('886849ba-d1cc-4d99-a299-60afad62c024','南歌子 二','張泌','唐','唐诗','tang','','["\u5b64\u72ec", "\u6292\u60c5", "\u67f3\u6811"]','岸柳拖烟綠，庭花照日紅。',31,'全唐诗/poet.tang.49000.json','["岸柳拖烟綠，庭花照日紅。", "數聲蜀魄入簾櫳，驚斷碧窗殘夢，畫屏空。"]'),
('7ed9516b-f837-474d-b953-b3de0cb7ab9f','南歌子 三','張泌','唐','唐诗','tang','','[]','錦薦紅鸂鶒，羅衣繡鳳皇。',31,'全唐诗/poet.tang.49000.json','["錦薦紅鸂鶒，羅衣繡鳳皇。", "綺疎飄雪北風狂，簾幕盡垂無事，鬱金香。"]'),
('f977537e-5fa2-4592-836d-3edc057d4fda','江城子 一','張泌','唐','唐诗','tang','','[]','碧闌干外小中庭，雨初晴，曉鶯聲。',43,'全唐诗/poet.tang.49000.json','["碧闌干外小中庭，雨初晴，曉鶯聲。", "飛絮落花，時節近清明。", "睡起卷簾無一事，勻面了，沒心情。"]'),
('e9ffd6f0-b307-46d9-95f6-e0e3162be772','江城子 二','張泌','唐','唐诗','tang','','[]','浣花溪上見卿卿，臉波秋水明，黛眉輕。',47,'全唐诗/poet.tang.49000.json','["浣花溪上見卿卿，臉波秋水明，黛眉輕。", "綠雲高綰，金簇小蜻蜓。", "好[是]問他來得麽，和笑道，莫多情。"]'),
('15afbf19-5be3-4b97-a4f4-4655d4844b8c','江城子 三','張泌','唐','唐诗','tang','','[]','窄羅衫子薄羅裙，小腰身，晚妝新。',43,'全唐诗/poet.tang.49000.json','["窄羅衫子薄羅裙，小腰身，晚妝新。", "每到花時，長是不宜春。", "蚤是自家無氣力，更被你，惡憐人。"]'),
('5ec769b5-2f1c-46cf-8de6-212f148495d6','河瀆神','張泌','唐','唐诗','tang','','[]','古樹噪寒鴉，滿庭楓葉蘆花。',57,'全唐诗/poet.tang.49000.json','["古樹噪寒鴉，滿庭楓葉蘆花。", "晝燈當午隔輕紗，畫閣珠簾影斜。", "門外往來祈賽客，翩翩帆落天涯。", "回首隔江煙火，渡頭三兩人家。"]'),
('844c56a7-626b-486f-8e48-0f7973719673','胡蝶兒','張泌','唐','唐诗','tang','','["\u6292\u60c5", "\u7231\u60c5", "\u5a49\u7ea6"]','胡蝶兒，晚春時。',48,'全唐诗/poet.tang.49000.json','["胡蝶兒，晚春時。", "阿嬌初著淡黃衣，倚窗學畫伊。", "還似花間見，雙雙對對飛。", "無端和淚拭燕脂，惹教雙翅垂。"]'),
('88f3e9b2-bd47-438a-a20d-fc52715b69cb','如夢令','馮延巳','唐','唐诗','tang','','[]','塵拂玉臺鸞鏡，鳳髻不堪重整。',40,'全唐诗/poet.tang.49000.json','["塵拂玉臺鸞鏡，鳳髻不堪重整。", "綃帳泣流蘇，愁掩玉屏人靜。", "多病，多病，自是行雲無定。"]'),
('ed4d885c-4073-47a3-b91e-70477b64f9bb','三臺令 一','馮延巳','唐','唐诗','tang','','[]','春色，春色，依舊青門紫陌。',40,'全唐诗/poet.tang.49000.json','["春色，春色，依舊青門紫陌。", "日斜柳暗花嫣，醉臥春色少年。", "年少，年少，行樂直須及早。"]'),
('2985c758-6be5-4096-b642-1a26f5fea351','三臺令 二','馮延巳','唐','唐诗','tang','','[]','明月，明月，照得離人愁絕。',40,'全唐诗/poet.tang.49000.json','["明月，明月，照得離人愁絕。", "更深影入空牀，不道帷屏夜長。", "長夜，長夜，夢到庭花陰下。"]'),
('10504673-9ec0-4096-80e2-69162b5cdf6c','三臺令 三','馮延巳','唐','唐诗','tang','','[]','南浦，南浦，翠鬟離人何處？',40,'全唐诗/poet.tang.49000.json','["南浦，南浦，翠鬟離人何處？", "當時攜手高樓，依舊樓前水流。", "流水，流水，中有傷心雙淚。"]'),
('2b5a5cb1-9bc8-4959-bd52-96eacfa88639','歸國謠 一','馮延巳','唐','唐诗','tang','','[]','何處笛，深夜夢回情脈脈。',40,'全唐诗/poet.tang.49000.json','["何處笛，深夜夢回情脈脈。", "竹風簷雨寒窗隔，離人幾歲無消息。", "今頭白，不眠特地重相憶。"]'),
('06006bd9-2362-46dd-b738-8185de46caeb','歸國謠 二','馮延巳','唐','唐诗','tang','','[]','春豔豔，江上晚山三四點。',40,'全唐诗/poet.tang.49000.json','["春豔豔，江上晚山三四點。", "柳絲如剪花如染，香閨寂寂門半掩。", "愁眉歛，淚珠滴破臙脂臉。"]');
